T_ETA_WINDOW = 3        # was 2 — wider window\nCRASH_EXPLOIT_POST_CRASH_DELAY = 1\n\nLATE_IMMEDIATE_SHIP_VALUE = 0.75\nWEAK_ENEMY_THRESHOLD = 110          # was 60 — detect weak enemies earlier\nELIMINATION_BONUS = 55.0            # was 28.0 — much stronger elimination drive\n\nBEHIND_DOMINATION = -0.20\nAHEAD_DOMINATION = 0.15\nFINISHING_DOMINATION = 0.28\nFINISHING_PROD_RATIO = 1.15\nAHEAD_ATTACK_MARGIN_BONUS = 0.12\nBEHIND_ATTACK_MARGIN_PENALTY = 0.05\nFINISHING_ATTACK_MARGIN_BONUS = 0.12\n\nDOOMED_EVAC_TURN_LIMIT = 24\nDOOMED_MIN_SHIPS = 8\n\nSOFT_ACT_DEADLINE = 0.82\nHEAVY_PHASE_MIN_TIME = 0.16\nOPTIONAL_PHASE_MIN_TIME = 0.08\nHEAVY_ROUTE_PLANET_LIMIT = 32\n\n# ============================================================\n# Shared Types\n# ============================================================\n\nPlanet = namedtuple(\n    "Planet", ["id", "owner", "x", "y", "radius", "ships", "production"]\n)\nFleet = namedtuple(\n    "Fleet", ["id", "owner", "x", "y", "angle", "from_planet_id", "ships"]\n)\n\n\n@dataclass(frozen=True)\nclass ShotOption:\n    score: float\n    src_id: int\n    target_id: int\n    angle: float\n    turns: int\n    needed: int\n    send_cap: int\n    mission: str = "capture"\n    anchor_turn: int | None = None\n\n\n@dataclass\nclass Mission:\n    kind: str\n    score: float\n    target_id: int\n    turns: int\n    options: list[ShotOption] = field(default_factory=list)\n\n# ============================================================\n# Physics\n# ============================================================\n\ndef dist(ax, ay, bx, by):\n    return math.hypot(ax - bx, ay - by)\n\n\ndef orbital_radius(planet):\n    return dist(planet.x, planet.y, CENTER_X, CENTER_Y)\n\n\ndef is_static_planet(planet):\n    return orbital_radius(planet) + planet.radius >= ROTATION_LIMIT\n\n\ndef fleet_speed(ships):\n    if ships <= 1:\n        return 1.0\n    ratio = math.log(ships) / math.log(1000.0)\n    ratio = max(0.0, min(1.0, ratio))\n    return 1.0 + (MAX_SPEED - 1.0) * (ratio**1.5)\n\n\ndef point_to_segment_distance(px, py, x1, y1, x2, y2):\n    dx = x2 - x1\n    dy = y2 - y1\n    seg_len_sq = dx * dx + dy * dy\n    if seg_len_sq <= 1e-9:\n        return dist(px, py, x1, y1)\n    t = ((px - x1) * dx + (py - y1) * dy) / seg_len_sq\n    t = max(0.0, min(1.0, t))\n    proj_x = x1 + t * dx\n    proj_y = y1 + t * dy\n    return dist(px, py, proj_x, proj_y)\n\n\ndef segment_hits_sun(x1, y1, x2, y2, safety=SUN_SAFETY):\n    return point_to_segment_distance(CENTER_X, CENTER_Y, x1, y1, x2, y2) < SUN_R + safety\n\n\ndef launch_point(sx, sy, sr, angle):\n    clearance = sr + LAUNCH_CLEARANCE\n    return sx + math.cos(angle) * clearance, sy + math.sin(angle) * clearance\n\n\ndef actual_path_geometry(sx, sy, sr, tx, ty, tr):\n    angle = math.atan2(ty - sy, tx - sx)\n    start_x, start_y = launch_point(sx, sy, sr, angle)\n    hit_distance = max(0.0, dist(sx, sy, tx, ty) - (sr + LAUNCH_CLEARANCE) - tr)\n    end_x = start_x + math.cos(angle) * hit_distance\n    end_y = start_y + math.sin(angle) * hit_distance\n    return angle, start_x, start_y, end_x, end_y, hit_distance\n\n\ndef safe_angle_and_distance(sx, sy, sr, tx, ty, tr):\n    angle, start_x, start_y, end_x, end_y, hit_distance = actual_path_geometry(\n        sx, sy, sr, tx, ty, tr,\n    )\n    if segment_hits_sun(start_x, start_y, end_x, end_y):\n        return None\n    return angle, hit_distance\n\n\ndef predict_planet_position(planet, initial_by_id, angular_velocity, turns):\n    init = initial_by_id.get(planet.id)\n    if init is None:\n        return planet.x, planet.y\n    r = dist(init.x, init.y, CENTER_X, CENTER_Y)\n    if r + init.radius >= ROTATION_LIMIT:\n        return planet.x, planet.y\n    cur_ang = math.atan2(planet.y - CENTER_Y, planet.x - CENTER_X)\n    new_ang = cur_ang + angular_velocity * turns\n    return (\n        CENTER_X + r * math.cos(new_ang),\n        CENTER_Y + r * math.sin(new_ang),\n    )\n\n\ndef predict_comet_position(planet_id, comets, turns):\n    for group in comets:\n        pids = group.get("planet_ids", [])\n        if planet_id not in pids:\n            continue\n        idx = pids.index(planet_id)\n        paths = group.get("paths", [])\n        path_index = group.get("path_index", 0)\n        if idx >= len(paths):\n            return None\n        path = paths[idx]\n        future_idx = path_index + int(turns)\n        if 0 <= future_idx < len(path):\n            return path[future_idx][0], path[future_idx][1]\n        return None\n    return None\n\n\ndef comet_remaining_life(planet_id, comets):\n    for group in comets:\n        pids = group.get("planet_ids", [])\n        if planet_id not in pids:\n            continue\n        idx = pids.index(planet_id)\n        paths = group.get("paths", [])\n        path_index = group.get("path_index", 0)\n        if idx < len(paths):\n            return max(0, len(paths[idx]) - path_index)\n    return 0\n\n\ndef estimate_arrival(sx, sy, sr, tx, ty, tr, ships):\n    safe = safe_angle_and_distance(sx, sy, sr, tx, ty, tr)\n    if safe is None:\n        return None\n    angle, total_d = safe\n    turns = max(1, int(math.ceil(total_d / fleet_speed(max(1, ships)))))\n    return angle, turns\n\n\ndef travel_time(sx, sy, sr, tx, ty, tr, ships):\n    est = estimate_arrival(sx, sy, sr, tx, ty, tr, ships)\n    if est is None:\n        return 10**9\n    return est[1]\n\n\ndef predict_target_position(target, turns, initial_by_id, ang_vel, comets, comet_ids):\n    if target.id in comet_ids:\n        return predict_comet_position(target.id, comets, turns)\n    return predict_planet_position(target, initial_by_id, ang_vel, turns)\n\n\ndef target_can_move(target, initial_by_id, comet_ids):\n    if target.id in comet_ids:\n        return True\n    init = initial_by_id.get(target.id)\n    if init is None:\n        return False\n    r = dist(init.x, init.y, CENTER_X, CENTER_Y)\n    return r + init.radius < ROTATION_LIMIT\n\n\ndef search_safe_intercept(src, target, ships, initial_by_id, ang_vel, comets, comet_ids):\n    best = None\n    best_score = None\n    max_turns = min(HORIZON, ROUTE_SEARCH_HORIZON)\n    if target.id in comet_ids:\n        max_turns = min(max_turns, max(0, comet_remaining_life(target.id, comets) - 1))\n\n    for candidate_turns in range(1, max_turns + 1):\n        pos = predict_target_position(\n            target, candidate_turns, initial_by_id, ang_vel, comets, comet_ids,\n        )\n        if pos is None:\n            continue\n        est = estimate_arrival(src.x, src.y, src.radius, pos[0], pos[1], target.radius, ships)\n        if est is None:\n            continue\n        _, turns = est\n        if abs(turns - candidate_turns) > INTERCEPT_TOLERANCE:\n            continue\n\n        actual_turns = max(turns, candidate_turns)\n        actual_pos = predict_target_position(\n            target, actual_turns, initial_by_id, ang_vel, comets, comet_ids,\n        )\n        if actual_pos is None:\n            continue\n\n        confirm = estimate_arrival(\n            src.x, src.y, src.radius, actual_pos[0], actual_pos[1], target.radius, ships,\n        )\n        if confirm is None:\n            continue\n\n        delta = abs(confirm[1] - actual_turns)\n        if delta > INTERCEPT_TOLERANCE:\n            continue\n\n        score = (delta, confirm[1], candidate_turns)\n        if best is None or score < best_score:\n            best_score = score\n            best = (confirm[0], confirm[1], actual_pos[0], actual_pos[1])\n\n    return best\n\n\ndef aim_with_prediction(src, target, ships, initial_by_id, ang_vel, comets, comet_ids):\n    est = estimate_arrival(src.x, src.y, src.radius, target.x, target.y, target.radius, ships)\n    if est is None:\n        if not target_can_move(target, initial_by_id, comet_ids):\n            return None\n        return search_safe_intercept(\n            src, target, ships, initial_by_id, ang_vel, comets, comet_ids,\n        )\n\n    tx, ty = target.x, target.y\n    for _ in range(5):\n        _, turns = est\n        pos = predict_target_position(target, turns, initial_by_id, ang_vel, comets, comet_ids)\n        if pos is None:\n            return None\n        ntx, nty = pos\n        next_est = estimate_arrival(src.x, src.y, src.radius, ntx, nty, target.radius, ships)\n        if next_est is None:\n            if not target_can_move(target, initial_by_id, comet_ids):\n                return None\n            return search_safe_intercept(\n                src, target, ships, initial_by_id, ang_vel, comets, comet_ids,\n            )\n        if (\n            abs(ntx - tx) < 0.3\n            and abs(nty - ty) < 0.3\n            and abs(next_est[1] - turns) <= INTERCEPT_TOLERANCE\n        ):\n            return next_est[0], next_est[1], ntx, nty\n        tx, ty = ntx, nty\n        est = next_est\n\n    final_est = estimate_arrival(src.x, src.y, src.radius, tx, ty, target.radius, ships)\n    if final_est is None:\n        return search_safe_intercept(\n            src, target, ships, initial_by_id, ang_vel, comets, comet_ids,\n        )\n    return final_est[0], final_est[1], tx, ty\n\n# ============================================================\n# World Model\n# ============================================================\n\ndef fleet_target_planet(fleet, planets):\n    best_planet = None\n    best_time = 1e9\n    dir_x = math.cos(fleet.angle)\n    dir_y = math.sin(fleet.angle)\n    speed = fleet_speed(fleet.ships)\n\n    for planet in planets:\n        dx = planet.x - fleet.x\n        dy = planet.y - fleet.y\n        proj = dx * dir_x + dy * dir_y\n        if proj < 0:\n            continue\n        perp_sq = dx * dx + dy * dy - proj * proj\n        radius_sq = planet.radius * planet.radius\n        if perp_sq >= radius_sq:\n            continue\n        hit_d = max(0.0, proj - math.sqrt(max(0.0, radius_sq - perp_sq)))\n        turns = hit_d / speed\n        if turns <= HORIZON and turns < best_time:\n            best_time = turns\n            best_planet = planet\n\n    if best_planet is None:\n        return None, None\n    return best_planet, int(math.ceil(best_time))\n\n\ndef segment_circle_entry_distance(x1, y1, x2, y2, cx, cy, radius):\n    dx = x2 - x1\n    dy = y2 - y1\n    fx = x1 - cx\n    fy = y1 - cy\n    a = dx * dx + dy * dy\n    if a <= 1e-9:\n        return 0.0 if dist(x1, y1, cx, cy) <= radius else None\n\n    b = 2.0 * (fx * dx + fy * dy)\n    c = fx * fx + fy * fy - radius * radius\n    disc = b * b - 4.0 * a * c\n    if disc < 0:\n        return None\n\n    root = math.sqrt(max(0.0, disc))\n    t1 = (-b - root) / (2.0 * a)\n    t2 = (-b + root) / (2.0 * a)\n    if 0.0 <= t1 <= 1.0:\n        return math.sqrt(a) * t1\n    if 0.0 <= t2 <= 1.0:\n        return math.sqrt(a) * t2\n    return None\n\n\ndef fleet_target_planet_dynamic(\n    fleet,\n    planets,\n    initial_by_id,\n    ang_vel,\n    comets,\n    comet_ids,\n    max_turns=ARRIVAL_LEDGER_DYNAMIC_HORIZON,\n):\n    """Project an in-flight fleet against moving planets/comets."""\n    moving_planets = [\n        planet\n        for planet in planets\n        if planet.id in comet_ids or target_can_move(planet, initial_by_id, comet_ids)\n    ]\n    static_target, static_eta = fleet_target_planet(fleet, planets)\n    if not moving_planets:\n        return static_target, static_eta\n    if static_eta is not None:\n        max_turns = min(max_turns, max(1, static_eta))\n\n    x = float(fleet.x)\n    y = float(fleet.y)\n    dir_x = math.cos(fleet.angle)\n    dir_y = math.sin(fleet.angle)\n    speed = fleet_speed(fleet.ships)\n\n    for turn in range(1, max_turns + 1):\n        old_x, old_y = x, y\n        new_x = old_x + dir_x * speed\n        new_y = old_y + dir_y * speed\n\n        if segment_hits_sun(old_x, old_y, new_x, new_y, safety=0.0):\n            return None, None\n\n        best_planet = None\n        best_distance = None\n        segment_len = max(1e-9, dist(old_x, old_y, new_x, new_y))\n\n        for planet in moving_planets:\n            move_pos = predict_target_position(\n                planet, turn - 1, initial_by_id, ang_vel, comets, comet_ids,\n            )\n            if move_pos is None:\n                continue\n\n            hit_distance = segment_circle_entry_distance(\n                old_x,\n                old_y,\n                new_x,\n                new_y,\n                move_pos[0],\n                move_pos[1],\n                planet.radius + 0.05,\n            )\n            if (\n                hit_distance is not None\n                and not (planet.id == fleet.from_planet_id and turn == 1 and hit_distance < 0.5)\n                and (best_distance is None or hit_distance < best_distance)\n            ):\n                best_distance = hit_distance\n                best_planet = planet\n\n            sweep_pos = predict_target_position(\n                planet, turn, initial_by_id, ang_vel, comets, comet_ids,\n            )\n            if sweep_pos is None:\n                continue\n            if (\n                dist(new_x, new_y, sweep_pos[0], sweep_pos[1]) <= planet.radius + 0.05\n                and (best_distance is None or segment_len < best_distance)\n            ):\n                best_distance = segment_len\n                best_planet = planet\n\n        if best_planet is not None:\n            return best_planet, turn\n\n        x, y = new_x, new_y\n        if x < 0.0 or x > BOARD or y < 0.0 or y > BOARD:\n            return None, None\n\n    return static_target, static_eta\n\n\ndef shot_hits_intended_target(\n    src,\n    target,\n    angle,\n    ships,\n    planets,\n    initial_by_id,\n    ang_vel,\n    comets,\n    comet_ids,\n    max_turns,\n):\n    """Check the actual launched path, including spawn offset, hits target first."""\n    start_x, start_y = launch_point(src.x, src.y, src.radius, angle)\n    probe = Fleet(-1, src.owner, start_x, start_y, angle, src.id, ships)\n    hit, eta = fleet_target_planet_dynamic(\n        probe,\n        planets,\n        initial_by_id,\n        ang_vel,\n        comets,\n        comet_ids,\n        max_turns=max_turns,\n    )\n    return hit is not None and hit.id == target.id and eta is not None\n\n\n# Compatibility helpers used by the replay-analysis scripts from the v4 line.\ndef distance_to_segment(px, py, x1, y1, x2, y2):\n    return point_to_segment_distance(px, py, x1, y1, x2, y2)\n\n\ndef crosses_sun(x1, y1, x2, y2):\n    return point_to_segment_distance(CENTER_X, CENTER_Y, x1, y1, x2, y2) <= SUN_R + 0.25\n\n\ndef projected_fleet_target(fleet, planets, obs=None, angular_velocity=0.0, comet_ids=None, max_turns=140):\n    target, eta = fleet_target_planet(fleet, planets)\n    if target is None:\n        return None\n    if eta is not None and eta > max_turns:\n        return None\n    return target\n\n\ndef build_arrival_ledger(fleets, planets, initial_by_id=None, ang_vel=0.0, comets=None, comet_ids=None):\n    arrivals_by_planet = {planet.id: [] for planet in planets}\n    initial_by_id = initial_by_id or {}\n    comets = comets or []\n    comet_ids = set(comet_ids or [])\n    for fleet in fleets:\n        if initial_by_id or comets:\n            target, eta = fleet_target_planet_dynamic(\n                fleet,\n                planets,\n                initial_by_id,\n                ang_vel,\n                comets,\n                comet_ids,\n            )\n        else:\n            target, eta = fleet_target_planet(fleet, planets)\n        if target is None:\n            continue\n        arrivals_by_planet[target.id].append((eta, fleet.owner, int(fleet.ships)))\n    return arrivals_by_planet\n\n\ndef resolve_arrival_event(owner, garrison, arrivals):\n    by_owner = {}\n    for _, attacker_owner, ships in arrivals:\n        by_owner[attacker_owner] = by_owner.get(attacker_owner, 0) + ships\n\n    if not by_owner:\n        return owner, max(0.0, garrison)\n\n    sorted_players = sorted(by_owner.items(), key=lambda item: item[1], reverse=True)\n    top_owner, top_ships = sorted_players[0]\n\n    if len(sorted_players) > 1:\n        second_ships = sorted_players[1][1]\n        if top_ships == second_ships:\n            survivor_owner = -1\n            survivor_ships = 0\n        else:\n            survivor_owner = top_owner\n            survivor_ships = top_ships - second_ships\n    else:\n        survivor_owner = top_owner\n        survivor_ships = top_ships\n\n    if survivor_ships <= 0:\n        return owner, max(0.0, garrison)\n\n    if owner == survivor_owner:\n        return owner, garrison + survivor_ships\n\n    garrison -= survivor_ships\n    if garrison < 0:\n        return survivor_owner, -garrison\n    return owner, garrison\n\n\ndef normalize_arrivals(arrivals, horizon):\n    events = []\n    for turns, owner, ships in arrivals:\n        if ships <= 0:\n            continue\n        eta = max(1, int(math.ceil(turns)))\n        if eta > horizon:\n            continue\n        events.append((eta, owner, int(ships)))\n    events.sort(key=lambda item: item[0])\n    return events\n\n\ndef simulate_planet_timeline(planet, arrivals, player, horizon):\n    horizon = max(0, int(math.ceil(horizon)))\n    events = normalize_arrivals(arrivals, horizon)\n    by_turn = defaultdict(list)\n    for item in events:\n        by_turn[item[0]].append(item)\n\n    owner = planet.owner\n    garrison = float(planet.ships)\n    owner_at = {0: owner}\n    ships_at = {0: max(0.0, garrison)}\n    min_owned = garrison if owner == player else 0.0\n    first_enemy = None\n    fall_turn = None\n\n    for turn in range(1, horizon + 1):\n        if owner != -1:\n            garrison += planet.production\n\n        group = by_turn.get(turn, [])\n        prev_owner = owner\n        if group:\n            if prev_owner == player and first_enemy is None:\n                if any(item[1] not in (-1, player) for item in group):\n                    first_enemy = turn\n            owner, garrison = resolve_arrival_event(owner, garrison, group)\n            if prev_owner == player and owner != player and fall_turn is None:\n                fall_turn = turn\n\n        owner_at[turn] = owner\n        ships_at[turn] = max(0.0, garrison)\n        if owner == player:\n            min_owned = min(min_owned, garrison)\n\n    keep_needed = 0\n    holds_full = True\n\n    if planet.owner == player:\n        def survives_with_keep(keep):\n            sim_owner = planet.owner\n            sim_garrison = float(keep)\n            for turn in range(1, horizon + 1):\n                if sim_owner != -1:\n                    sim_garrison += planet.production\n                group = by_turn.get(turn, [])\n                if group:\n                    sim_owner, sim_garrison = resolve_arrival_event(sim_owner, sim_garrison, group)\n                    if sim_owner != player:\n                        return False\n            return sim_owner == player\n\n        if survives_with_keep(int(planet.ships)):\n            lo, hi = 0, int(planet.ships)\n            while lo < hi:\n                mid = (lo + hi) // 2\n                if survives_with_keep(mid):\n                    hi = mid\n                else:\n                    lo = mid + 1\n            keep_needed = lo\n        else:\n            holds_full = False\n            keep_needed = int(planet.ships)\n\n    return {\n        "owner_at": owner_at,\n        "ships_at": ships_at,\n        "keep_needed": keep_needed,\n        "min_owned": max(0, int(math.floor(min_owned))) if planet.owner == player else 0,\n        "first_enemy": first_enemy,\n        "fall_turn": fall_turn,\n        "holds_full": holds_full,\n        "horizon": horizon,\n    }\n\n\ndef state_at_timeline(timeline, arrival_turn):\n    turn = max(0, int(math.ceil(arrival_turn)))\n    turn = min(turn, timeline["horizon"])\n    owner = timeline["owner_at"].get(turn, timeline["owner_at"][timeline["horizon"]])\n    ships = timeline["ships_at"].get(turn, timeline["ships_at"][timeline["horizon"]])\n    return owner, max(0.0, ships)\n\n\ndef count_players(planets, fleets):\n    owners = set()\n    for planet in planets:\n        if planet.owner != -1:\n            owners.add(planet.owner)\n    for fleet in fleets:\n        owners.add(fleet.owner)\n    return max(2, len(owners))\n\n\ndef nearest_distance_to_set(px, py, planets):\n    if not planets:\n        return 10**9\n    return min(dist(px, py, planet.x, planet.y) for planet in planets)\n\n\ndef indirect_features(planet, planets, player):\n    friendly = 0.0\n    neutral = 0.0\n    enemy = 0.0\n    for other in planets:\n        if other.id == planet.id:\n            continue\n        d = dist(planet.x, planet.y, other.x, other.y)\n        if d < 1:\n            continue\n        factor = other.production / (d + 12.0)\n        if other.owner == player:\n            friendly += factor\n        elif other.owner == -1:\n            neutral += factor\n        else:\n            enemy += factor\n    return friendly, neutral, enemy\n\n\ndef detect_exposed_enemy_planets(fleets, enemy_planets):\n    exposed = set()\n    for planet in enemy_planets:\n        outbound = sum(\n            int(f.ships)\n            for f in fleets\n            if f.owner == planet.owner and f.from_planet_id == planet.id and f.ships >= 5\n        )\n        if outbound >= 12 and outbound >= planet.ships * 0.8:  # lowered threshold\n            exposed.add(planet.id)\n    return exposed\n\n\ndef _compute_weakest_enemy(enemy_planets, owner_strength, owner_production):\n    """Return the player ID of the weakest enemy (lowest ships + future production)."""\n    enemy_owners = set(p.owner for p in enemy_planets)\n    if not enemy_owners:\n        return None\n    return min(\n        enemy_owners,\n        key=lambda owner: owner_strength.get(owner, 0) + owner_production.get(owner, 0) * 15,\n    )\n\n\ndef _compute_strongest_enemy(enemy_planets, owner_strength, owner_production):\n    enemy_owners = set(p.owner for p in enemy_planets)\n    if not enemy_owners:\n        return None\n    return max(\n        enemy_owners,\n        key=lambda owner: owner_strength.get(owner, 0) + owner_production.get(owner, 0) * 18,\n    )\n\n\nclass WorldModel:\n    def __init__(self, player, step, planets, fleets, initial_by_id, ang_vel, comets, comet_ids):\n        self.player = player\n        self.step = step\n        self.planets = planets\n        self.fleets = fleets\n        self.initial_by_id = initial_by_id\n        self.ang_vel = ang_vel\n        self.comets = comets\n        self.comet_ids = set(comet_ids)\n\n        self.planet_by_id = {planet.id: planet for planet in planets}\n        self.my_planets = [planet for planet in planets if planet.owner == player]\n        self.enemy_planets = [planet for planet in planets if planet.owner not in (-1, player)]\n        self.neutral_planets = [planet for planet in planets if planet.owner == -1]\n        self.static_neutral_planets = [\n            planet for planet in self.neutral_planets if is_static_planet(planet)\n        ]\n\n        self.num_players = count_players(planets, fleets)\n        self.remaining_steps = max(1, TOTAL_STEPS - step)\n        self.is_early = step < EARLY_TURN_LIMIT\n        self.is_opening = step < OPENING_TURN_LIMIT\n        self.is_late = self.remaining_steps < LATE_REMAINING_TURNS\n        self.is_very_late = self.remaining_steps < VERY_LATE_REMAINING_TURNS\n        self.is_total_war = self.remaining_steps < TOTAL_WAR_REMAINING_TURNS\n        self.is_four_player = self.num_players >= 4\n\n        self.owner_strength = defaultdict(int)\n        self.owner_production = defaultdict(int)\n        for planet in planets:\n            if planet.owner != -1:\n                self.owner_strength[planet.owner] += int(planet.ships)\n                self.owner_production[planet.owner] += int(planet.production)\n        for fleet in fleets:\n            self.owner_strength[fleet.owner] += int(fleet.ships)\n\n        self.my_total = self.owner_strength.get(player, 0)\n        self.enemy_total = sum(\n            strength for owner, strength in self.owner_strength.items() if owner != player\n        )\n        self.max_enemy_strength = max(\n            (strength for owner, strength in self.owner_strength.items() if owner != player),\n            default=0,\n        )\n        self.my_prod = self.owner_production.get(player, 0)\n        self.max_enemy_prod = max(\n            (\n                production\n                for owner, production in self.owner_production.items()\n                if owner != player\n            ),\n            default=0,\n        )\n        self.enemy_prod = sum(\n            production\n            for owner, production in self.owner_production.items()\n            if owner != player\n        )\n\n        # Weakest enemy tracking (key for 4P elimination strategy)\n        self._weakest_enemy = _compute_weakest_enemy(\n            self.enemy_planets, self.owner_strength, self.owner_production\n        )\n        self._weakest_enemy_strength = (\n            self.owner_strength.get(self._weakest_enemy, 0)\n            if self._weakest_enemy is not None else 0\n        )\n        self._leader_enemy = _compute_strongest_enemy(\n            self.enemy_planets, self.owner_strength, self.owner_production\n        )\n        self._leader_enemy_strength = (\n            self.owner_strength.get(self._leader_enemy, 0)\n            if self._leader_enemy is not None else 0\n        )\n        self._leader_enemy_prod = (\n            self.owner_production.get(self._leader_enemy, 0)\n            if self._leader_enemy is not None else 0\n        )\n\n        self.arrivals_by_planet = build_arrival_ledger(\n            fleets, planets, initial_by_id, ang_vel, comets, comet_ids,\n        )\n        self.base_timeline = {\n            planet.id: simulate_planet_timeline(\n                planet,\n                self.arrivals_by_planet[planet.id],\n                player,\n                HORIZON,\n            )\n            for planet in planets\n        }\n        self.keep_needed_map = {\n            planet.id: self.base_timeline[planet.id]["keep_needed"] for planet in planets\n        }\n        self.min_owned_map = {\n            planet.id: self.base_timeline[planet.id]["min_owned"] for planet in planets\n        }\n        self.first_enemy_map = {\n            planet.id: self.base_timeline[planet.id]["first_enemy"] for planet in planets\n        }\n        self.fall_turn_map = {\n            planet.id: self.base_timeline[planet.id]["fall_turn"] for planet in planets\n        }\n        self.holds_full_map = {\n            planet.id: self.base_timeline[planet.id]["holds_full"] for planet in planets\n        }\n        self.indirect_feature_map = {\n            planet.id: indirect_features(planet, planets, player) for planet in planets\n        }\n        self.exposed_planet_ids = detect_exposed_enemy_planets(fleets, self.enemy_planets)\n        self.shot_cache = {}\n        self.probe_candidate_cache = {}\n        self.best_probe_cache = {}\n        self.reaction_cache = {}\n        self.exact_need_cache = {}\n\n        self.total_visible_ships = sum(int(planet.ships) for planet in planets) + sum(\n            int(fleet.ships) for fleet in fleets\n        )\n        self.total_production = sum(int(planet.production) for planet in planets)\n\n    def is_static(self, planet_id):\n        return is_static_planet(self.planet_by_id[planet_id])\n\n    def comet_life(self, planet_id):\n        return comet_remaining_life(planet_id, self.comets)\n\n    def source_inventory_left(self, source_id, spent_total):\n        return max(0, int(self.planet_by_id[source_id].ships) - spent_total[source_id])\n\n    def plan_shot(self, src_id, target_id, ships):\n        ships = int(ships)\n        key = (src_id, target_id, ships)\n        if key in self.shot_cache:\n            return self.shot_cache[key]\n        src = self.planet_by_id[src_id]\n        target = self.planet_by_id[target_id]\n        result = aim_with_prediction(\n            src, target, ships, self.initial_by_id, self.ang_vel, self.comets, self.comet_ids,\n        )\n        self.shot_cache[key] = result\n        return result\n\n    def probe_ship_candidates(self, src_id, target_id, source_cap, hints=()):\n        source_cap = max(1, int(source_cap))\n        normalized_hints = tuple(\n            int(math.ceil(hint)) for hint in hints if hint is not None\n        )\n        cache_key = (src_id, target_id, source_cap, normalized_hints)\n        cached = self.probe_candidate_cache.get(cache_key)\n        if cached is not None:\n            return cached\n        target = self.planet_by_id[target_id]\n        target_ships = max(1, int(math.ceil(target.ships)))\n\n        values = set(range(1, min(6, source_cap) + 1))\n        values.update({\n            source_cap,\n            max(1, source_cap // 2),\n            max(1, source_cap // 3),\n            min(source_cap, PARTIAL_SOURCE_MIN_SHIPS),\n            min(source_cap, target_ships + 1),\n            min(source_cap, target_ships + 2),\n            min(source_cap, target_ships + 4),\n            min(source_cap, target_ships + 8),\n        })\n\n        for hint in normalized_hints:\n            base = max(1, min(source_cap, hint))\n            for delta in (-2, -1, 0, 1, 2):\n                candidate = base + delta\n                if 1 <= candidate <= source_cap:\n                    values.add(candidate)\n\n        result = sorted(values)\n        self.probe_candidate_cache[cache_key] = result\n        return result\n\n    def best_probe_aim(\n        self,\n        src_id,\n        target_id,\n        source_cap,\n        hints=(),\n        min_turn=None,\n        max_turn=None,\n        anchor_turn=None,\n        max_anchor_diff=None,\n    ):\n        cache_key = (\n            src_id,\n            target_id,\n            max(1, int(source_cap)),\n            tuple(hints),\n            min_turn,\n            max_turn,\n            anchor_turn,\n            max_anchor_diff,\n        )\n        if cache_key in self.best_probe_cache:\n            return self.best_probe_cache[cache_key]\n\n        best = None\n        best_key = None\n\n        for ships in self.probe_ship_candidates(src_id, target_id, source_cap, hints=hints):\n            aim = self.plan_shot(src_id, target_id, ships)\n            if aim is None:\n                continue\n\n            angle, turns, dist_to_target, path_target = aim\n            if min_turn is not None and turns < min_turn:\n                continue\n            if max_turn is not None and turns > max_turn:\n                continue\n            if (\n                anchor_turn is not None\n                and max_anchor_diff is not None\n                and abs(turns - anchor_turn) > max_anchor_diff\n            ):\n                continue\n\n            if anchor_turn is None:\n                key = (turns, ships)\n            else:\n                key = (abs(turns - anchor_turn), turns, ships)\n\n            if best_key is None or key < best_key:\n                best_key = key\n                best = (ships, (angle, turns, dist_to_target, path_target))\n\n        self.best_probe_cache[cache_key] = best\n        return best\n\n    def reaction_times(self, target_id):\n        cached = self.reaction_cache.get(target_id)\n        if cached is not None:\n            return cached\n\n        target = self.planet_by_id[target_id]\n        my_t = 10**9\n        for planet in self.my_planets:\n            seeded = self.best_probe_aim(planet.id, target.id, max(1, int(planet.ships)))\n            if seeded is None:\n                continue\n            _, aim = seeded\n            my_t = min(my_t, aim[1])\n\n        enemy_t = 10**9\n        for planet in self.enemy_planets:\n            seeded = self.best_probe_aim(planet.id, target.id, max(1, int(planet.ships)))\n            if seeded is None:\n                continue\n            _, aim = seeded\n            enemy_t = min(enemy_t, aim[1])\n\n        cached = (my_t, enemy_t)\n        self.reaction_cache[target_id] = cached\n        return cached\n\n    def projected_state(self, target_id, arrival_turn, planned_commitments=None, extra_arrivals=()):\n        planned_commitments = planned_commitments or {}\n        cutoff = max(1, int(math.ceil(arrival_turn)))\n        if not planned_commitments.get(target_id) and not extra_arrivals:\n            return state_at_timeline(self.base_timeline[target_id], cutoff)\n\n        arrivals = [\n            item\n            for item in self.arrivals_by_planet.get(target_id, [])\n            if item[0] <= cutoff\n        ]\n        arrivals.extend(\n            item\n            for item in planned_commitments.get(target_id, [])\n            if item[0] <= cutoff\n        )\n        arrivals.extend(item for item in extra_arrivals if item[0] <= cutoff)\n\n        target = self.planet_by_id[target_id]\n        dyn = simulate_planet_timeline(target, arrivals, self.player, cutoff)\n        return state_at_timeline(dyn, cutoff)\n\n    def projected_timeline(self, target_id, horizon, planned_commitments=None, extra_arrivals=()):\n        planned_commitments = planned_commitments or {}\n        horizon = max(1, int(math.ceil(horizon)))\n        arrivals = [\n            item for item in self.arrivals_by_planet.get(target_id, []) if item[0] <= horizon\n        ]\n        arrivals.extend(\n            item for item in planned_commitments.get(target_id, []) if item[0] <= horizon\n        )\n        arrivals.extend(item for item in extra_arrivals if item[0] <= horizon)\n        target = self.planet_by_id[target_id]\n        return simulate_planet_timeline(target, arrivals, self.player, horizon)\n\n    def hold_status(self, target_id, planned_commitments=None, horizon=HORIZON):\n        planned_commitments = planned_commitments or {}\n        if planned_commitments.get(target_id):\n            tl = self.projected_timeline(\n                target_id, horizon, planned_commitments=planned_commitments,\n            )\n        else:\n            tl = self.base_timeline[target_id]\n        return {\n            "keep_needed": tl["keep_needed"],\n            "min_owned": tl["min_owned"],\n            "first_enemy": tl["first_enemy"],\n            "fall_turn": tl["fall_turn"],\n            "holds_full": tl["holds_full"],\n        }\n\n    def _ownership_search_cap(self, eval_turn):\n        productive_cap = self.total_production * max(2, eval_turn + 2)\n        return max(32, int(self.total_visible_ships + productive_cap + 32))\n\n    def min_ships_to_own_by(\n        self,\n        target_id,\n        eval_turn,\n        attacker_owner,\n        arrival_turn=None,\n        planned_commitments=None,\n        extra_arrivals=(),\n        upper_bound=None,\n    ):\n        planned_commitments = planned_commitments or {}\n        eval_turn = max(1, int(math.ceil(eval_turn)))\n        arrival_turn = eval_turn if arrival_turn is None else max(1, int(math.ceil(arrival_turn)))\n        if arrival_turn > eval_turn:\n            if upper_bound is not None:\n                return max(1, int(upper_bound)) + 1\n            return self._ownership_search_cap(eval_turn) + 1\n\n        normalized_extra = tuple(\n            (max(1, int(math.ceil(turns))), owner, int(ships))\n            for turns, owner, ships in extra_arrivals\n            if ships > 0 and max(1, int(math.ceil(turns))) <= eval_turn\n        )\n\n        cache_key = None\n        if (\n            arrival_turn == eval_turn\n            and not planned_commitments.get(target_id)\n            and not normalized_extra\n        ):\n            cache_key = (target_id, eval_turn, attacker_owner)\n            cached = self.exact_need_cache.get(cache_key)\n            if cached is not None:\n                return cached\n\n        owner_before, ships_before = self.projected_state(\n            target_id,\n            eval_turn,\n            planned_commitments=planned_commitments,\n            extra_arrivals=normalized_extra,\n        )\n        if owner_before == attacker_owner:\n            if cache_key is not None:\n                self.exact_need_cache[cache_key] = 0\n            return 0\n\n        def owns_at(ships):\n            owner_after, _ = self.projected_state(\n                target_id,\n                eval_turn,\n                planned_commitments=planned_commitments,\n                extra_arrivals=normalized_extra + ((arrival_turn, attacker_owner, int(ships)),),\n            )\n            return owner_after == attacker_owner\n\n        if upper_bound is not None:\n            hi = max(1, int(upper_bound))\n            if not owns_at(hi):\n                return hi + 1\n        else:\n            hi = max(1, int(math.ceil(ships_before)) + 1)\n            search_cap = self._ownership_search_cap(eval_turn)\n            while hi <= search_cap and not owns_at(hi):\n                hi *= 2\n            if hi > search_cap:\n                hi = search_cap\n                if not owns_at(hi):\n                    return hi + 1\n\n        lo = 1\n        while lo < hi:\n            mid = (lo + hi) // 2\n            if owns_at(mid):\n                hi = mid\n            else:\n                lo = mid + 1\n\n        if cache_key is not None:\n            self.exact_need_cache[cache_key] = lo\n        return lo\n\n    def min_ships_to_own_at(\n        self,\n        target_id,\n        arrival_turn,\n        attacker_owner,\n        planned_commitments=None,\n        extra_arrivals=(),\n        upper_bound=None,\n    ):\n        return self.min_ships_to_own_by(\n            target_id,\n            arrival_turn,\n            attacker_owner,\n            arrival_turn=arrival_turn,\n            planned_commitments=planned_commitments,\n            extra_arrivals=extra_arrivals,\n            upper_bound=upper_bound,\n        )\n\n    def reinforcement_needed_to_hold_until(\n        self,\n        planet_id,\n        arrival_turn,\n        hold_until,\n        planned_commitments=None,\n        upper_bound=None,\n    ):\n        planned_commitments = planned_commitments or {}\n        target = self.planet_by_id[planet_id]\n        arrival_turn = max(1, int(math.ceil(arrival_turn)))\n        hold_until = max(arrival_turn, int(math.ceil(hold_until)))\n\n        if target.owner != self.player:\n            return self.min_ships_to_own_by(\n                planet_id,\n                hold_until,\n                self.player,\n                arrival_turn=arrival_turn,\n                planned_commitments=planned_commitments,\n                upper_bound=upper_bound,\n            )\n\n        def holds_with_reinforcement(ships):\n            timeline = self.projected_timeline(\n                planet_id,\n                hold_until,\n                planned_commitments=planned_commitments,\n                extra_arrivals=((arrival_turn, self.player, int(ships)),),\n            )\n            for turn in range(arrival_turn, hold_until + 1):\n                if timeline["owner_at"].get(turn) != self.player:\n                    return False\n            return True\n\n        if upper_bound is not None:\n            hi = max(1, int(upper_bound))\n            if not holds_with_reinforcement(hi):\n                return hi + 1\n        else:\n            hi = 1\n            search_cap = self._ownership_search_cap(hold_until)\n            while hi <= search_cap and not holds_with_reinforcement(hi):\n                hi *= 2\n            if hi > search_cap:\n                hi = search_cap\n                if not holds_with_reinforcement(hi):\n                    return hi + 1\n\n        lo = 1\n        while lo < hi:\n            mid = (lo + hi) // 2\n            if holds_with_reinforcement(mid):\n                hi = mid\n            else:\n                lo = mid + 1\n        return lo\n\n    def ships_needed_to_capture(\n        self,\n        target_id,\n        arrival_turn,\n        planned_commitments=None,\n        extra_arrivals=(),\n    ):\n        return self.min_ships_to_own_at(\n            target_id,\n            arrival_turn,\n            self.player,\n            planned_commitments=planned_commitments,\n            extra_arrivals=extra_arrivals,\n        )\n\n# ============================================================\n# Strategy\n# ============================================================\n\ndef planet_distance(first, second):\n    return math.hypot(first.x - second.x, first.y - second.y)\n\n\ndef nearest_sources_to_target(target, sources, top_k):\n    if top_k <= 0 or len(sources) <= top_k:\n        return sources\n    return sorted(\n        sources,\n        key=lambda src: (planet_distance(src, target), -int(src.ships), src.id),\n    )[:top_k]\n\n\ndef min_legal_reaction_time(target, sources, world):\n    best = 10**9\n    for src in sources:\n        seeded = world.best_probe_aim(src.id, target.id, max(1, int(src.ships)))\n        if seeded is None:\n            continue\n        _, aim = seeded\n        best = min(best, aim[1])\n    return best\n\n\ndef policy_reaction_times(target_id, policy):\n    return policy["reaction_time_map"].get(target_id, (10**9, 10**9))\n\n\ndef candidate_time_valid(target, turns, world, remaining_buffer):\n    if turns > world.remaining_steps - remaining_buffer:\n        return False\n    if target.id in world.comet_ids:\n        life = world.comet_life(target.id)\n        if turns >= life or turns > COMET_MAX_CHASE_TURNS:\n            return False\n    return True\n\n\ndef stacked_enemy_proactive_keep(planet, world):\n    threats = []\n    for enemy in world.enemy_planets:\n        seeded = world.best_probe_aim(enemy.id, planet.id, max(1, int(enemy.ships)))\n        if seeded is None:\n            continue\n        _, aim = seeded\n        eta = aim[1]\n        if eta > MULTI_ENEMY_PROACTIVE_HORIZON:\n            continue\n        threats.append((eta, int(enemy.ships)))\n\n    if not threats:\n        return 0\n\n    threats.sort()\n    best_stacked = 0\n    left = 0\n    running = 0\n    for right in range(len(threats)):\n        running += threats[right][1]\n        while threats[right][0] - threats[left][0] > MULTI_ENEMY_STACK_WINDOW:\n            running -= threats[left][1]\n            left += 1\n        best_stacked = max(best_stacked, running)\n\n    return int(best_stacked * MULTI_ENEMY_PROACTIVE_RATIO)\n\n\ndef swarm_eta_tolerance(options, target, world):\n    if len(options) >= 3:\n        return THREE_SOURCE_ETA_TOLERANCE\n    if target.owner not in (-1, world.player):\n        return HOSTILE_SWARM_ETA_TOLERANCE\n    return MULTI_SOURCE_ETA_TOLERANCE\n\n\ndef detect_enemy_crashes(world):\n    crashes = []\n    for target_id, arrivals in world.arrivals_by_planet.items():\n        enemy_events = [\n            (int(math.ceil(eta)), owner, int(ships))\n            for eta, owner, ships in arrivals\n            if owner not in (-1, world.player) and ships > 0\n        ]\n        enemy_events.sort()\n        for i in range(len(enemy_events)):\n            eta_a, owner_a, ships_a = enemy_events[i]\n            for j in range(i + 1, len(enemy_events)):\n                eta_b, owner_b, ships_b = enemy_events[j]\n                if owner_a == owner_b:\n                    continue\n                if abs(eta_a - eta_b) > CRASH_EXPLOIT_ETA_WINDOW:\n                    break\n                if ships_a + ships_b < CRASH_EXPLOIT_MIN_TOTAL_SHIPS:\n                    continue\n                crashes.append({\n                    "target_id": target_id,\n                    "crash_turn": max(eta_a, eta_b),\n                    "owners": (owner_a, owner_b),\n                    "ships": (ships_a, ships_b),\n                })\n    return crashes\n\n\ndef detect_enemy_planet_battles(world):\n    """\n    Detect where an enemy fleet is attacking another enemy\'s owned planet.\n    These create attack windows — the winning side will be weakened.\n    Returns list of dicts with target_id, battle_turn, estimated post_battle_ships.\n    """\n    battles = []\n    for target in world.enemy_planets:\n        attacking_fleets = [\n            (int(math.ceil(eta)), owner, int(ships))\n            for eta, owner, ships in world.arrivals_by_planet.get(target.id, [])\n            if owner not in (-1, world.player) and owner != target.owner and ships > 0\n        ]\n        if not attacking_fleets:\n            continue\n\n        for eta, attacker_owner, attacker_ships in attacking_fleets:\n            # Rough post-battle estimate (production growth + garrison vs attacker)\n            garrison_at_eta = target.ships + target.production * eta\n            surviving_attacker = max(0, attacker_ships - garrison_at_eta)\n            surviving_defender = max(0, garrison_at_eta - attacker_ships)\n\n            if attacker_ships > garrison_at_eta:\n                post_owner = attacker_owner\n                post_ships = surviving_attacker\n            else:\n                post_owner = target.owner\n                post_ships = surviving_defender\n\n            # Only interesting if planet will be weak after battle\n            if post_ships < 25:\n                battles.append({\n                    "target_id": target.id,\n                    "battle_turn": eta,\n                    "post_owner": post_owner,\n                    "post_ships": post_ships,\n                    "original_owner": target.owner,\n                })\n\n    return battles\n\n\ndef build_policy_state(world, deadline=None):\n    def expired():\n        return deadline is not None and time.perf_counter() > deadline\n\n    indirect_wealth_map = {}\n    for target_id, features in world.indirect_feature_map.items():\n        friendly, neutral, enemy = features\n        indirect_wealth_map[target_id] = (\n            friendly * INDIRECT_FRIENDLY_WEIGHT\n            + neutral * INDIRECT_NEUTRAL_WEIGHT\n            + enemy * INDIRECT_ENEMY_WEIGHT\n        )\n\n    reserve = {}\n    attack_budget = {}\n    reaction_time_map = {}\n\n    for target in world.planets:\n        if expired():\n            break\n        if target.owner == world.player:\n            continue\n        my_sources = nearest_sources_to_target(target, world.my_planets, REACTION_SOURCE_TOP_K_MY)\n        enemy_sources = nearest_sources_to_target(target, world.enemy_planets, REACTION_SOURCE_TOP_K_ENEMY)\n        my_t = min_legal_reaction_time(target, my_sources, world)\n        enemy_t = min_legal_reaction_time(target, enemy_sources, world)\n        reaction_time_map[target.id] = (my_t, enemy_t)\n\n    for planet in world.my_planets:\n        if expired():\n            break\n        exact_keep = world.keep_needed_map.get(planet.id, 0)\n\n        proactive_keep = 0\n        for enemy in nearest_sources_to_target(planet, world.enemy_planets, PROACTIVE_ENEMY_TOP_K):\n            enemy_aim = world.plan_shot(enemy.id, planet.id, max(1, int(enemy.ships)))\n            if enemy_aim is None:\n                continue\n            enemy_eta = enemy_aim[1]\n            if enemy_eta > PROACTIVE_DEFENSE_HORIZON:\n                continue\n            proactive_keep = max(proactive_keep, int(enemy.ships * PROACTIVE_DEFENSE_RATIO))\n        proactive_keep = max(proactive_keep, stacked_enemy_proactive_keep(planet, world))\n\n        if world.is_four_player and proactive_keep > 0 and not world.is_late:\n            cap_ratio = FOUR_PLAYER_PROACTIVE_RESERVE_CAP\n            if world.max_enemy_prod >= world.my_prod + FOUR_PLAYER_LEADER_PRESSURE_MIN_GAP:\n                cap_ratio = FOUR_PLAYER_BEHIND_RESERVE_CAP\n            proactive_cap = max(\n                int(planet.production) + 2,\n                int(planet.ships * cap_ratio),\n            )\n            proactive_keep = min(proactive_keep, proactive_cap)\n\n        if world.is_total_war:\n            exact_keep = min(exact_keep, max(1, exact_keep // 2))\n            proactive_keep = min(proactive_keep, max(1, proactive_keep // 2))\n\n        reserve[planet.id] = min(int(planet.ships), max(exact_keep, proactive_keep))\n        attack_budget[planet.id] = max(0, int(planet.ships) - reserve[planet.id])\n\n    return {\n        "indirect_wealth_map": indirect_wealth_map,\n        "reserve": reserve,\n        "attack_budget": attack_budget,\n        "reaction_time_map": reaction_time_map,\n    }\n\n\ndef build_modes(world):\n    domination = (world.my_total - world.enemy_total) / max(1, world.my_total + world.enemy_total)\n    is_behind = domination < BEHIND_DOMINATION\n    is_ahead = domination > AHEAD_DOMINATION\n    prod_gap = world.max_enemy_prod - world.my_prod\n    is_prod_behind = (\n        not world.is_four_player\n        and world.step >= 35\n        and prod_gap >= 7\n        and world.max_enemy_prod > world.my_prod * 1.18\n    )\n    is_four_player_leader_pressure = (\n        world.is_four_player\n        and world.step >= 35\n        and prod_gap >= FOUR_PLAYER_LEADER_PRESSURE_MIN_GAP\n        and world.max_enemy_prod >= world.my_prod * FOUR_PLAYER_LEADER_PRESSURE_RATIO\n        and not is_ahead\n    )\n    is_snowball_risk = is_prod_behind and not is_ahead\n    is_dominating = is_ahead or (\n        world.max_enemy_strength > 0 and world.my_total > world.max_enemy_strength * 1.25\n    )\n    is_finishing = (\n        domination > FINISHING_DOMINATION\n        and world.my_prod > world.enemy_prod * FINISHING_PROD_RATIO\n        and world.step > 80\n    )\n\n    attack_margin_mult = 1.0\n    if is_ahead:\n        attack_margin_mult += AHEAD_ATTACK_MARGIN_BONUS\n    if is_behind:\n        attack_margin_mult -= BEHIND_ATTACK_MARGIN_PENALTY\n    if is_finishing:\n        attack_margin_mult += FINISHING_ATTACK_MARGIN_BONUS\n\n    return {\n        "domination": domination,\n        "is_behind": is_behind,\n        "is_ahead": is_ahead,\n        "is_prod_behind": is_prod_behind,\n        "is_four_player_leader_pressure": is_four_player_leader_pressure,\n        "is_snowball_risk": is_snowball_risk,\n        "is_dominating": is_dominating,\n        "is_finishing": is_finishing,\n        "attack_margin_mult": attack_margin_mult,\n    }\n\n\ndef is_safe_neutral(target, policy):\n    if target.owner != -1:\n        return False\n    my_t, enemy_t = policy_reaction_times(target.id, policy)\n    return my_t <= enemy_t - SAFE_NEUTRAL_MARGIN\n\n\ndef is_contested_neutral(target, policy):\n    if target.owner != -1:\n        return False\n    my_t, enemy_t = policy_reaction_times(target.id, policy)\n    return abs(my_t - enemy_t) <= CONTESTED_NEUTRAL_MARGIN\n\n\ndef opening_filter(target, arrival_turns, needed, src_available, world, policy, src=None):\n    if not world.is_opening or target.owner != -1:\n        return False\n    if target.id in world.comet_ids:\n        return False\n    if (\n        src is not None\n        and not world.is_four_player\n        and world.step < HIGH_PROD_SOURCE_SAVE_TURN_LIMIT\n        and int(src.production) >= HIGH_PROD_SOURCE_MIN_PROD\n        and target.production <= HIGH_PROD_SAVE_LOW_TARGET_MAX_PROD\n    ):\n        future_budget = src_available + int(src.production) * HIGH_PROD_SAVE_LOOKAHEAD_TURNS\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < HIGH_PROD_SAVE_TARGET_MIN_PROD:\n                continue\n            if int(candidate.ships) + 1 > future_budget:\n                continue\n            seeded = world.best_probe_aim(\n                src.id,\n                candidate.id,\n                max(1, src_available),\n                hints=(max(1, src_available), int(candidate.ships) + 1),\n            )\n            if seeded is None:\n                continue\n            _, aim = seeded\n            if aim[1] > HIGH_PROD_SAVE_MAX_ROUTE_TURNS:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if enemy_t + 5 < my_t:\n                continue\n            return True\n    if (\n        not world.is_four_player\n        and world.step < 35\n        and world.my_prod <= 2\n        and target.production <= 1\n    ):\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < 4:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if my_t <= 34 and enemy_t >= my_t - 3:\n                return True\n    if (\n        world.is_four_player\n        and src is not None\n        and world.step < 55\n        and target.production <= 1\n    ):\n        full_source = max(1, int(src.ships))\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < 3:\n                continue\n            if int(candidate.ships) + 1 > full_source:\n                continue\n            seeded = world.best_probe_aim(\n                src.id,\n                candidate.id,\n                full_source,\n                hints=(int(candidate.ships) + 1,),\n            )\n            if seeded is None:\n                continue\n            _, aim = seeded\n            if aim[1] > 34:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if enemy_t >= my_t - 3:\n                return True\n    if (\n        world.is_four_player\n        and src is not None\n        and world.step < 32\n        and target.production <= 3\n    ):\n        full_source = max(1, int(src.ships))\n        future_source = full_source + int(src.production) * 4\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < 5:\n                continue\n            need_hint = int(candidate.ships) + 1\n            if need_hint > future_source:\n                continue\n            aim = world.plan_shot(src.id, candidate.id, min(future_source, need_hint))\n            if aim is None:\n                continue\n            if aim[1] > 30:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if enemy_t >= my_t - 4:\n                return True\n    if world.is_static(target.id):\n        return False\n\n    my_t, enemy_t = policy_reaction_times(target.id, policy)\n    reaction_gap = enemy_t - my_t\n    if (\n        target.production >= SAFE_OPENING_PROD_THRESHOLD\n        and arrival_turns <= SAFE_OPENING_TURN_LIMIT\n        and reaction_gap >= SAFE_NEUTRAL_MARGIN\n    ):\n        return False\n\n    if world.is_four_player:\n        affordable = needed <= max(\n            PARTIAL_SOURCE_MIN_SHIPS,\n            int(src_available * FOUR_PLAYER_ROTATING_SEND_RATIO),\n        )\n        if (\n            affordable\n            and arrival_turns <= FOUR_PLAYER_ROTATING_TURN_LIMIT\n            and reaction_gap >= FOUR_PLAYER_ROTATING_REACTION_GAP\n        ):\n            return False\n        return True\n\n    return arrival_turns > ROTATING_OPENING_MAX_TURNS or target.production <= ROTATING_OPENING_LOW_PROD\n\n\ndef target_value(target, arrival_turns, mission, world, modes, policy):\n    turns_profit = max(1, world.remaining_steps - arrival_turns)\n    if target.id in world.comet_ids:\n        life = world.comet_life(target.id)\n        turns_profit = max(0, min(turns_profit, life - arrival_turns))\n        if turns_profit <= 0:\n            return -1.0\n\n    value = target.production * turns_profit\n    value += policy["indirect_wealth_map"][target.id] * turns_profit * INDIRECT_VALUE_SCALE\n\n    if world.is_static(target.id):\n        value *= STATIC_NEUTRAL_VALUE_MULT if target.owner == -1 else STATIC_HOSTILE_VALUE_MULT\n    else:\n        value *= ROTATING_OPENING_VALUE_MULT if world.is_opening else 1.0\n\n    if target.owner not in (-1, world.player):\n        value *= OPENING_HOSTILE_TARGET_VALUE_MULT if world.is_opening else HOSTILE_TARGET_VALUE_MULT\n\n    if target.owner == -1:\n        if is_safe_neutral(target, policy):\n            value *= SAFE_NEUTRAL_VALUE_MULT\n        elif is_contested_neutral(target, policy):\n            value *= CONTESTED_NEUTRAL_VALUE_MULT\n        if world.is_early:\n            value *= EARLY_NEUTRAL_VALUE_MULT\n        if world.is_four_player and world.is_opening:\n            if target.production >= 4:\n                value *= FOUR_PLAYER_HIGH_PROD_NEUTRAL_VALUE_MULT\n            elif target.production <= 1:\n                value *= FOUR_PLAYER_LOW_PROD_OPENING_VALUE_MULT\n\n    if target.id in world.comet_ids:\n        value *= COMET_VALUE_MULT\n\n    if mission == "snipe":\n        value *= SNIPE_VALUE_MULT\n    elif mission == "swarm":\n        value *= SWARM_VALUE_MULT\n    elif mission == "reinforce":\n        value *= REINFORCE_VALUE_MULT\n    elif mission == "crash_exploit":\n        value *= CRASH_EXPLOIT_VALUE_MULT\n\n    if target.id in world.exposed_planet_ids:\n        value *= EXPOSED_PLANET_VALUE_MULT\n\n    if world.is_late:\n        value += max(0, target.ships) * LATE_IMMEDIATE_SHIP_VALUE\n\n    # Elimination bonus — applies whenever enemy is weak (not just late game)\n    if target.owner not in (-1, world.player):\n        enemy_strength = world.owner_strength.get(target.owner, 0)\n        if enemy_strength <= WEAK_ENEMY_THRESHOLD:\n            value += ELIMINATION_BONUS\n\n    # Weakest enemy targeting bonus (key for 4P strategy)\n    if target.owner not in (-1, world.player) and world._weakest_enemy is not None:\n        if target.owner == world._weakest_enemy:\n            if not (\n                world.is_four_player\n                and modes.get("is_four_player_leader_pressure")\n                and target.owner != world._leader_enemy\n            ):\n                mult = WEAKEST_ENEMY_VALUE_MULT_4P if world.is_four_player else WEAKEST_ENEMY_VALUE_MULT_2P\n                value *= mult\n    if world.is_four_player and target.owner not in (-1, world.player):\n        if target.owner == world._leader_enemy:\n            if modes.get("is_four_player_leader_pressure") or target.production >= 4:\n                value *= FOUR_PLAYER_LEADER_TARGET_VALUE_MULT\n        elif modes.get("is_four_player_leader_pressure") and target.production <= 1:\n            value *= FOUR_PLAYER_LOW_PROD_HOSTILE_VALUE_MULT\n\n    if modes["is_finishing"] and target.owner not in (-1, world.player):\n        value *= FINISHING_HOSTILE_VALUE_MULT\n    if modes["is_snowball_risk"]:\n        if target.owner not in (-1, world.player):\n            value *= 1.35\n        elif target.owner == -1 and target.production >= 4:\n            value *= 1.12\n        elif target.owner == -1 and target.production <= 2:\n            value *= 0.78\n    if modes["is_behind"] and target.owner == -1 and not world.is_static(target.id):\n        value *= BEHIND_ROTATING_NEUTRAL_VALUE_MULT\n    if modes["is_behind"] and target.owner == -1 and is_safe_neutral(target, policy):\n        value *= 1.08\n    if modes["is_dominating"] and target.owner == -1 and is_contested_neutral(target, policy):\n        value *= 0.92\n\n    return value\n\n\ndef reinforce_value(target, hold_until, world, policy):\n    saved_turns = max(1, world.remaining_steps - hold_until)\n    value = target.production * saved_turns + max(0, target.ships) * DEFENSE_SHIP_VALUE\n    if world.enemy_planets and nearest_distance_to_set(target.x, target.y, world.enemy_planets) < 22:\n        value *= DEFENSE_FRONTIER_SCORE_MULT\n    value += policy["indirect_wealth_map"][target.id] * saved_turns * INDIRECT_VALUE_SCALE * 0.35\n    return value * REINFORCE_VALUE_MULT\n\n\ndef preferred_send(target, base_needed, arrival_turns, src_available, world, modes, policy):\n    send = max(base_needed, int(math.ceil(base_needed * modes["attack_margin_mult"])))\n    margin = 0\n    if target.owner == -1:\n        margin += min(\n            NEUTRAL_MARGIN_CAP,\n            NEUTRAL_MARGIN_BASE + target.production * NEUTRAL_MARGIN_PROD_WEIGHT,\n        )\n    else:\n        margin += min(\n            HOSTILE_MARGIN_CAP,\n            HOSTILE_MARGIN_BASE + target.production * HOSTILE_MARGIN_PROD_WEIGHT,\n        )\n    if world.is_static(target.id):\n        margin += STATIC_TARGET_MARGIN\n    if is_contested_neutral(target, policy):\n        margin += CONTESTED_TARGET_MARGIN\n    if world.is_four_player:\n        margin += FOUR_PLAYER_TARGET_MARGIN\n    if arrival_turns > LONG_TRAVEL_MARGIN_START:\n        margin += min(LONG_TRAVEL_MARGIN_CAP, arrival_turns // LONG_TRAVEL_MARGIN_DIVISOR)\n    if target.id in world.comet_ids:\n        margin = max(0, margin - COMET_MARGIN_RELIEF)\n    if modes["is_finishing"] and target.owner not in (-1, world.player):\n        margin += FINISHING_HOSTILE_SEND_BONUS\n    if modes["is_snowball_risk"]:\n        if target.owner == -1 and target.production <= 2:\n            margin = max(0, margin - 3)\n        elif target.owner not in (-1, world.player):\n            margin = max(0, margin - 1)\n    if target.id in world.exposed_planet_ids:\n        margin = max(0, margin - 2)\n    # In 4P, be more efficient when targeting weakest enemy (finishing blow)\n    if world.is_four_player and world._weakest_enemy is not None and target.owner == world._weakest_enemy:\n        margin = max(0, margin - 2)\n    if (\n        world.is_four_player\n        and modes.get("is_four_player_leader_pressure")\n        and target.owner == world._leader_enemy\n    ):\n        margin = max(0, margin - 1)\n    return min(src_available, send + margin)\n\n\ndef apply_score_modifiers(base_score, target, mission, world):\n    score = base_score\n    if world.is_static(target.id):\n        score *= STATIC_TARGET_SCORE_MULT\n    if world.is_early and target.owner == -1 and world.is_static(target.id):\n        score *= EARLY_STATIC_NEUTRAL_SCORE_MULT\n    if world.is_four_player and target.owner == -1 and not world.is_static(target.id):\n        score *= FOUR_PLAYER_ROTATING_NEUTRAL_SCORE_MULT\n    if (\n        len(world.static_neutral_planets) >= DENSE_STATIC_NEUTRAL_COUNT\n        and target.owner == -1\n        and not world.is_static(target.id)\n    ):\n        score *= DENSE_ROTATING_NEUTRAL_SCORE_MULT\n    if mission == "snipe":\n        score *= SNIPE_SCORE_MULT\n    elif mission == "swarm":\n        score *= SWARM_SCORE_MULT\n    elif mission == "crash_exploit":\n        score *= CRASH_EXPLOIT_SCORE_MULT\n    if target.id in world.exposed_planet_ids:\n        score *= 1.25\n    if target.owner not in (-1, world.player):\n        # When production is slipping away, every viable enemy capture also\n        # denies future production to the leader.\n        # `world` modes are not available here, so use the raw production gap.\n        if not world.is_four_player and world.step >= 35 and world.max_enemy_prod >= world.my_prod + 7:\n            score *= 1.12\n        if world.is_four_player and target.owner == world._leader_enemy:\n            leader_gap = world.max_enemy_prod - world.my_prod\n            if (\n                target.production >= 4\n                or (\n                    world.step >= 35\n                    and leader_gap >= FOUR_PLAYER_LEADER_PRESSURE_MIN_GAP\n                    and world.max_enemy_prod >= world.my_prod * FOUR_PLAYER_LEADER_PRESSURE_RATIO\n                )\n            ):\n                score *= FOUR_PLAYER_LEADER_SCORE_MULT\n    elif (\n        target.owner == -1\n        and not world.is_four_player\n        and world.step >= 35\n        and world.max_enemy_prod >= world.my_prod + 7\n        and target.production <= 2\n    ):\n        score *= 0.9\n    # Bonus score for targeting weakest enemy planet\n    if target.owner not in (-1, world.player) and world._weakest_enemy == target.owner:\n        leader_gap = world.max_enemy_prod - world.my_prod\n        if not (\n            world.is_four_player\n            and target.owner != world._leader_enemy\n            and world.step >= 35\n            and leader_gap >= FOUR_PLAYER_LEADER_PRESSURE_MIN_GAP\n        ):\n            score *= 1.2\n    return score\n\n\ndef settle_plan(\n    src,\n    target,\n    src_cap,\n    send_guess,\n    world,\n    planned_commitments,\n    modes,\n    policy,\n    mission="capture",\n    eval_turn_fn=None,\n    anchor_turn=None,\n    anchor_tolerance=None,\n    max_iter=4,\n):\n    if src_cap < 1:\n        return None\n\n    seed_hint = max(1, min(src_cap, int(send_guess)))\n    eval_turn_fn = eval_turn_fn or (lambda turns: turns)\n    anchor_tolerance = (\n        anchor_tolerance\n        if anchor_tolerance is not None\n        else (1 if mission == "snipe" else None)\n    )\n    tested = {}\n    tested_order = []\n\n    def evaluate(send):\n        send = max(1, min(src_cap, int(send)))\n        cached = tested.get(send)\n        if cached is not None or send in tested:\n            return cached\n\n        aim = world.plan_shot(src.id, target.id, send)\n        if aim is None:\n            tested[send] = None\n            return None\n\n        angle, turns, _, _ = aim\n        if mission == "crash_exploit" and anchor_turn is not None and turns < anchor_turn:\n            tested[send] = None\n            return None\n        raw_eval_turn = int(math.ceil(eval_turn_fn(turns)))\n        if raw_eval_turn < turns:\n            tested[send] = None\n            return None\n        eval_turn = raw_eval_turn\n        need = world.min_ships_to_own_by(\n            target.id,\n            eval_turn,\n            world.player,\n            arrival_turn=turns,\n            planned_commitments=planned_commitments,\n            upper_bound=src_cap,\n        )\n        if need <= 0 or need > src_cap:\n            tested[send] = None\n            return None\n\n        if mission in ("snipe", "crash_exploit"):\n            desired = need\n        elif mission == "rescue":\n            desired = min(\n                src_cap,\n                max(\n                    need,\n                    need + DEFENSE_SEND_MARGIN_BASE + target.production * DEFENSE_SEND_MARGIN_PROD_WEIGHT,\n                ),\n            )\n        else:\n            desired = min(\n                src_cap,\n                max(need, preferred_send(target, need, turns, src_cap, world, modes, policy)),\n            )\n\n        result = (angle, turns, eval_turn, need, send, desired)\n        tested[send] = result\n        tested_order.append(send)\n        return result\n\n    initial_candidates = sorted(\n        world.probe_ship_candidates(src.id, target.id, src_cap, hints=(seed_hint,)),\n        key=lambda send: (abs(send - seed_hint), send),\n    )\n\n    current_send = None\n    for seed in initial_candidates:\n        result = evaluate(seed)\n        if result is None:\n            continue\n        if (\n            anchor_turn is not None\n            and anchor_tolerance is not None\n            and abs(result[1] - anchor_turn) > anchor_tolerance\n        ):\n            continue\n        current_send = seed\n        break\n\n    if current_send is None:\n        return None\n\n    for _ in range(max_iter):\n        result = evaluate(current_send)\n        if result is None:\n            break\n\n        angle, turns, eval_turn, need, actual_send, desired = result\n        if desired == actual_send:\n            if (\n                anchor_turn is not None\n                and anchor_tolerance is not None\n                and abs(turns - anchor_turn) > anchor_tolerance\n            ):\n                return None\n            if mission == "rescue" and turns > eval_turn:\n                return None\n            return angle, turns, eval_turn, need, actual_send\n\n        next_send = max(1, min(src_cap, int(desired)))\n        if next_send in tested:\n            current_send = next_send\n            break\n        current_send = next_send\n\n    candidate_sends = sorted(\n        [send for send in tested_order if tested.get(send) is not None],\n        key=lambda send: (\n            0 if mission != "snipe" or anchor_turn is None else abs(tested[send][1] - anchor_turn),\n            abs(send - seed_hint),\n            tested[send][1],\n            send,\n        ),\n    )\n\n    seen = set()\n    for send in candidate_sends:\n        if send in seen:\n            continue\n        seen.add(send)\n        result = tested.get(send)\n        if result is None:\n            continue\n        angle, turns, eval_turn, need, actual_send, _ = result\n        if actual_send < need:\n            continue\n        if (\n            anchor_turn is not None\n            and anchor_tolerance is not None\n            and abs(turns - anchor_turn) > anchor_tolerance\n        ):\n            continue\n        if mission == "rescue" and turns > eval_turn:\n            continue\n        return angle, turns, eval_turn, need, actual_send\n\n    return None\n\n\ndef settle_reinforce_plan(\n    src,\n    target,\n    src_cap,\n    send_guess,\n    world,\n    planned_commitments,\n    hold_until,\n    max_arrival_turn,\n    max_iter=4,\n):\n    if src_cap < 1:\n        return None\n\n    seed_hint = max(1, min(src_cap, int(send_guess)))\n    tested = {}\n    tested_order = []\n\n    def evaluate(send):\n        send = max(1, min(src_cap, int(send)))\n        cached = tested.get(send)\n        if cached is not None or send in tested:\n            return cached\n\n        aim = world.plan_shot(src.id, target.id, send)\n        if aim is None:\n            tested[send] = None\n            return None\n\n        angle, turns, _, _ = aim\n        if turns > max_arrival_turn:\n            tested[send] = None\n            return None\n\n        need = world.reinforcement_needed_to_hold_until(\n            target.id,\n            turns,\n            hold_until,\n            planned_commitments=planned_commitments,\n            upper_bound=src_cap,\n        )\n        if need <= 0 or need > src_cap:\n            tested[send] = None\n            return None\n\n        desired = min(src_cap, need + REINFORCE_SAFETY_MARGIN)\n        result = (angle, turns, hold_until, need, send, desired)\n        tested[send] = result\n        tested_order.append(send)\n        return result\n\n    initial_candidates = sorted(\n        world.probe_ship_candidates(src.id, target.id, src_cap, hints=(seed_hint,)),\n        key=lambda send: (abs(send - seed_hint), send),\n    )\n\n    current_send = None\n    for seed in initial_candidates:\n        result = evaluate(seed)\n        if result is None:\n            continue\n        current_send = seed\n        break\n\n    if current_send is None:\n        return None\n\n    for _ in range(max_iter):\n        result = evaluate(current_send)\n        if result is None:\n            break\n\n        angle, turns, eval_turn, need, actual_send, desired = result\n        if desired == actual_send:\n            return angle, turns, eval_turn, need, actual_send\n\n        next_send = max(1, min(src_cap, int(desired)))\n        if next_send in tested:\n            current_send = next_send\n            break\n        current_send = next_send\n\n    candidate_sends = sorted(\n        [send for send in tested_order if tested.get(send) is not None],\n        key=lambda send: (abs(send - seed_hint), tested[send][1], send),\n    )\n    for send in candidate_sends:\n        result = tested.get(send)\n        if result is None:\n            continue\n        angle, turns, eval_turn, need, actual_send, _ = result\n        if actual_send < need or turns > max_arrival_turn:\n            continue\n        return angle, turns, eval_turn, need, actual_send\n\n    return None\n\n\ndef build_snipe_mission(src, target, src_available, world, planned_commitments, modes, policy):\n    if target.owner != -1:\n        return None\n\n    enemy_etas = sorted({\n        int(math.ceil(eta))\n        for eta, owner, ships in world.arrivals_by_planet.get(target.id, [])\n        if owner not in (-1, world.player) and ships > 0\n    })\n    if not enemy_etas:\n        return None\n\n    best = None\n    for enemy_eta in enemy_etas[:3]:\n        seeded = world.best_probe_aim(\n            src.id,\n            target.id,\n            src_available,\n            hints=(int(target.ships) + 1, int(target.ships) + 8),\n            anchor_turn=enemy_eta,\n            max_anchor_diff=1,\n        )\n        if seeded is None:\n            continue\n\n        probe, rough = seeded\n        sync_turn = max(rough[1], enemy_eta)\n        if target.id in world.comet_ids:\n            life = world.comet_life(target.id)\n            if sync_turn >= life or sync_turn > COMET_MAX_CHASE_TURNS:\n                continue\n\n        plan = settle_plan(\n            src,\n            target,\n            src_available,\n            probe,\n            world,\n            planned_commitments,\n            modes,\n            policy,\n            mission="snipe",\n            eval_turn_fn=lambda turns, enemy_eta=enemy_eta: max(turns, enemy_eta),\n            anchor_turn=enemy_eta,\n        )\n        if plan is None:\n            continue\n\n        angle, turns, sync_turn, need, send_pref = plan\n        if target.id in world.comet_ids:\n            life = world.comet_life(target.id)\n            if sync_turn >= life or sync_turn > COMET_MAX_CHASE_TURNS:\n                continue\n\n        value = target_value(target, sync_turn, "snipe", world, modes, policy)\n        if value <= 0:\n            continue\n\n        score = apply_score_modifiers(\n            value / (send_pref + sync_turn * SNIPE_COST_TURN_WEIGHT + 1.0),\n            target,\n            "snipe",\n            world,\n        )\n        option = ShotOption(\n            score=score,\n            src_id=src.id,\n            target_id=target.id,\n            angle=angle,\n            turns=turns,\n            needed=need,\n            send_cap=send_pref,\n            mission="snipe",\n            anchor_turn=enemy_eta,\n        )\n        mission_obj = Mission(\n            kind="snipe",\n            score=score,\n            target_id=target.id,\n            turns=sync_turn,\n            options=[option],\n        )\n        if best is None or mission_obj.score > best.score:\n            best = mission_obj\n\n    return best\n\n\ndef build_rescue_missions(world, policy, planned_commitments, modes):\n    missions = []\n\n    for target in world.my_planets:\n        fall_turn = world.fall_turn_map.get(target.id)\n        if fall_turn is None or fall_turn > DEFENSE_LOOKAHEAD_TURNS:\n            continue\n\n        for src in world.my_planets:\n            if src.id == target.id:\n                continue\n\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < PARTIAL_SOURCE_MIN_SHIPS:\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(target.production + DEFENSE_SEND_MARGIN_BASE + 2,),\n                max_turn=fall_turn,\n            )\n            if seeded is None:\n                continue\n            probe, probe_aim = seeded\n            plan = settle_plan(\n                src,\n                target,\n                src_available,\n                probe,\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="rescue",\n                eval_turn_fn=lambda _turns, fall_turn=fall_turn: fall_turn,\n                anchor_turn=fall_turn,\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            saved_turns = max(1, world.remaining_steps - fall_turn)\n            value = target.production * saved_turns + max(0, target.ships) * DEFENSE_SHIP_VALUE\n            if world.enemy_planets and nearest_distance_to_set(target.x, target.y, world.enemy_planets) < 22:\n                value *= DEFENSE_FRONTIER_SCORE_MULT\n            score = value / (send_pref + turns * DEFENSE_COST_TURN_WEIGHT + 1.0)\n\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="rescue",\n                anchor_turn=fall_turn,\n            )\n            missions.append(Mission(\n                kind="rescue",\n                score=score,\n                target_id=target.id,\n                turns=fall_turn,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_recapture_missions(world, policy, planned_commitments, modes):\n    missions = []\n\n    for target in world.my_planets:\n        fall_turn = world.fall_turn_map.get(target.id)\n        if fall_turn is None or fall_turn > DEFENSE_LOOKAHEAD_TURNS:\n            continue\n\n        for src in world.my_planets:\n            if src.id == target.id:\n                continue\n\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < PARTIAL_SOURCE_MIN_SHIPS:\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(target.production + DEFENSE_SEND_MARGIN_BASE + 2,),\n                min_turn=fall_turn + 1,\n                max_turn=fall_turn + RECAPTURE_LOOKAHEAD_TURNS,\n            )\n            if seeded is None:\n                continue\n            probe, probe_aim = seeded\n            probe_turns = probe_aim[1]\n\n            plan = settle_plan(\n                src,\n                target,\n                src_available,\n                probe,\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="capture",\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            if turns <= fall_turn or turns - fall_turn > RECAPTURE_LOOKAHEAD_TURNS:\n                continue\n\n            saved_turns = max(1, world.remaining_steps - turns)\n            value = (\n                RECAPTURE_PRODUCTION_WEIGHT * target.production * saved_turns\n                + RECAPTURE_IMMEDIATE_WEIGHT * max(0, target.ships)\n            )\n            if world.enemy_planets and nearest_distance_to_set(target.x, target.y, world.enemy_planets) < 22:\n                value *= RECAPTURE_FRONTIER_MULT\n            value *= RECAPTURE_VALUE_MULT\n            score = value / (send_pref + turns * RECAPTURE_COST_TURN_WEIGHT + 1.0)\n\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="recapture",\n                anchor_turn=fall_turn,\n            )\n            missions.append(Mission(\n                kind="recapture",\n                score=score,\n                target_id=target.id,\n                turns=turns,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_reinforce_missions(world, policy, planned_commitments, modes, inventory_left_fn):\n    if not REINFORCE_ENABLED:\n        return []\n\n    missions = []\n    if world.remaining_steps < REINFORCE_MIN_FUTURE_TURNS:\n        return missions\n\n    for target in world.my_planets:\n        fall_turn = world.fall_turn_map.get(target.id)\n        if fall_turn is None:\n            continue\n        if target.production < REINFORCE_MIN_PRODUCTION:\n            continue\n\n        hold_until = min(HORIZON, fall_turn + REINFORCE_HOLD_LOOKAHEAD)\n        max_arrival_turn = min(fall_turn, REINFORCE_MAX_TRAVEL_TURNS)\n\n        for src in world.my_planets:\n            if src.id == target.id:\n                continue\n\n            budget = inventory_left_fn(src.id)\n            source_cap = min(budget, int(src.ships * REINFORCE_MAX_SOURCE_FRACTION))\n            if source_cap < PARTIAL_SOURCE_MIN_SHIPS:\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                source_cap,\n                hints=(target.production + REINFORCE_SAFETY_MARGIN + 2,),\n                max_turn=max_arrival_turn,\n            )\n            if seeded is None:\n                continue\n            probe, _ = seeded\n\n            plan = settle_reinforce_plan(\n                src,\n                target,\n                source_cap,\n                probe,\n                world,\n                planned_commitments,\n                hold_until,\n                max_arrival_turn,\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            value = reinforce_value(target, hold_until, world, policy)\n            score = value / (send_pref + turns * REINFORCE_COST_TURN_WEIGHT + 1.0)\n\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="reinforce",\n                anchor_turn=hold_until,\n            )\n            missions.append(Mission(\n                kind="reinforce",\n                score=score,\n                target_id=target.id,\n                turns=fall_turn,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_crash_exploit_missions(world, policy, planned_commitments, modes):\n    if not CRASH_EXPLOIT_ENABLED or not world.is_four_player:\n        return []\n\n    missions = []\n    for crash in detect_enemy_crashes(world):\n        target = world.planet_by_id[crash["target_id"]]\n        if target.owner == world.player:\n            continue\n        desired_arrival = crash["crash_turn"] + CRASH_EXPLOIT_POST_CRASH_DELAY\n\n        for src in world.my_planets:\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < PARTIAL_SOURCE_MIN_SHIPS:\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(12, int(target.ships) + 1),\n                anchor_turn=desired_arrival,\n                max_anchor_diff=CRASH_EXPLOIT_ETA_WINDOW,\n            )\n            if seeded is None:\n                continue\n            probe, _ = seeded\n\n            plan = settle_plan(\n                src,\n                target,\n                src_available,\n                probe,\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="crash_exploit",\n                eval_turn_fn=lambda turns, desired_arrival=desired_arrival: max(turns, desired_arrival),\n                anchor_turn=desired_arrival,\n                anchor_tolerance=CRASH_EXPLOIT_ETA_WINDOW,\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            if not candidate_time_valid(target, turns, world, LATE_CAPTURE_BUFFER):\n                continue\n            value = target_value(target, turns, "crash_exploit", world, modes, policy)\n            if value <= 0:\n                continue\n\n            score = apply_score_modifiers(\n                value / (send_pref + turns * SNIPE_COST_TURN_WEIGHT + 1.0),\n                target,\n                "crash_exploit",\n                world,\n            )\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="crash_exploit",\n                anchor_turn=desired_arrival,\n            )\n            missions.append(Mission(\n                kind="crash_exploit",\n                score=score,\n                target_id=target.id,\n                turns=turns,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_gang_up_missions(world, policy, planned_commitments, modes):\n    """\n    Attack enemy planets that will be weakened by inter-enemy combat.\n    Schedule our fleet to arrive shortly after the battle resolves.\n    This is the key 4P tactic: use enemies fighting each other to our advantage.\n    """\n    missions = []\n\n    for battle in detect_enemy_planet_battles(world):\n        target = world.planet_by_id[battle["target_id"]]\n        if target.owner == world.player:\n            continue\n\n        # Arrive a couple turns after the battle to clean up\n        desired_arrival = battle["battle_turn"] + GANG_UP_POST_BATTLE_DELAY\n\n        for src in world.my_planets:\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < PARTIAL_SOURCE_MIN_SHIPS:\n                continue\n\n            # Hint: need just slightly more than estimated post-battle ships\n            post_hint = max(3, int(battle["post_ships"]) + 3)\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(post_hint, int(target.ships) + 1),\n                anchor_turn=desired_arrival,\n                max_anchor_diff=GANG_UP_ETA_WINDOW,\n            )\n            if seeded is None:\n                continue\n            probe, _ = seeded\n\n            plan = settle_plan(\n                src,\n                target,\n                src_available,\n                probe,\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="capture",\n                eval_turn_fn=lambda turns, da=desired_arrival: max(turns, da),\n                anchor_turn=desired_arrival,\n                anchor_tolerance=GANG_UP_ETA_WINDOW,\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            if not candidate_time_valid(target, turns, world, LATE_CAPTURE_BUFFER):\n                continue\n\n            value = target_value(target, turns, "capture", world, modes, policy)\n            value *= GANG_UP_VALUE_MULT  # extra bonus for exploiting enemy fight\n            if value <= 0:\n                continue\n\n            score = apply_score_modifiers(\n                value / (send_pref + turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                target,\n                "capture",\n                world,\n            )\n\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="capture",\n                anchor_turn=desired_arrival,\n            )\n            missions.append(Mission(\n                kind="single",\n                score=score,\n                target_id=target.id,\n                turns=turns,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_elimination_missions(world, policy, planned_commitments, modes):\n    """\n    Dedicated missions to eliminate the weakest enemy entirely.\n    High priority in 4P — removing a player is a massive advantage.\n    Only activates when we have a clear strength advantage over the target.\n    """\n    if world._weakest_enemy is None:\n        return []\n\n    weakest = world._weakest_enemy\n    weakest_total = world._weakest_enemy_strength\n\n    # Only pursue if we\'re meaningfully stronger than the target\n    if weakest_total > world.my_total * 0.9:\n        return []\n\n    # Must be clearly the weakest (not just slightly weaker than someone else)\n    other_enemies = [\n        s for owner, s in world.owner_strength.items()\n        if owner not in (world.player, weakest)\n    ]\n    if other_enemies and weakest_total > min(other_enemies) * 0.95:\n        return []\n\n    weakest_planets = [p for p in world.enemy_planets if p.owner == weakest]\n    if not weakest_planets:\n        return []\n\n    missions = []\n    elimination_bonus_mult = 1.5 if world.is_four_player else 1.25\n\n    for target in weakest_planets:\n        for src in world.my_planets:\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < PARTIAL_SOURCE_MIN_SHIPS:\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(int(target.ships) + 1, int(target.ships) + 5),\n            )\n            if seeded is None:\n                continue\n            probe, rough_aim = seeded\n            rough_turns = rough_aim[1]\n\n            if not candidate_time_valid(target, rough_turns, world, LATE_CAPTURE_BUFFER):\n                continue\n\n            global_needed = world.min_ships_to_own_at(\n                target.id, rough_turns, world.player,\n                planned_commitments=planned_commitments,\n            )\n            if global_needed <= 0 or global_needed > src_available:\n                continue\n\n            send_guess = preferred_send(target, global_needed, rough_turns, src_available, world, modes, policy)\n            plan = settle_plan(\n                src, target, src_available, send_guess,\n                world, planned_commitments, modes, policy,\n                mission="capture",\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            if not candidate_time_valid(target, turns, world, LATE_CAPTURE_BUFFER):\n                continue\n            if send_pref < need:\n                continue\n\n            value = target_value(target, turns, "capture", world, modes, policy)\n            if value <= 0:\n                continue\n\n            score = apply_score_modifiers(\n                value * elimination_bonus_mult / (send_pref + turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                target, "capture", world,\n            )\n\n            option = ShotOption(\n                score=score, src_id=src.id, target_id=target.id,\n                angle=angle, turns=turns, needed=need, send_cap=send_pref,\n                mission="capture",\n            )\n            missions.append(Mission(\n                kind="single", score=score, target_id=target.id,\n                turns=turns, options=[option],\n            ))\n\n    return missions\n\n\ndef plan_moves(world, deadline=None):\n    def expired():\n        return deadline is not None and time.perf_counter() > deadline\n\n    def time_left():\n        if deadline is None:\n            return 10**9\n        return deadline - time.perf_counter()\n\n    def allow_heavy_phase():\n        return time_left() > HEAVY_PHASE_MIN_TIME and len(world.planets) <= HEAVY_ROUTE_PLANET_LIMIT\n\n    def allow_optional_phase():\n        return time_left() > OPTIONAL_PHASE_MIN_TIME\n\n    modes = build_modes(world)\n    policy = build_policy_state(world, deadline=deadline)\n    planned_commitments = defaultdict(list)\n    source_options_by_target = defaultdict(list)\n    missions = []\n    moves = []\n    spent_total = defaultdict(int)\n\n    def source_inventory_left(source_id):\n        return world.source_inventory_left(source_id, spent_total)\n\n    def source_attack_left(source_id):\n        budget = policy["attack_budget"].get(source_id, 0)\n        return max(0, budget - spent_total[source_id])\n\n    def append_move(src_id, angle, ships):\n        send = min(int(ships), source_inventory_left(src_id))\n        if send < 1:\n            return 0\n        moves.append([src_id, float(angle), int(send)])\n        spent_total[src_id] += send\n        return send\n\n\n    def finalize_moves():\n        final_moves = []\n        used_final = defaultdict(int)\n        for src_id, angle, ships in moves:\n            source = world.planet_by_id[src_id]\n            max_allowed = int(source.ships) - used_final[src_id]\n            send = min(int(ships), max_allowed)\n            if send >= 1:\n                final_moves.append([src_id, float(angle), int(send)])\n                used_final[src_id] += send\n        return final_moves\n\n    def compute_live_doomed():\n        doomed = set()\n        for planet in world.my_planets:\n            status = world.hold_status(\n                planet.id,\n                planned_commitments=planned_commitments,\n                horizon=DOOMED_EVAC_TURN_LIMIT,\n            )\n            if (\n                not status["holds_full"]\n                and status["fall_turn"] is not None\n                and status["fall_turn"] <= DOOMED_EVAC_TURN_LIMIT\n                and source_inventory_left(planet.id) >= DOOMED_MIN_SHIPS\n            ):\n                doomed.add(planet.id)\n        return doomed\n\n    def time_filters_pass(target, turns, needed, src_cap, src=None):\n        if not candidate_time_valid(target, turns, world, VERY_LATE_CAPTURE_BUFFER if world.is_very_late else LATE_CAPTURE_BUFFER):\n            return False\n        if opening_filter(target, turns, needed, src_cap, world, policy, src=src):\n            return False\n        return True\n\n    # === MISSION BUILDING PHASE ===\n\n    if allow_heavy_phase():\n        missions.extend(\n            build_reinforce_missions(world, policy, planned_commitments, modes, source_inventory_left)\n        )\n\n    missions.extend(build_rescue_missions(world, policy, planned_commitments, modes))\n    missions.extend(build_recapture_missions(world, policy, planned_commitments, modes))\n\n    # Elimination missions — high priority in 4P\n    if allow_heavy_phase():\n        missions.extend(build_elimination_missions(world, policy, planned_commitments, modes))\n\n    # Gang-up missions — exploit inter-enemy fights (very useful in 4P)\n    if allow_heavy_phase():\n        missions.extend(build_gang_up_missions(world, policy, planned_commitments, modes))\n\n    for src in world.my_planets:\n        if expired():\n            return finalize_moves()\n        src_available = source_attack_left(src.id)\n        if src_available <= 0:\n            continue\n\n        for target in world.planets:\n            if expired():\n                return finalize_moves()\n            if target.id == src.id or target.owner == world.player:\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(int(target.ships) + 1,),\n            )\n            if seeded is None:\n                continue\n            _, rough_aim = seeded\n\n            rough_turns = rough_aim[1]\n            if not candidate_time_valid(\n                target,\n                rough_turns,\n                world,\n                VERY_LATE_CAPTURE_BUFFER if world.is_very_late else LATE_CAPTURE_BUFFER,\n            ):\n                continue\n\n            global_needed = world.min_ships_to_own_at(\n                target.id,\n                rough_turns,\n                world.player,\n                planned_commitments=planned_commitments,\n            )\n            if global_needed <= 0:\n                continue\n            if opening_filter(target, rough_turns, global_needed, src_available, world, policy, src=src):\n                continue\n\n            partial_send_cap = min(\n                src_available,\n                preferred_send(target, global_needed, rough_turns, src_available, world, modes, policy),\n            )\n            if partial_send_cap >= PARTIAL_SOURCE_MIN_SHIPS:\n                partial_seed = world.best_probe_aim(\n                    src.id,\n                    target.id,\n                    partial_send_cap,\n                    hints=(partial_send_cap, global_needed, int(target.ships) + 1),\n                )\n                if partial_seed is not None:\n                    _, partial_aim = partial_seed\n                    p_angle, p_turns, _, _ = partial_aim\n                    if time_filters_pass(target, p_turns, global_needed, src_available, src=src):\n                        partial_value = target_value(target, p_turns, "swarm", world, modes, policy)\n                        if partial_value > 0:\n                            partial_score = apply_score_modifiers(\n                                partial_value / (partial_send_cap + p_turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                                target,\n                                "swarm",\n                                world,\n                            )\n                            source_options_by_target[target.id].append(\n                                ShotOption(\n                                    score=partial_score,\n                                    src_id=src.id,\n                                    target_id=target.id,\n                                    angle=p_angle,\n                                    turns=p_turns,\n                                    needed=global_needed,\n                                    send_cap=partial_send_cap,\n                                    mission="swarm",\n                                )\n                            )\n\n            if global_needed <= src_available:\n                send_guess = preferred_send(\n                    target, global_needed, rough_turns, src_available, world, modes, policy,\n                )\n                plan = settle_plan(\n                    src,\n                    target,\n                    src_available,\n                    send_guess,\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="capture",\n                )\n                if plan is None:\n                    continue\n\n                angle, turns, _, needed, send_cap = plan\n                if not time_filters_pass(target, turns, needed, src_available, src=src):\n                    continue\n                if send_cap < 1:\n                    continue\n\n                value = target_value(target, turns, "capture", world, modes, policy)\n                if value <= 0:\n                    continue\n\n                score = apply_score_modifiers(\n                    value / (send_cap + turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                    target,\n                    "capture",\n                    world,\n                )\n\n                option = ShotOption(\n                    score=score,\n                    src_id=src.id,\n                    target_id=target.id,\n                    angle=angle,\n                    turns=turns,\n                    needed=needed,\n                    send_cap=send_cap,\n                    mission="capture",\n                )\n\n                if send_cap >= needed:\n                    missions.append(Mission(\n                        kind="single",\n                        score=score,\n                        target_id=target.id,\n                        turns=turns,\n                        options=[option],\n                    ))\n\n            snipe = build_snipe_mission(src, target, src_available, world, planned_commitments, modes, policy)\n            if snipe is not None:\n                missions.append(snipe)\n\n    for target_id, options in source_options_by_target.items():\n        if expired():\n            return finalize_moves()\n        if len(options) < 2:\n            continue\n\n        target = world.planet_by_id[target_id]\n        top_options = sorted(options, key=lambda item: -item.score)[:MULTI_SOURCE_TOP_K]\n        for i in range(len(top_options)):\n            for j in range(i + 1, len(top_options)):\n                first = top_options[i]\n                second = top_options[j]\n                if first.src_id == second.src_id:\n                    continue\n                pair_tol = swarm_eta_tolerance((first, second), target, world)\n                if abs(first.turns - second.turns) > pair_tol:\n                    continue\n\n                joint_turn = max(first.turns, second.turns)\n                total_cap = first.send_cap + second.send_cap\n                need = world.min_ships_to_own_at(\n                    target_id,\n                    joint_turn,\n                    world.player,\n                    planned_commitments=planned_commitments,\n                    upper_bound=total_cap,\n                )\n                if need <= 0:\n                    continue\n                if first.send_cap >= need or second.send_cap >= need:\n                    continue\n                if total_cap < need:\n                    continue\n\n                value = target_value(target, joint_turn, "swarm", world, modes, policy)\n                if value <= 0:\n                    continue\n\n                pair_score = apply_score_modifiers(\n                    value / (need + joint_turn * ATTACK_COST_TURN_WEIGHT + 1.0),\n                    target,\n                    "swarm",\n                    world,\n                )\n                pair_score *= MULTI_SOURCE_PLAN_PENALTY\n                missions.append(Mission(\n                    kind="swarm",\n                    score=pair_score,\n                    target_id=target_id,\n                    turns=joint_turn,\n                    options=[first, second],\n                ))\n\n        if (\n            THREE_SOURCE_SWARM_ENABLED\n            and allow_heavy_phase()\n            and target.owner not in (-1, world.player)\n            and int(target.ships) >= THREE_SOURCE_MIN_TARGET_SHIPS\n            and len(top_options) >= 3\n        ):\n            for i in range(len(top_options)):\n                for j in range(i + 1, len(top_options)):\n                    for k in range(j + 1, len(top_options)):\n                        if expired():\n                            return finalize_moves()\n                        trio = [top_options[i], top_options[j], top_options[k]]\n                        if len({option.src_id for option in trio}) < 3:\n                            continue\n                        trio_tol = swarm_eta_tolerance(tuple(trio), target, world)\n                        turns = [option.turns for option in trio]\n                        if max(turns) - min(turns) > trio_tol:\n                            continue\n\n                        joint_turn = max(turns)\n                        total_cap = sum(option.send_cap for option in trio)\n                        need = world.min_ships_to_own_at(\n                            target_id,\n                            joint_turn,\n                            world.player,\n                            planned_commitments=planned_commitments,\n                            upper_bound=total_cap,\n                        )\n                        if need <= 0 or total_cap < need:\n                            continue\n                        if any(\n                            trio[a].send_cap + trio[b].send_cap >= need\n                            for a in range(3)\n                            for b in range(a + 1, 3)\n                        ):\n                            continue\n\n                        value = target_value(target, joint_turn, "swarm", world, modes, policy)\n                        if value <= 0:\n                            continue\n\n                        trio_score = apply_score_modifiers(\n                            value / (need + joint_turn * ATTACK_COST_TURN_WEIGHT + 1.0),\n                            target,\n                            "swarm",\n                            world,\n                        )\n                        trio_score *= THREE_SOURCE_PLAN_PENALTY\n                        missions.append(Mission(\n                            kind="swarm",\n                            score=trio_score,\n                            target_id=target_id,\n                            turns=joint_turn,\n                            options=trio,\n                        ))\n\n    if allow_heavy_phase():\n        missions.extend(build_crash_exploit_missions(world, policy, planned_commitments, modes))\n\n    missions.sort(key=lambda item: -item.score)\n\n    # === MISSION EXECUTION PHASE ===\n\n    for mission in missions:\n        if expired():\n            return finalize_moves()\n        target = world.planet_by_id[mission.target_id]\n\n        if mission.kind in ("single", "snipe", "rescue", "recapture", "reinforce", "crash_exploit"):\n            option = mission.options[0]\n            src = world.planet_by_id[option.src_id]\n            if mission.kind == "reinforce":\n                left = min(\n                    source_inventory_left(option.src_id),\n                    int(src.ships * REINFORCE_MAX_SOURCE_FRACTION),\n                )\n            else:\n                left = source_attack_left(option.src_id)\n            if left <= 0:\n                continue\n\n            if mission.kind == "reinforce":\n                plan = settle_reinforce_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    option.anchor_turn,\n                    mission.turns,\n                )\n            elif mission.kind == "rescue":\n                plan = settle_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="rescue",\n                    eval_turn_fn=lambda _turns, hold_turn=mission.turns: hold_turn,\n                    anchor_turn=option.anchor_turn,\n                )\n            elif mission.kind == "snipe":\n                plan = settle_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="snipe",\n                    eval_turn_fn=lambda turns, enemy_eta=option.anchor_turn: max(turns, enemy_eta),\n                    anchor_turn=option.anchor_turn,\n                )\n            elif mission.kind == "crash_exploit":\n                plan = settle_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="crash_exploit",\n                    eval_turn_fn=lambda turns, desired_arrival=option.anchor_turn: max(turns, desired_arrival),\n                    anchor_turn=option.anchor_turn,\n                    anchor_tolerance=CRASH_EXPLOIT_ETA_WINDOW,\n                )\n            else:\n                plan = settle_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="capture",\n                )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send = plan\n            if send < need or need > left:\n                continue\n\n            sent = append_move(option.src_id, angle, send)\n            if sent < need:\n                continue\n            planned_commitments[target.id].append((turns, world.player, int(sent)))\n            continue\n\n        limits = []\n        for option in mission.options:\n            left = source_attack_left(option.src_id)\n            limits.append(min(left, option.send_cap))\n        if min(limits) <= 0:\n            continue\n\n        missing = world.min_ships_to_own_at(\n            target.id,\n            mission.turns,\n            world.player,\n            planned_commitments=planned_commitments,\n            upper_bound=sum(limits),\n        )\n        if missing <= 0 or sum(limits) < missing:\n            continue\n\n        ordered = sorted(\n            zip(mission.options, limits),\n            key=lambda item: (item[0].turns, -item[1], item[0].src_id),\n        )\n        remaining = missing\n        sends = {}\n        for idx, (option, limit) in enumerate(ordered):\n            remaining_other = sum(other_limit for _, other_limit in ordered[idx + 1:])\n            send = min(limit, max(0, remaining - remaining_other))\n            sends[option.src_id] = send\n            remaining -= send\n        if remaining > 0:\n            continue\n\n        reaimed = []\n        for option, _ in ordered:\n            send = sends.get(option.src_id, 0)\n            if send <= 0:\n                continue\n            src = world.planet_by_id[option.src_id]\n            fixed_aim = world.plan_shot(src.id, target.id, send)\n            if fixed_aim is None:\n                reaimed = []\n                break\n            angle, turns, _, _ = fixed_aim\n            reaimed.append((option.src_id, angle, turns, send))\n        if not reaimed:\n            continue\n\n        turns_only = [item[2] for item in reaimed]\n        eta_tol = swarm_eta_tolerance(mission.options, target, world)\n        if max(turns_only) - min(turns_only) > eta_tol:\n            continue\n\n        actual_joint_turn = max(turns_only)\n        owner_after, _ = world.projected_state(\n            target.id,\n            actual_joint_turn,\n            planned_commitments=planned_commitments,\n            extra_arrivals=[(turns, world.player, send) for _, _, turns, send in reaimed],\n        )\n        if owner_after != world.player:\n            continue\n\n        committed = []\n        for src_id, angle, turns, send in reaimed:\n            actual = append_move(src_id, angle, send)\n            if actual <= 0:\n                continue\n            committed.append((turns, world.player, int(actual)))\n        if sum(item[2] for item in committed) < missing:\n            continue\n        planned_commitments[target.id].extend(committed)\n\n    # === FOLLOWUP PHASE ===\n\n    if not world.is_very_late and allow_optional_phase():\n        for src in world.my_planets:\n            if expired():\n                return finalize_moves()\n            src_left = source_attack_left(src.id)\n            if src_left < FOLLOWUP_MIN_SHIPS:\n                continue\n\n            best = None\n            for target in world.planets:\n                if expired():\n                    return finalize_moves()\n                if target.id == src.id or target.owner == world.player:\n                    continue\n                if target.id in world.comet_ids and target.production <= LOW_VALUE_COMET_PRODUCTION:\n                    continue\n\n                seeded = world.best_probe_aim(\n                    src.id,\n                    target.id,\n                    src_left,\n                    hints=(int(target.ships) + 1,),\n                )\n                if seeded is None:\n                    continue\n                rough_ships, rough_aim = seeded\n\n                est_turns = rough_aim[1]\n                if world.is_late and est_turns > world.remaining_steps - LATE_CAPTURE_BUFFER:\n                    continue\n\n                rough_needed = world.min_ships_to_own_at(\n                    target.id,\n                    est_turns,\n                    world.player,\n                    planned_commitments=planned_commitments,\n                    upper_bound=src_left,\n                )\n                if rough_needed <= 0 or rough_needed > src_left:\n                    continue\n                if opening_filter(target, est_turns, rough_needed, src_left, world, policy, src=src):\n                    continue\n\n                send = preferred_send(target, rough_needed, est_turns, src_left, world, modes, policy)\n                if send < rough_needed:\n                    continue\n\n                plan = settle_plan(\n                    src,\n                    target,\n                    src_left,\n                    send,\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="capture",\n                )\n                if plan is None:\n                    continue\n\n                _, turns, _, need, final_send = plan\n                if world.is_late and turns > world.remaining_steps - LATE_CAPTURE_BUFFER:\n                    continue\n                if final_send < need:\n                    continue\n\n                value = target_value(target, turns, "capture", world, modes, policy)\n                if value <= 0:\n                    continue\n\n                score = apply_score_modifiers(\n                    value / (final_send + turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                    target,\n                    "capture",\n                    world,\n                )\n                if best is None or score > best[0]:\n                    best = (score, target, plan)\n\n            if best is None:\n                continue\n\n            _, target, plan = best\n            angle, turns, _, need, send = plan\n            src_left = source_attack_left(src.id)\n            if need > src_left:\n                continue\n\n            plan = settle_plan(\n                src,\n                target,\n                src_left,\n                min(src_left, send),\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="capture",\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send = plan\n            if send < need:\n                continue\n\n            actual = append_move(src.id, angle, send)\n            if actual < need:\n                continue\n            planned_commitments[target.id].append((turns, world.player, int(actual)))\n\n    # === DOOMED PLANET EVACUATION ===\n\n    if expired():\n        return finalize_moves()\n    live_doomed = compute_live_doomed()\n    if live_doomed:\n        frontier_targets = (\n            world.enemy_planets\n            if world.enemy_planets\n            else (world.static_neutral_planets or world.neutral_planets)\n        )\n        if frontier_targets:\n            frontier_distance = {\n                planet.id: nearest_distance_to_set(planet.x, planet.y, frontier_targets)\n                for planet in world.my_planets\n            }\n        else:\n            frontier_distance = {planet.id: 10**9 for planet in world.my_planets}\n\n        for planet in world.my_planets:\n            if expired():\n                return finalize_moves()\n            if planet.id not in live_doomed:\n                continue\n\n            available_now = source_inventory_left(planet.id)\n            if available_now < policy["reserve"].get(planet.id, 0):\n                continue\n\n            best_capture = None\n            for target in world.planets:\n                if expired():\n                    return finalize_moves()\n                if target.id == planet.id or target.owner == world.player:\n                    continue\n                seeded = world.best_probe_aim(\n                    planet.id,\n                    target.id,\n                    available_now,\n                    hints=(available_now, int(target.ships) + 1),\n                )\n                if seeded is None:\n                    continue\n                _, probe_aim = seeded\n                probe_turns = probe_aim[1]\n                if probe_turns > world.remaining_steps - 2:\n                    continue\n\n                need = world.min_ships_to_own_at(\n                    target.id,\n                    probe_turns,\n                    world.player,\n                    planned_commitments=planned_commitments,\n                    upper_bound=available_now,\n                )\n                if need <= 0 or need > available_now:\n                    continue\n\n                plan = settle_plan(\n                    planet,\n                    target,\n                    available_now,\n                    min(available_now, max(need, int(target.ships) + 1)),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="capture",\n                )\n                if plan is None:\n                    continue\n                angle, turns, _, plan_need, send = plan\n                if send < plan_need:\n                    continue\n                score = target_value(target, turns, "capture", world, modes, policy) / (send + turns + 1.0)\n                if target.owner not in (-1, world.player):\n                    score *= 1.05\n                if best_capture is None or score > best_capture[0]:\n                    best_capture = (score, target.id, angle, turns, send)\n\n            if best_capture is not None:\n                _, target_id, angle, turns, need = best_capture\n                actual = append_move(planet.id, angle, need)\n                if actual >= 1:\n                    planned_commitments[target_id].append((turns, world.player, int(actual)))\n                continue\n\n            safe_allies = [\n                ally\n                for ally in world.my_planets\n                if ally.id != planet.id and ally.id not in live_doomed\n            ]\n            if not safe_allies:\n                continue\n\n            retreat_target = min(\n                safe_allies,\n                key=lambda ally: (\n                    frontier_distance.get(ally.id, 10**9),\n                    planet_distance(planet, ally),\n                ),\n            )\n            aim = world.plan_shot(planet.id, retreat_target.id, available_now)\n            if aim is None:\n                continue\n            angle, _, _, _ = aim\n            append_move(planet.id, angle, available_now)\n\n    # === REAR FORWARDING ===\n\n    if (\n        (world.enemy_planets or world.neutral_planets)\n        and len(world.my_planets) > 1\n        and not world.is_late\n        and allow_optional_phase()\n    ):\n        live_doomed = compute_live_doomed()\n        frontier_targets = (\n            world.enemy_planets\n            if world.enemy_planets\n            else (world.static_neutral_planets or world.neutral_planets)\n        )\n        frontier_distance = {\n            planet.id: nearest_distance_to_set(planet.x, planet.y, frontier_targets)\n            for planet in world.my_planets\n        }\n        safe_fronts = [planet for planet in world.my_planets if planet.id not in live_doomed]\n        if safe_fronts:\n            front_anchor = min(safe_fronts, key=lambda planet: frontier_distance[planet.id])\n            send_ratio = REAR_SEND_RATIO_FOUR_PLAYER if world.is_four_player else REAR_SEND_RATIO_TWO_PLAYER\n            if modes["is_finishing"]:\n                send_ratio = max(send_ratio, REAR_SEND_RATIO_FOUR_PLAYER)\n            rear_source_min = 12 if world.is_four_player else REAR_SOURCE_MIN_SHIPS\n            rear_send_min = 7 if world.is_four_player else REAR_SEND_MIN_SHIPS\n            rear_distance_ratio = 1.12 if world.is_four_player else REAR_DISTANCE_RATIO\n            rear_stage_progress = 0.86 if world.is_four_player else REAR_STAGE_PROGRESS\n            rear_max_turns = 48 if world.is_four_player else REAR_MAX_TRAVEL_TURNS\n\n            for rear in sorted(world.my_planets, key=lambda planet: -frontier_distance[planet.id]):\n                if expired():\n                    return finalize_moves()\n                if rear.id == front_anchor.id or rear.id in live_doomed:\n                    continue\n                if source_attack_left(rear.id) < rear_source_min:\n                    continue\n                if frontier_distance[rear.id] < frontier_distance[front_anchor.id] * rear_distance_ratio:\n                    continue\n\n                stage_candidates = [\n                    planet\n                    for planet in safe_fronts\n                    if planet.id != rear.id\n                    and frontier_distance[planet.id] < frontier_distance[rear.id] * rear_stage_progress\n                ]\n                if stage_candidates:\n                    front = min(stage_candidates, key=lambda planet: planet_distance(rear, planet))\n                else:\n                    objective = min(frontier_targets, key=lambda target: planet_distance(rear, target))\n                    remaining_fronts = [planet for planet in safe_fronts if planet.id != rear.id]\n                    if not remaining_fronts:\n                        continue\n                    front = min(remaining_fronts, key=lambda planet: planet_distance(planet, objective))\n\n                if front.id == rear.id:\n                    continue\n\n                send = int(source_attack_left(rear.id) * send_ratio)\n                if send < rear_send_min:\n                    continue\n\n                aim = world.plan_shot(rear.id, front.id, send)\n                if aim is None:\n                    continue\n\n                angle, turns, _, _ = aim\n                if turns > rear_max_turns:\n                    continue\n                append_move(rear.id, angle, send)\n\n    # === TOTAL WAR ENDGAME ===\n\n    if world.is_total_war and world.enemy_planets and allow_optional_phase():\n        # Prioritize weakest enemy in total war\n        if world._weakest_enemy is not None:\n            weakest_planets = [p for p in world.enemy_planets if p.owner == world._weakest_enemy]\n            if weakest_planets:\n                primary_targets = weakest_planets\n            else:\n                primary_targets = world.enemy_planets\n        else:\n            primary_targets = world.enemy_planets\n\n        # Attack weakest enemy first, then others\n        for target_set in [primary_targets, world.enemy_planets]:\n            if not target_set:\n                continue\n            for src in world.my_planets:\n                if expired():\n                    return finalize_moves()\n                atk_left = source_attack_left(src.id)\n                if atk_left < 5:\n                    continue\n\n                # Find best target from current set\n                best_target = None\n                best_dist = float(\'inf\')\n                for ep in target_set:\n                    d = planet_distance(src, ep)\n                    if d < best_dist:\n                        aim_test = world.plan_shot(src.id, ep.id, atk_left)\n                        if aim_test is not None:\n                            best_dist = d\n                            best_target = ep\n\n                if best_target is None:\n                    continue\n                aim = world.plan_shot(src.id, best_target.id, atk_left)\n                if aim is None:\n                    continue\n                angle, turns, _, _ = aim\n                if turns >= world.remaining_steps:\n                    continue\n                append_move(src.id, angle, atk_left)\n            break  # Only run primary targets set; secondary is backup\n\n    return finalize_moves()\n\n# ============================================================\n# Agent Entry Point\n# ============================================================\n\n_TURN_BY_GAME_PLAYER = {}\n\n\ndef _read(obs, key, default=None):\n    if isinstance(obs, dict):\n        return obs.get(key, default)\n    return getattr(obs, key, default)\n\n\ndef _safe_int(value, default=0):\n    try:\n        return int(value)\n    except (TypeError, ValueError):\n        return default\n\n\ndef _turn_state_key(obs, player, angular_velocity):\n    initial_rows = _read(obs, "initial_planets", []) or []\n    if not initial_rows:\n        return (player, round(float(angular_velocity or 0.0), 8), "fallback")\n\n    signature = []\n    for row in initial_rows:\n        try:\n            signature.append(\n                (\n                    int(row[0]),\n                    int(row[1]),\n                    round(float(row[2]), 3),\n                    round(float(row[3]), 3),\n                    round(float(row[4]), 3),\n                    int(row[6]),\n                )\n            )\n        except (TypeError, ValueError, IndexError):\n            continue\n\n    if not signature:\n        return (player, round(float(angular_velocity or 0.0), 8), "fallback")\n    return (player, round(float(angular_velocity or 0.0), 8), tuple(signature))\n\n\ndef _remember_step(obs, player, angular_velocity, step):\n    _TURN_BY_GAME_PLAYER[_turn_state_key(obs, player, angular_velocity)] = max(0, min(TOTAL_STEPS, int(step)))\n\n\ndef _infer_step_from_orbits(obs, planets, angular_velocity, comet_ids):\n    if abs(angular_velocity) < 1e-9:\n        return None\n\n    initial_rows = _read(obs, "initial_planets", []) or []\n    if not initial_rows:\n        return None\n\n    current_by_id = {planet.id: planet for planet in planets}\n    inferred_steps = []\n    for row in initial_rows:\n        try:\n            initial = Planet(*row)\n        except (TypeError, ValueError):\n            continue\n        if initial.id in comet_ids:\n            continue\n\n        current = current_by_id.get(initial.id)\n        if current is None:\n            continue\n        if orbital_radius(initial) + initial.radius >= ROTATION_LIMIT:\n            continue\n        if orbital_radius(current) + current.radius >= ROTATION_LIMIT + 1.0:\n            continue\n\n        start_angle = math.atan2(initial.y - CENTER_Y, initial.x - CENTER_X)\n        current_angle = math.atan2(current.y - CENTER_Y, current.x - CENTER_X)\n        if angular_velocity > 0:\n            delta = (current_angle - start_angle) % (2.0 * math.pi)\n        else:\n            delta = (start_angle - current_angle) % (2.0 * math.pi)\n        inferred_steps.append(delta / abs(angular_velocity))\n\n    if not inferred_steps:\n        return None\n    inferred_steps.sort()\n    return inferred_steps[len(inferred_steps) // 2]\n\n\ndef _current_step(obs, planets, fleets, player, angular_velocity, comet_ids):\n    raw_step = _read(obs, "step", None)\n    if raw_step is not None:\n        step = _safe_int(raw_step, 0)\n        _remember_step(obs, player, angular_velocity, step)\n        return step\n\n    inferred = _infer_step_from_orbits(obs, planets, angular_velocity, comet_ids)\n    key = _turn_state_key(obs, player, angular_velocity)\n    prior = _TURN_BY_GAME_PLAYER.get(key)\n\n    if prior is not None and inferred is not None and inferred <= 1.5 and prior > 20 and not fleets:\n        prior = None\n\n    if prior is None:\n        step = max(0, int(round(inferred or 0)))\n    elif inferred is None or abs(angular_velocity) < 1e-9:\n        step = prior + 1\n    else:\n        expected = prior + 1\n        period = (2.0 * math.pi) / abs(angular_velocity)\n        wraps = int(TOTAL_STEPS / period) + 3\n        candidates = [inferred + period * wrap for wrap in range(wraps)]\n        step = int(round(min(candidates, key=lambda candidate: abs(candidate - expected))))\n        if abs(step - expected) > 4:\n            step = expected\n\n    step = max(0, min(TOTAL_STEPS, step))\n    _TURN_BY_GAME_PLAYER[key] = step\n    return step\n\n\ndef build_world(obs, inferred_step=None):\n    player = _read(obs, "player", 0)\n    raw_planets = _read(obs, "planets", []) or []\n    raw_fleets = _read(obs, "fleets", []) or []\n    ang_vel = _read(obs, "angular_velocity", 0.0) or 0.0\n    raw_init = _read(obs, "initial_planets", []) or []\n    comets = _read(obs, "comets", []) or []\n    comet_ids = set(_read(obs, "comet_planet_ids", []) or [])\n\n    planets = [Planet(*planet) for planet in raw_planets]\n    fleets = [Fleet(*fleet) for fleet in raw_fleets]\n    initial_planets = [Planet(*planet) for planet in raw_init]\n    initial_by_id = {planet.id: planet for planet in initial_planets}\n    step = _current_step(obs, planets, fleets, player, ang_vel, comet_ids)\n    if inferred_step is not None:\n        step = max(step, int(inferred_step))\n\n    return WorldModel(\n        player=player,\n        step=step,\n        planets=planets,\n        fleets=fleets,\n        initial_by_id=initial_by_id,\n        ang_vel=ang_vel,\n        comets=comets,\n        comet_ids=comet_ids,\n    )\n\n\ndef agent(obs, config=None):\n    start_time = time.perf_counter()\n    world = build_world(obs)\n    if not world.my_planets:\n        return []\n    act_timeout = _read(config, "actTimeout", 1.0) if config is not None else 1.0\n    soft_budget = min(SOFT_ACT_DEADLINE, max(0.55, act_timeout * 0.82))\n    deadline = start_time + soft_budget\n    return plan_moves(world, deadline=deadline)\n\n\n__all__ = ["agent", "build_world"]\n'

_V4P_SOURCE = '# orf527 / Orbit Wars — v5 base\n#\n# Derivative work based on the public Kaggle notebook\n#   "Orbit (Star) Wars | LB: MAX 1224"\n#   by Roman Tamrazov (kernel: romantamrazov/orbit-star-wars-lb-max-1224, version 6).\n# Notebook is publicly listed on Kaggle (isPrivate=false). Apache 2.0 / MIT\n# license is claimed in the third-party `automatylicza/orbit-wars-lab` distribution.\n# Original author retains credit; modifications by orf527 are documented inline\n# below the constants block.\n\nimport math\nimport time\nfrom collections import defaultdict, namedtuple\nfrom dataclasses import dataclass, field\n\n# ============================================================\n# Shared Configuration\n# ============================================================\n\nBOARD = 100.0\nBOARD_SIZE = BOARD\nCENTER_X = 50.0\nCENTER_Y = 50.0\nSUN_R = 10.0\nMAX_SPEED = 6.0\nSUN_SAFETY = 1.5\nROTATION_LIMIT = 50.0\nTOTAL_STEPS = 500\nSIM_HORIZON = 110\nROUTE_SEARCH_HORIZON = 60\nHORIZON = SIM_HORIZON\nARRIVAL_LEDGER_DYNAMIC_HORIZON = 72\nLAUNCH_CLEARANCE = 0.1\n\nEARLY_TURN_LIMIT = 40\nOPENING_TURN_LIMIT = 80\nLATE_REMAINING_TURNS = 70          # was 60 — enter late-game earlier\nVERY_LATE_REMAINING_TURNS = 25\nTOTAL_WAR_REMAINING_TURNS = 55     # was 38 — endgame push starts sooner\n\nSAFE_NEUTRAL_MARGIN = 2\nCONTESTED_NEUTRAL_MARGIN = 2\nINTERCEPT_TOLERANCE = 1\n\nSAFE_OPENING_PROD_THRESHOLD = 4\nSAFE_OPENING_TURN_LIMIT = 10\nROTATING_OPENING_MAX_TURNS = 13\nROTATING_OPENING_LOW_PROD = 2\nFOUR_PLAYER_ROTATING_REACTION_GAP = 3\nFOUR_PLAYER_ROTATING_SEND_RATIO = 0.55  # was 0.62 — less overcommit in 4P\nFOUR_PLAYER_ROTATING_TURN_LIMIT = 10\nHIGH_PROD_SOURCE_SAVE_TURN_LIMIT = 58\nHIGH_PROD_SOURCE_MIN_PROD = 3\nHIGH_PROD_SAVE_TARGET_MIN_PROD = 4\nHIGH_PROD_SAVE_LOW_TARGET_MAX_PROD = 1\nHIGH_PROD_SAVE_LOOKAHEAD_TURNS = 10\nHIGH_PROD_SAVE_MAX_ROUTE_TURNS = 44\nOPENING_HIGH_PROD_PACKET_TURN = 45\nOPENING_HIGH_PROD_MIN_PROD = 4\nOPENING_HIGH_PROD_LOW_TARGET_MAX_PROD = 3\nOPENING_HIGH_PROD_FUTURE_TURNS = 16\nOPENING_HIGH_PROD_MAX_ROUTE_TURNS = 44\nOPENING_HIGH_PROD_MIN_PACKET = 22\nOPENING_HIGH_PROD_PACKET_PROD_WEIGHT = 2\n\nCOMET_MAX_CHASE_TURNS = 10\n\nATTACK_COST_TURN_WEIGHT = 0.50\nSNIPE_COST_TURN_WEIGHT = 0.42\nINDIRECT_VALUE_SCALE = 0.15\nINDIRECT_FRIENDLY_WEIGHT = 0.35\nINDIRECT_NEUTRAL_WEIGHT = 0.9\nINDIRECT_ENEMY_WEIGHT = 1.25\n\nSTATIC_NEUTRAL_VALUE_MULT = 1.4\nSTATIC_HOSTILE_VALUE_MULT = 1.65\nROTATING_OPENING_VALUE_MULT = 0.9\nHOSTILE_TARGET_VALUE_MULT = 2.05   # was 1.95\nOPENING_HOSTILE_TARGET_VALUE_MULT = 1.55\nSAFE_NEUTRAL_VALUE_MULT = 1.2\nCONTESTED_NEUTRAL_VALUE_MULT = 0.7\nEARLY_NEUTRAL_VALUE_MULT = 1.2\nCOMET_VALUE_MULT = 0.65\nSNIPE_VALUE_MULT = 1.12\nSWARM_VALUE_MULT = 1.05\nREINFORCE_VALUE_MULT = 1.35\nCRASH_EXPLOIT_VALUE_MULT = 1.18\nFINISHING_HOSTILE_VALUE_MULT = 1.3  # was 1.2\nBEHIND_ROTATING_NEUTRAL_VALUE_MULT = 0.92\nEXPOSED_PLANET_VALUE_MULT = 2.0    # was 1.75\n\n# NEW: weakest enemy targeting multipliers\nWEAKEST_ENEMY_VALUE_MULT_4P = 1.5   # bonus for targeting weakest in 4P\nWEAKEST_ENEMY_VALUE_MULT_2P = 1.25  # bonus for targeting weakest in 1v1\nFOUR_PLAYER_HIGH_PROD_NEUTRAL_VALUE_MULT = 1.18\nFOUR_PLAYER_LOW_PROD_OPENING_VALUE_MULT = 0.66\nFOUR_PLAYER_LOW_PROD_HOSTILE_VALUE_MULT = 0.88\nFOUR_PLAYER_LEADER_TARGET_VALUE_MULT = 1.32\nFOUR_PLAYER_LEADER_SCORE_MULT = 1.18\nFOUR_PLAYER_LEADER_PRESSURE_MIN_GAP = 4\nFOUR_PLAYER_LEADER_PRESSURE_RATIO = 1.10\nFOUR_PLAYER_ROUTE_VALIDATE_TURN_LIMIT = 130\nGANG_UP_VALUE_MULT = 1.4            # bonus for gang-up attacks on weakened planets\nGANG_UP_POST_BATTLE_DELAY = 2       # turns after battle to arrive\nGANG_UP_ETA_WINDOW = 4              # tolerance window for gang-up timing\n\nNEUTRAL_MARGIN_BASE = 2\nNEUTRAL_MARGIN_PROD_WEIGHT = 2\nNEUTRAL_MARGIN_CAP = 8\nHOSTILE_MARGIN_BASE = 3\nHOSTILE_MARGIN_PROD_WEIGHT = 2\nHOSTILE_MARGIN_CAP = 12\nSTATIC_TARGET_MARGIN = 4\nCONTESTED_TARGET_MARGIN = 5\nFOUR_PLAYER_TARGET_MARGIN = 2       # was 3 — more efficient in 4P\nLONG_TRAVEL_MARGIN_START = 18\nLONG_TRAVEL_MARGIN_DIVISOR = 3\nLONG_TRAVEL_MARGIN_CAP = 8\nCOMET_MARGIN_RELIEF = 6\nFINISHING_HOSTILE_SEND_BONUS = 3\n\nSTATIC_TARGET_SCORE_MULT = 1.18\nEARLY_STATIC_NEUTRAL_SCORE_MULT = 1.25\nFOUR_PLAYER_ROTATING_NEUTRAL_SCORE_MULT = 0.84\nDENSE_STATIC_NEUTRAL_COUNT = 4\nDENSE_ROTATING_NEUTRAL_SCORE_MULT = 0.86\nSNIPE_SCORE_MULT = 1.12\nSWARM_SCORE_MULT = 1.06\nCRASH_EXPLOIT_SCORE_MULT = 1.05\n\nFOLLOWUP_MIN_SHIPS = 8\nLOW_VALUE_COMET_PRODUCTION = 1\nLATE_CAPTURE_BUFFER = 5\nVERY_LATE_CAPTURE_BUFFER = 3\n\nDEFENSE_LOOKAHEAD_TURNS = 28\nDEFENSE_COST_TURN_WEIGHT = 0.4\nDEFENSE_FRONTIER_SCORE_MULT = 1.12\nDEFENSE_SEND_MARGIN_BASE = 1\nDEFENSE_SEND_MARGIN_PROD_WEIGHT = 1\nDEFENSE_SHIP_VALUE = 0.55\n\nREINFORCE_ENABLED = True\nREINFORCE_MIN_PRODUCTION = 2\nREINFORCE_MAX_TRAVEL_TURNS = 22\nREINFORCE_SAFETY_MARGIN = 2\nREINFORCE_MAX_SOURCE_FRACTION = 0.75\nREINFORCE_MIN_FUTURE_TURNS = 40\nREINFORCE_HOLD_LOOKAHEAD = 20\nREINFORCE_COST_TURN_WEIGHT = 0.35\n\nRECAPTURE_LOOKAHEAD_TURNS = 10\nRECAPTURE_COST_TURN_WEIGHT = 0.52\nRECAPTURE_VALUE_MULT = 0.88\nRECAPTURE_FRONTIER_MULT = 1.08\nRECAPTURE_PRODUCTION_WEIGHT = 0.6\nRECAPTURE_IMMEDIATE_WEIGHT = 0.4\n\nREAR_SOURCE_MIN_SHIPS = 16\nREAR_DISTANCE_RATIO = 1.25\nREAR_STAGE_PROGRESS = 0.78\nREAR_SEND_RATIO_TWO_PLAYER = 0.62\nREAR_SEND_RATIO_FOUR_PLAYER = 0.68\nREAR_SEND_MIN_SHIPS = 10\nREAR_MAX_TRAVEL_TURNS = 40\n\nPRESSURE_PACKET_ENABLED = True\nPRESSURE_PACKET_TURN = 52\nPRESSURE_PACKET_STOP_REMAINING = 90\nPRESSURE_PACKET_MIN_LEFT = 42\nPRESSURE_PACKET_MIN_SEND = 34\nPRESSURE_PACKET_MAX_SEND = 260\nPRESSURE_PACKET_BASE_RATIO = 0.72\nPRESSURE_PACKET_BEHIND_RATIO = 0.86\nPRESSURE_PACKET_MAX_TURNS = 42\nPRESSURE_PACKET_HIGH_PROD_BONUS = 12\nPRESSURE_PACKET_LEADER_MULT = 1.24\nPRESSURE_PACKET_FRONTIER_MULT = 1.12\nPRESSURE_PACKET_OVERKILL_CAP = 3.2\nPRESSURE_PACKET_MAX_PER_TURN = 3\nPRESSURE_PACKET_MIN_MY_PROD = 20\n\nFOUR_PLAYER_PACKET_AGGREGATION_TURN = 45\nFOUR_PLAYER_PACKET_NEUTRAL_FLOOR = 26\nFOUR_PLAYER_PACKET_HIGH_PROD_NEUTRAL_FLOOR = 22\nFOUR_PLAYER_PACKET_ENEMY_FLOOR = 36\nFOUR_PLAYER_PACKET_LEADER_BONUS = 8\nFOUR_PLAYER_PACKET_HIGH_PROD_BONUS = 6\nFOUR_PLAYER_PACKET_JOINT_FLOOR = 34\n\nPARTIAL_SOURCE_MIN_SHIPS = 6\nMULTI_SOURCE_TOP_K = 5\nMULTI_SOURCE_ETA_TOLERANCE = 2\nMULTI_SOURCE_PLAN_PENALTY = 0.97\nCOORDINATED_WAVE_ENABLED = True\nCOORDINATED_WAVE_TOP_K = 7\nCOORDINATED_WAVE_MAX_SOURCES = 5\nCOORDINATED_WAVE_ETA_TOLERANCE = 3\nCOORDINATED_WAVE_PLAN_PENALTY = 0.90\nCOORDINATED_WAVE_MIN_PROD_GAP = 5\nHOSTILE_SWARM_ETA_TOLERANCE = 1\nTHREE_SOURCE_SWARM_ENABLED = True\nTHREE_SOURCE_MIN_TARGET_SHIPS = 20\nTHREE_SOURCE_ETA_TOLERANCE = 1\nTHREE_SOURCE_PLAN_PENALTY = 0.93\n\nPROACTIVE_DEFENSE_HORIZON = 12\nPROACTIVE_DEFENSE_RATIO = 0.28      # was 0.20 — more defensive\nMULTI_ENEMY_PROACTIVE_HORIZON = 14\nMULTI_ENEMY_PROACTIVE_RATIO = 0.35  # was 0.24 — much more defensive in 4P\nMULTI_ENEMY_STACK_WINDOW = 4        # was 3 — wider detection window\nFOUR_PLAYER_PROACTIVE_RESERVE_CAP = 0.48\nFOUR_PLAYER_BEHIND_RESERVE_CAP = 0.36\nREACTION_SOURCE_TOP_K_MY = 4\nREACTION_SOURCE_TOP_K_ENEMY = 4\nPROACTIVE_ENEMY_TOP_K = 3\n\nTWO_PLAYER_STRATEGY = {\n    "name": "duel_economy_race",\n    "partial_source_min": 5,\n    "followup_min": FOLLOWUP_MIN_SHIPS,\n    "opening_high_prod_turn": 45,\n    "opening_high_prod_min_prod": 4,\n    "opening_high_prod_low_target_max_prod": 3,\n    "opening_high_prod_future_turns": 16,\n    "opening_high_prod_max_route_turns": 44,\n    "opening_high_prod_min_packet": 22,\n    "opening_high_prod_packet_prod_weight": 2,\n    "opening_high_prod_reaction_slack": 6,\n    "pressure_packet_min_my_prod": 24,\n    "pressure_packet_base_ratio": 0.60,\n    "pressure_packet_behind_ratio": 0.78,\n    "pressure_packet_min_send": PRESSURE_PACKET_MIN_SEND,\n    "pressure_packet_max_per_turn": PRESSURE_PACKET_MAX_PER_TURN,\n    "rear_send_ratio": REAR_SEND_RATIO_TWO_PLAYER,\n    "rear_source_min": REAR_SOURCE_MIN_SHIPS,\n    "rear_send_min": REAR_SEND_MIN_SHIPS,\n    "rear_distance_ratio": REAR_DISTANCE_RATIO,\n    "rear_stage_progress": REAR_STAGE_PROGRESS,\n    "rear_max_turns": REAR_MAX_TRAVEL_TURNS,\n}\n\nFOUR_PLAYER_STRATEGY = {\n    "name": "four_player_leader_pressure",\n    "partial_source_min": 8,\n    "followup_min": 8,\n    "opening_high_prod_turn": 52,\n    "opening_high_prod_min_prod": 4,\n    "opening_high_prod_low_target_max_prod": 2,\n    "opening_high_prod_future_turns": 12,\n    "opening_high_prod_max_route_turns": 34,\n    "opening_high_prod_min_packet": 15,\n    "opening_high_prod_packet_prod_weight": 1,\n    "opening_high_prod_reaction_slack": 4,\n    "pressure_packet_min_my_prod": PRESSURE_PACKET_MIN_MY_PROD,\n    "pressure_packet_base_ratio": PRESSURE_PACKET_BASE_RATIO,\n    "pressure_packet_behind_ratio": PRESSURE_PACKET_BEHIND_RATIO,\n    "pressure_packet_min_send": PRESSURE_PACKET_MIN_SEND,\n    "pressure_packet_max_per_turn": PRESSURE_PACKET_MAX_PER_TURN,\n    "rear_send_ratio": REAR_SEND_RATIO_FOUR_PLAYER,\n    "rear_source_min": 12,\n    "rear_send_min": 12,\n    "rear_distance_ratio": 1.12,\n    "rear_stage_progress": 0.86,\n    "rear_max_turns": 48,\n}\n\nCRASH_EXPLOIT_ENABLED = True\nCRASH_EXPLOIT_MIN_TOTAL_SHIPS = 7   # was 10 — exploit smaller crashes too\nCRASH_EXPLOIT_ETA_WINDOW = 3        # was 2 — wider window\nCRASH_EXPLOIT_POST_CRASH_DELAY = 1\n\nLATE_IMMEDIATE_SHIP_VALUE = 0.75\nWEAK_ENEMY_THRESHOLD = 110          # was 60 — detect weak enemies earlier\nELIMINATION_BONUS = 55.0            # was 28.0 — much stronger elimination drive\n\nBEHIND_DOMINATION = -0.20\nAHEAD_DOMINATION = 0.15\nFINISHING_DOMINATION = 0.28\nFINISHING_PROD_RATIO = 1.15\nAHEAD_ATTACK_MARGIN_BONUS = 0.12\nBEHIND_ATTACK_MARGIN_PENALTY = 0.05\nFINISHING_ATTACK_MARGIN_BONUS = 0.12\n\nDOOMED_EVAC_TURN_LIMIT = 24\nDOOMED_MIN_SHIPS = 8\n\nSOFT_ACT_DEADLINE = 0.82\nHEAVY_PHASE_MIN_TIME = 0.16\nOPTIONAL_PHASE_MIN_TIME = 0.08\nHEAVY_ROUTE_PLANET_LIMIT = 32\n\nENDGAME_REFINER_ENABLED = True\nENDGAME_REFINER_REMAINING_TURNS = 35\nENDGAME_REFINER_MAX_NON_COMET_PLANETS = 12\nENDGAME_REFINER_MAX_MOVES = 10\nENDGAME_REFINER_PROD_VALUE = 1.0\nENDGAME_REFINER_ENEMY_PROD_VALUE = 0.85\nENDGAME_REFINER_SHIP_VALUE = 0.25\nENDGAME_REFINER_FLEET_VALUE = 0.10\n\n# ============================================================\n# Shared Types\n# ============================================================\n\nPlanet = namedtuple(\n    "Planet", ["id", "owner", "x", "y", "radius", "ships", "production"]\n)\nFleet = namedtuple(\n    "Fleet", ["id", "owner", "x", "y", "angle", "from_planet_id", "ships"]\n)\n\n\n@dataclass(frozen=True)\nclass ShotOption:\n    score: float\n    src_id: int\n    target_id: int\n    angle: float\n    turns: int\n    needed: int\n    send_cap: int\n    mission: str = "capture"\n    anchor_turn: int | None = None\n\n\n@dataclass\nclass Mission:\n    kind: str\n    score: float\n    target_id: int\n    turns: int\n    options: list[ShotOption] = field(default_factory=list)\n\n# ============================================================\n# Physics\n# ============================================================\n\ndef dist(ax, ay, bx, by):\n    return math.hypot(ax - bx, ay - by)\n\n\ndef orbital_radius(planet):\n    return dist(planet.x, planet.y, CENTER_X, CENTER_Y)\n\n\ndef is_static_planet(planet):\n    return orbital_radius(planet) + planet.radius >= ROTATION_LIMIT\n\n\ndef fleet_speed(ships):\n    if ships <= 1:\n        return 1.0\n    ratio = math.log(ships) / math.log(1000.0)\n    ratio = max(0.0, min(1.0, ratio))\n    return 1.0 + (MAX_SPEED - 1.0) * (ratio**1.5)\n\n\ndef point_to_segment_distance(px, py, x1, y1, x2, y2):\n    dx = x2 - x1\n    dy = y2 - y1\n    seg_len_sq = dx * dx + dy * dy\n    if seg_len_sq <= 1e-9:\n        return dist(px, py, x1, y1)\n    t = ((px - x1) * dx + (py - y1) * dy) / seg_len_sq\n    t = max(0.0, min(1.0, t))\n    proj_x = x1 + t * dx\n    proj_y = y1 + t * dy\n    return dist(px, py, proj_x, proj_y)\n\n\ndef segment_hits_sun(x1, y1, x2, y2, safety=SUN_SAFETY):\n    return point_to_segment_distance(CENTER_X, CENTER_Y, x1, y1, x2, y2) < SUN_R + safety\n\n\ndef launch_point(sx, sy, sr, angle):\n    clearance = sr + LAUNCH_CLEARANCE\n    return sx + math.cos(angle) * clearance, sy + math.sin(angle) * clearance\n\n\ndef actual_path_geometry(sx, sy, sr, tx, ty, tr):\n    angle = math.atan2(ty - sy, tx - sx)\n    start_x, start_y = launch_point(sx, sy, sr, angle)\n    hit_distance = max(0.0, dist(sx, sy, tx, ty) - (sr + LAUNCH_CLEARANCE) - tr)\n    end_x = start_x + math.cos(angle) * hit_distance\n    end_y = start_y + math.sin(angle) * hit_distance\n    return angle, start_x, start_y, end_x, end_y, hit_distance\n\n\ndef safe_angle_and_distance(sx, sy, sr, tx, ty, tr):\n    angle, start_x, start_y, end_x, end_y, hit_distance = actual_path_geometry(\n        sx, sy, sr, tx, ty, tr,\n    )\n    if segment_hits_sun(start_x, start_y, end_x, end_y):\n        return None\n    return angle, hit_distance\n\n\ndef predict_planet_position(planet, initial_by_id, angular_velocity, turns):\n    init = initial_by_id.get(planet.id)\n    if init is None:\n        return planet.x, planet.y\n    r = dist(init.x, init.y, CENTER_X, CENTER_Y)\n    if r + init.radius >= ROTATION_LIMIT:\n        return planet.x, planet.y\n    cur_ang = math.atan2(planet.y - CENTER_Y, planet.x - CENTER_X)\n    new_ang = cur_ang + angular_velocity * turns\n    return (\n        CENTER_X + r * math.cos(new_ang),\n        CENTER_Y + r * math.sin(new_ang),\n    )\n\n\ndef predict_comet_position(planet_id, comets, turns):\n    for group in comets:\n        pids = group.get("planet_ids", [])\n        if planet_id not in pids:\n            continue\n        idx = pids.index(planet_id)\n        paths = group.get("paths", [])\n        path_index = group.get("path_index", 0)\n        if idx >= len(paths):\n            return None\n        path = paths[idx]\n        future_idx = path_index + int(turns)\n        if 0 <= future_idx < len(path):\n            return path[future_idx][0], path[future_idx][1]\n        return None\n    return None\n\n\ndef comet_remaining_life(planet_id, comets):\n    for group in comets:\n        pids = group.get("planet_ids", [])\n        if planet_id not in pids:\n            continue\n        idx = pids.index(planet_id)\n        paths = group.get("paths", [])\n        path_index = group.get("path_index", 0)\n        if idx < len(paths):\n            return max(0, len(paths[idx]) - path_index)\n    return 0\n\n\ndef estimate_arrival(sx, sy, sr, tx, ty, tr, ships):\n    safe = safe_angle_and_distance(sx, sy, sr, tx, ty, tr)\n    if safe is None:\n        return None\n    angle, total_d = safe\n    turns = max(1, int(math.ceil(total_d / fleet_speed(max(1, ships)))))\n    return angle, turns\n\n\ndef travel_time(sx, sy, sr, tx, ty, tr, ships):\n    est = estimate_arrival(sx, sy, sr, tx, ty, tr, ships)\n    if est is None:\n        return 10**9\n    return est[1]\n\n\ndef predict_target_position(target, turns, initial_by_id, ang_vel, comets, comet_ids):\n    if target.id in comet_ids:\n        return predict_comet_position(target.id, comets, turns)\n    return predict_planet_position(target, initial_by_id, ang_vel, turns)\n\n\ndef target_can_move(target, initial_by_id, comet_ids):\n    if target.id in comet_ids:\n        return True\n    init = initial_by_id.get(target.id)\n    if init is None:\n        return False\n    r = dist(init.x, init.y, CENTER_X, CENTER_Y)\n    return r + init.radius < ROTATION_LIMIT\n\n\ndef search_safe_intercept(src, target, ships, initial_by_id, ang_vel, comets, comet_ids):\n    best = None\n    best_score = None\n    max_turns = min(HORIZON, ROUTE_SEARCH_HORIZON)\n    if target.id in comet_ids:\n        max_turns = min(max_turns, max(0, comet_remaining_life(target.id, comets) - 1))\n\n    for candidate_turns in range(1, max_turns + 1):\n        pos = predict_target_position(\n            target, candidate_turns, initial_by_id, ang_vel, comets, comet_ids,\n        )\n        if pos is None:\n            continue\n        est = estimate_arrival(src.x, src.y, src.radius, pos[0], pos[1], target.radius, ships)\n        if est is None:\n            continue\n        _, turns = est\n        if abs(turns - candidate_turns) > INTERCEPT_TOLERANCE:\n            continue\n\n        actual_turns = max(turns, candidate_turns)\n        actual_pos = predict_target_position(\n            target, actual_turns, initial_by_id, ang_vel, comets, comet_ids,\n        )\n        if actual_pos is None:\n            continue\n\n        confirm = estimate_arrival(\n            src.x, src.y, src.radius, actual_pos[0], actual_pos[1], target.radius, ships,\n        )\n        if confirm is None:\n            continue\n\n        delta = abs(confirm[1] - actual_turns)\n        if delta > INTERCEPT_TOLERANCE:\n            continue\n\n        score = (delta, confirm[1], candidate_turns)\n        if best is None or score < best_score:\n            best_score = score\n            best = (confirm[0], confirm[1], actual_pos[0], actual_pos[1])\n\n    return best\n\n\ndef aim_with_prediction(src, target, ships, initial_by_id, ang_vel, comets, comet_ids):\n    est = estimate_arrival(src.x, src.y, src.radius, target.x, target.y, target.radius, ships)\n    if est is None:\n        if not target_can_move(target, initial_by_id, comet_ids):\n            return None\n        return search_safe_intercept(\n            src, target, ships, initial_by_id, ang_vel, comets, comet_ids,\n        )\n\n    tx, ty = target.x, target.y\n    for _ in range(5):\n        _, turns = est\n        pos = predict_target_position(target, turns, initial_by_id, ang_vel, comets, comet_ids)\n        if pos is None:\n            return None\n        ntx, nty = pos\n        next_est = estimate_arrival(src.x, src.y, src.radius, ntx, nty, target.radius, ships)\n        if next_est is None:\n            if not target_can_move(target, initial_by_id, comet_ids):\n                return None\n            return search_safe_intercept(\n                src, target, ships, initial_by_id, ang_vel, comets, comet_ids,\n            )\n        if (\n            abs(ntx - tx) < 0.3\n            and abs(nty - ty) < 0.3\n            and abs(next_est[1] - turns) <= INTERCEPT_TOLERANCE\n        ):\n            return next_est[0], next_est[1], ntx, nty\n        tx, ty = ntx, nty\n        est = next_est\n\n    final_est = estimate_arrival(src.x, src.y, src.radius, tx, ty, target.radius, ships)\n    if final_est is None:\n        return search_safe_intercept(\n            src, target, ships, initial_by_id, ang_vel, comets, comet_ids,\n        )\n    return final_est[0], final_est[1], tx, ty\n\n# ============================================================\n# World Model\n# ============================================================\n\ndef fleet_target_planet(fleet, planets):\n    best_planet = None\n    best_time = 1e9\n    dir_x = math.cos(fleet.angle)\n    dir_y = math.sin(fleet.angle)\n    speed = fleet_speed(fleet.ships)\n\n    for planet in planets:\n        dx = planet.x - fleet.x\n        dy = planet.y - fleet.y\n        proj = dx * dir_x + dy * dir_y\n        if proj < 0:\n            continue\n        perp_sq = dx * dx + dy * dy - proj * proj\n        radius_sq = planet.radius * planet.radius\n        if perp_sq >= radius_sq:\n            continue\n        hit_d = max(0.0, proj - math.sqrt(max(0.0, radius_sq - perp_sq)))\n        turns = hit_d / speed\n        if turns <= HORIZON and turns < best_time:\n            best_time = turns\n            best_planet = planet\n\n    if best_planet is None:\n        return None, None\n    return best_planet, int(math.ceil(best_time))\n\n\ndef segment_circle_entry_distance(x1, y1, x2, y2, cx, cy, radius):\n    dx = x2 - x1\n    dy = y2 - y1\n    fx = x1 - cx\n    fy = y1 - cy\n    a = dx * dx + dy * dy\n    if a <= 1e-9:\n        return 0.0 if dist(x1, y1, cx, cy) <= radius else None\n\n    b = 2.0 * (fx * dx + fy * dy)\n    c = fx * fx + fy * fy - radius * radius\n    disc = b * b - 4.0 * a * c\n    if disc < 0:\n        return None\n\n    root = math.sqrt(max(0.0, disc))\n    t1 = (-b - root) / (2.0 * a)\n    t2 = (-b + root) / (2.0 * a)\n    if 0.0 <= t1 <= 1.0:\n        return math.sqrt(a) * t1\n    if 0.0 <= t2 <= 1.0:\n        return math.sqrt(a) * t2\n    return None\n\n\ndef fleet_target_planet_dynamic(\n    fleet,\n    planets,\n    initial_by_id,\n    ang_vel,\n    comets,\n    comet_ids,\n    max_turns=ARRIVAL_LEDGER_DYNAMIC_HORIZON,\n):\n    """Project an in-flight fleet against moving planets/comets."""\n    moving_planets = [\n        planet\n        for planet in planets\n        if planet.id in comet_ids or target_can_move(planet, initial_by_id, comet_ids)\n    ]\n    static_target, static_eta = fleet_target_planet(fleet, planets)\n    if not moving_planets:\n        return static_target, static_eta\n    if static_eta is not None:\n        max_turns = min(max_turns, max(1, static_eta))\n\n    x = float(fleet.x)\n    y = float(fleet.y)\n    dir_x = math.cos(fleet.angle)\n    dir_y = math.sin(fleet.angle)\n    speed = fleet_speed(fleet.ships)\n\n    for turn in range(1, max_turns + 1):\n        old_x, old_y = x, y\n        new_x = old_x + dir_x * speed\n        new_y = old_y + dir_y * speed\n\n        if segment_hits_sun(old_x, old_y, new_x, new_y, safety=0.0):\n            return None, None\n\n        best_planet = None\n        best_distance = None\n        segment_len = max(1e-9, dist(old_x, old_y, new_x, new_y))\n\n        for planet in moving_planets:\n            move_pos = predict_target_position(\n                planet, turn - 1, initial_by_id, ang_vel, comets, comet_ids,\n            )\n            if move_pos is None:\n                continue\n\n            hit_distance = segment_circle_entry_distance(\n                old_x,\n                old_y,\n                new_x,\n                new_y,\n                move_pos[0],\n                move_pos[1],\n                planet.radius + 0.05,\n            )\n            if (\n                hit_distance is not None\n                and not (planet.id == fleet.from_planet_id and turn == 1 and hit_distance < 0.5)\n                and (best_distance is None or hit_distance < best_distance)\n            ):\n                best_distance = hit_distance\n                best_planet = planet\n\n            sweep_pos = predict_target_position(\n                planet, turn, initial_by_id, ang_vel, comets, comet_ids,\n            )\n            if sweep_pos is None:\n                continue\n            if (\n                dist(new_x, new_y, sweep_pos[0], sweep_pos[1]) <= planet.radius + 0.05\n                and (best_distance is None or segment_len < best_distance)\n            ):\n                best_distance = segment_len\n                best_planet = planet\n\n        if best_planet is not None:\n            return best_planet, turn\n\n        x, y = new_x, new_y\n        if x < 0.0 or x > BOARD or y < 0.0 or y > BOARD:\n            return None, None\n\n    return static_target, static_eta\n\n\ndef shot_hits_intended_target(\n    src,\n    target,\n    angle,\n    ships,\n    planets,\n    initial_by_id,\n    ang_vel,\n    comets,\n    comet_ids,\n    max_turns,\n):\n    """Check the actual launched path, including spawn offset, hits target first."""\n    start_x, start_y = launch_point(src.x, src.y, src.radius, angle)\n    probe = Fleet(-1, src.owner, start_x, start_y, angle, src.id, ships)\n    hit, eta = fleet_target_planet_dynamic(\n        probe,\n        planets,\n        initial_by_id,\n        ang_vel,\n        comets,\n        comet_ids,\n        max_turns=max_turns,\n    )\n    return hit is not None and hit.id == target.id and eta is not None\n\n\n# Compatibility helpers used by the replay-analysis scripts from the v4 line.\ndef distance_to_segment(px, py, x1, y1, x2, y2):\n    return point_to_segment_distance(px, py, x1, y1, x2, y2)\n\n\ndef crosses_sun(x1, y1, x2, y2):\n    return point_to_segment_distance(CENTER_X, CENTER_Y, x1, y1, x2, y2) <= SUN_R + 0.25\n\n\ndef projected_fleet_target(fleet, planets, obs=None, angular_velocity=0.0, comet_ids=None, max_turns=140):\n    target, eta = fleet_target_planet(fleet, planets)\n    if target is None:\n        return None\n    if eta is not None and eta > max_turns:\n        return None\n    return target\n\n\ndef build_arrival_ledger(fleets, planets, initial_by_id=None, ang_vel=0.0, comets=None, comet_ids=None):\n    arrivals_by_planet = {planet.id: [] for planet in planets}\n    initial_by_id = initial_by_id or {}\n    comets = comets or []\n    comet_ids = set(comet_ids or [])\n    for fleet in fleets:\n        if initial_by_id or comets:\n            target, eta = fleet_target_planet_dynamic(\n                fleet,\n                planets,\n                initial_by_id,\n                ang_vel,\n                comets,\n                comet_ids,\n            )\n        else:\n            target, eta = fleet_target_planet(fleet, planets)\n        if target is None:\n            continue\n        arrivals_by_planet[target.id].append((eta, fleet.owner, int(fleet.ships)))\n    return arrivals_by_planet\n\n\ndef resolve_arrival_event(owner, garrison, arrivals):\n    by_owner = {}\n    for _, attacker_owner, ships in arrivals:\n        by_owner[attacker_owner] = by_owner.get(attacker_owner, 0) + ships\n\n    if not by_owner:\n        return owner, max(0.0, garrison)\n\n    sorted_players = sorted(by_owner.items(), key=lambda item: item[1], reverse=True)\n    top_owner, top_ships = sorted_players[0]\n\n    if len(sorted_players) > 1:\n        second_ships = sorted_players[1][1]\n        if top_ships == second_ships:\n            survivor_owner = -1\n            survivor_ships = 0\n        else:\n            survivor_owner = top_owner\n            survivor_ships = top_ships - second_ships\n    else:\n        survivor_owner = top_owner\n        survivor_ships = top_ships\n\n    if survivor_ships <= 0:\n        return owner, max(0.0, garrison)\n\n    if owner == survivor_owner:\n        return owner, garrison + survivor_ships\n\n    garrison -= survivor_ships\n    if garrison < 0:\n        return survivor_owner, -garrison\n    return owner, garrison\n\n\ndef normalize_arrivals(arrivals, horizon):\n    events = []\n    for turns, owner, ships in arrivals:\n        if ships <= 0:\n            continue\n        eta = max(1, int(math.ceil(turns)))\n        if eta > horizon:\n            continue\n        events.append((eta, owner, int(ships)))\n    events.sort(key=lambda item: item[0])\n    return events\n\n\ndef simulate_planet_timeline(planet, arrivals, player, horizon):\n    horizon = max(0, int(math.ceil(horizon)))\n    events = normalize_arrivals(arrivals, horizon)\n    by_turn = defaultdict(list)\n    for item in events:\n        by_turn[item[0]].append(item)\n\n    owner = planet.owner\n    garrison = float(planet.ships)\n    owner_at = {0: owner}\n    ships_at = {0: max(0.0, garrison)}\n    min_owned = garrison if owner == player else 0.0\n    first_enemy = None\n    fall_turn = None\n\n    for turn in range(1, horizon + 1):\n        if owner != -1:\n            garrison += planet.production\n\n        group = by_turn.get(turn, [])\n        prev_owner = owner\n        if group:\n            if prev_owner == player and first_enemy is None:\n                if any(item[1] not in (-1, player) for item in group):\n                    first_enemy = turn\n            owner, garrison = resolve_arrival_event(owner, garrison, group)\n            if prev_owner == player and owner != player and fall_turn is None:\n                fall_turn = turn\n\n        owner_at[turn] = owner\n        ships_at[turn] = max(0.0, garrison)\n        if owner == player:\n            min_owned = min(min_owned, garrison)\n\n    keep_needed = 0\n    holds_full = True\n\n    if planet.owner == player:\n        def survives_with_keep(keep):\n            sim_owner = planet.owner\n            sim_garrison = float(keep)\n            for turn in range(1, horizon + 1):\n                if sim_owner != -1:\n                    sim_garrison += planet.production\n                group = by_turn.get(turn, [])\n                if group:\n                    sim_owner, sim_garrison = resolve_arrival_event(sim_owner, sim_garrison, group)\n                    if sim_owner != player:\n                        return False\n            return sim_owner == player\n\n        if survives_with_keep(int(planet.ships)):\n            lo, hi = 0, int(planet.ships)\n            while lo < hi:\n                mid = (lo + hi) // 2\n                if survives_with_keep(mid):\n                    hi = mid\n                else:\n                    lo = mid + 1\n            keep_needed = lo\n        else:\n            holds_full = False\n            keep_needed = int(planet.ships)\n\n    return {\n        "owner_at": owner_at,\n        "ships_at": ships_at,\n        "keep_needed": keep_needed,\n        "min_owned": max(0, int(math.floor(min_owned))) if planet.owner == player else 0,\n        "first_enemy": first_enemy,\n        "fall_turn": fall_turn,\n        "holds_full": holds_full,\n        "horizon": horizon,\n    }\n\n\ndef state_at_timeline(timeline, arrival_turn):\n    turn = max(0, int(math.ceil(arrival_turn)))\n    turn = min(turn, timeline["horizon"])\n    owner = timeline["owner_at"].get(turn, timeline["owner_at"][timeline["horizon"]])\n    ships = timeline["ships_at"].get(turn, timeline["ships_at"][timeline["horizon"]])\n    return owner, max(0.0, ships)\n\n\ndef count_players(planets, fleets):\n    owners = set()\n    for planet in planets:\n        if planet.owner != -1:\n            owners.add(planet.owner)\n    for fleet in fleets:\n        owners.add(fleet.owner)\n    return max(2, len(owners))\n\n\ndef nearest_distance_to_set(px, py, planets):\n    if not planets:\n        return 10**9\n    return min(dist(px, py, planet.x, planet.y) for planet in planets)\n\n\ndef indirect_features(planet, planets, player):\n    friendly = 0.0\n    neutral = 0.0\n    enemy = 0.0\n    for other in planets:\n        if other.id == planet.id:\n            continue\n        d = dist(planet.x, planet.y, other.x, other.y)\n        if d < 1:\n            continue\n        factor = other.production / (d + 12.0)\n        if other.owner == player:\n            friendly += factor\n        elif other.owner == -1:\n            neutral += factor\n        else:\n            enemy += factor\n    return friendly, neutral, enemy\n\n\ndef detect_exposed_enemy_planets(fleets, enemy_planets):\n    exposed = set()\n    for planet in enemy_planets:\n        outbound = sum(\n            int(f.ships)\n            for f in fleets\n            if f.owner == planet.owner and f.from_planet_id == planet.id and f.ships >= 5\n        )\n        if outbound >= 12 and outbound >= planet.ships * 0.8:  # lowered threshold\n            exposed.add(planet.id)\n    return exposed\n\n\ndef _compute_weakest_enemy(enemy_planets, owner_strength, owner_production):\n    """Return the player ID of the weakest enemy (lowest ships + future production)."""\n    enemy_owners = set(p.owner for p in enemy_planets)\n    if not enemy_owners:\n        return None\n    return min(\n        enemy_owners,\n        key=lambda owner: owner_strength.get(owner, 0) + owner_production.get(owner, 0) * 15,\n    )\n\n\ndef _compute_strongest_enemy(enemy_planets, owner_strength, owner_production):\n    enemy_owners = set(p.owner for p in enemy_planets)\n    if not enemy_owners:\n        return None\n    return max(\n        enemy_owners,\n        key=lambda owner: owner_strength.get(owner, 0) + owner_production.get(owner, 0) * 18,\n    )\n\n\nclass WorldModel:\n    def __init__(self, player, step, planets, fleets, initial_by_id, ang_vel, comets, comet_ids):\n        self.player = player\n        self.step = step\n        self.planets = planets\n        self.fleets = fleets\n        self.initial_by_id = initial_by_id\n        self.ang_vel = ang_vel\n        self.comets = comets\n        self.comet_ids = set(comet_ids)\n\n        self.planet_by_id = {planet.id: planet for planet in planets}\n        self.my_planets = [planet for planet in planets if planet.owner == player]\n        self.enemy_planets = [planet for planet in planets if planet.owner not in (-1, player)]\n        self.neutral_planets = [planet for planet in planets if planet.owner == -1]\n        self.static_neutral_planets = [\n            planet for planet in self.neutral_planets if is_static_planet(planet)\n        ]\n\n        self.num_players = count_players(planets, fleets)\n        self.remaining_steps = max(1, TOTAL_STEPS - step)\n        self.is_early = step < EARLY_TURN_LIMIT\n        self.is_opening = step < OPENING_TURN_LIMIT\n        self.is_late = self.remaining_steps < LATE_REMAINING_TURNS\n        self.is_very_late = self.remaining_steps < VERY_LATE_REMAINING_TURNS\n        self.is_total_war = self.remaining_steps < TOTAL_WAR_REMAINING_TURNS\n        self.is_four_player = self.num_players >= 4\n\n        self.owner_strength = defaultdict(int)\n        self.owner_production = defaultdict(int)\n        for planet in planets:\n            if planet.owner != -1:\n                self.owner_strength[planet.owner] += int(planet.ships)\n                self.owner_production[planet.owner] += int(planet.production)\n        for fleet in fleets:\n            self.owner_strength[fleet.owner] += int(fleet.ships)\n\n        self.my_total = self.owner_strength.get(player, 0)\n        self.enemy_total = sum(\n            strength for owner, strength in self.owner_strength.items() if owner != player\n        )\n        self.max_enemy_strength = max(\n            (strength for owner, strength in self.owner_strength.items() if owner != player),\n            default=0,\n        )\n        self.my_prod = self.owner_production.get(player, 0)\n        self.max_enemy_prod = max(\n            (\n                production\n                for owner, production in self.owner_production.items()\n                if owner != player\n            ),\n            default=0,\n        )\n        self.enemy_prod = sum(\n            production\n            for owner, production in self.owner_production.items()\n            if owner != player\n        )\n\n        # Weakest enemy tracking (key for 4P elimination strategy)\n        self._weakest_enemy = _compute_weakest_enemy(\n            self.enemy_planets, self.owner_strength, self.owner_production\n        )\n        self._weakest_enemy_strength = (\n            self.owner_strength.get(self._weakest_enemy, 0)\n            if self._weakest_enemy is not None else 0\n        )\n        self._leader_enemy = _compute_strongest_enemy(\n            self.enemy_planets, self.owner_strength, self.owner_production\n        )\n        self._leader_enemy_strength = (\n            self.owner_strength.get(self._leader_enemy, 0)\n            if self._leader_enemy is not None else 0\n        )\n        self._leader_enemy_prod = (\n            self.owner_production.get(self._leader_enemy, 0)\n            if self._leader_enemy is not None else 0\n        )\n\n        self.arrivals_by_planet = build_arrival_ledger(\n            fleets, planets, initial_by_id, ang_vel, comets, comet_ids,\n        )\n        self.base_timeline = {\n            planet.id: simulate_planet_timeline(\n                planet,\n                self.arrivals_by_planet[planet.id],\n                player,\n                HORIZON,\n            )\n            for planet in planets\n        }\n        self.keep_needed_map = {\n            planet.id: self.base_timeline[planet.id]["keep_needed"] for planet in planets\n        }\n        self.min_owned_map = {\n            planet.id: self.base_timeline[planet.id]["min_owned"] for planet in planets\n        }\n        self.first_enemy_map = {\n            planet.id: self.base_timeline[planet.id]["first_enemy"] for planet in planets\n        }\n        self.fall_turn_map = {\n            planet.id: self.base_timeline[planet.id]["fall_turn"] for planet in planets\n        }\n        self.holds_full_map = {\n            planet.id: self.base_timeline[planet.id]["holds_full"] for planet in planets\n        }\n        self.indirect_feature_map = {\n            planet.id: indirect_features(planet, planets, player) for planet in planets\n        }\n        self.exposed_planet_ids = detect_exposed_enemy_planets(fleets, self.enemy_planets)\n        self.shot_cache = {}\n        self.probe_candidate_cache = {}\n        self.best_probe_cache = {}\n        self.reaction_cache = {}\n        self.exact_need_cache = {}\n\n        self.total_visible_ships = sum(int(planet.ships) for planet in planets) + sum(\n            int(fleet.ships) for fleet in fleets\n        )\n        self.total_production = sum(int(planet.production) for planet in planets)\n\n    def is_static(self, planet_id):\n        return is_static_planet(self.planet_by_id[planet_id])\n\n    def comet_life(self, planet_id):\n        return comet_remaining_life(planet_id, self.comets)\n\n    def source_inventory_left(self, source_id, spent_total):\n        return max(0, int(self.planet_by_id[source_id].ships) - spent_total[source_id])\n\n    def plan_shot(self, src_id, target_id, ships):\n        ships = int(ships)\n        key = (src_id, target_id, ships)\n        if key in self.shot_cache:\n            return self.shot_cache[key]\n        src = self.planet_by_id[src_id]\n        target = self.planet_by_id[target_id]\n        result = aim_with_prediction(\n            src, target, ships, self.initial_by_id, self.ang_vel, self.comets, self.comet_ids,\n        )\n        self.shot_cache[key] = result\n        return result\n\n    def probe_ship_candidates(self, src_id, target_id, source_cap, hints=()):\n        source_cap = max(1, int(source_cap))\n        normalized_hints = tuple(\n            int(math.ceil(hint)) for hint in hints if hint is not None\n        )\n        cache_key = (src_id, target_id, source_cap, normalized_hints)\n        cached = self.probe_candidate_cache.get(cache_key)\n        if cached is not None:\n            return cached\n        target = self.planet_by_id[target_id]\n        target_ships = max(1, int(math.ceil(target.ships)))\n\n        values = set(range(1, min(6, source_cap) + 1))\n        values.update({\n            source_cap,\n            max(1, source_cap // 2),\n            max(1, source_cap // 3),\n            min(source_cap, PARTIAL_SOURCE_MIN_SHIPS),\n            min(source_cap, target_ships + 1),\n            min(source_cap, target_ships + 2),\n            min(source_cap, target_ships + 4),\n            min(source_cap, target_ships + 8),\n        })\n\n        for hint in normalized_hints:\n            base = max(1, min(source_cap, hint))\n            for delta in (-2, -1, 0, 1, 2):\n                candidate = base + delta\n                if 1 <= candidate <= source_cap:\n                    values.add(candidate)\n\n        result = sorted(values)\n        self.probe_candidate_cache[cache_key] = result\n        return result\n\n    def best_probe_aim(\n        self,\n        src_id,\n        target_id,\n        source_cap,\n        hints=(),\n        min_turn=None,\n        max_turn=None,\n        anchor_turn=None,\n        max_anchor_diff=None,\n    ):\n        cache_key = (\n            src_id,\n            target_id,\n            max(1, int(source_cap)),\n            tuple(hints),\n            min_turn,\n            max_turn,\n            anchor_turn,\n            max_anchor_diff,\n        )\n        if cache_key in self.best_probe_cache:\n            return self.best_probe_cache[cache_key]\n\n        best = None\n        best_key = None\n\n        for ships in self.probe_ship_candidates(src_id, target_id, source_cap, hints=hints):\n            aim = self.plan_shot(src_id, target_id, ships)\n            if aim is None:\n                continue\n\n            angle, turns, dist_to_target, path_target = aim\n            if min_turn is not None and turns < min_turn:\n                continue\n            if max_turn is not None and turns > max_turn:\n                continue\n            if (\n                anchor_turn is not None\n                and max_anchor_diff is not None\n                and abs(turns - anchor_turn) > max_anchor_diff\n            ):\n                continue\n\n            if anchor_turn is None:\n                key = (turns, ships)\n            else:\n                key = (abs(turns - anchor_turn), turns, ships)\n\n            if best_key is None or key < best_key:\n                best_key = key\n                best = (ships, (angle, turns, dist_to_target, path_target))\n\n        self.best_probe_cache[cache_key] = best\n        return best\n\n    def reaction_times(self, target_id):\n        cached = self.reaction_cache.get(target_id)\n        if cached is not None:\n            return cached\n\n        target = self.planet_by_id[target_id]\n        my_t = 10**9\n        for planet in self.my_planets:\n            seeded = self.best_probe_aim(planet.id, target.id, max(1, int(planet.ships)))\n            if seeded is None:\n                continue\n            _, aim = seeded\n            my_t = min(my_t, aim[1])\n\n        enemy_t = 10**9\n        for planet in self.enemy_planets:\n            seeded = self.best_probe_aim(planet.id, target.id, max(1, int(planet.ships)))\n            if seeded is None:\n                continue\n            _, aim = seeded\n            enemy_t = min(enemy_t, aim[1])\n\n        cached = (my_t, enemy_t)\n        self.reaction_cache[target_id] = cached\n        return cached\n\n    def projected_state(self, target_id, arrival_turn, planned_commitments=None, extra_arrivals=()):\n        planned_commitments = planned_commitments or {}\n        cutoff = max(1, int(math.ceil(arrival_turn)))\n        if not planned_commitments.get(target_id) and not extra_arrivals:\n            return state_at_timeline(self.base_timeline[target_id], cutoff)\n\n        arrivals = [\n            item\n            for item in self.arrivals_by_planet.get(target_id, [])\n            if item[0] <= cutoff\n        ]\n        arrivals.extend(\n            item\n            for item in planned_commitments.get(target_id, [])\n            if item[0] <= cutoff\n        )\n        arrivals.extend(item for item in extra_arrivals if item[0] <= cutoff)\n\n        target = self.planet_by_id[target_id]\n        dyn = simulate_planet_timeline(target, arrivals, self.player, cutoff)\n        return state_at_timeline(dyn, cutoff)\n\n    def projected_timeline(self, target_id, horizon, planned_commitments=None, extra_arrivals=()):\n        planned_commitments = planned_commitments or {}\n        horizon = max(1, int(math.ceil(horizon)))\n        arrivals = [\n            item for item in self.arrivals_by_planet.get(target_id, []) if item[0] <= horizon\n        ]\n        arrivals.extend(\n            item for item in planned_commitments.get(target_id, []) if item[0] <= horizon\n        )\n        arrivals.extend(item for item in extra_arrivals if item[0] <= horizon)\n        target = self.planet_by_id[target_id]\n        return simulate_planet_timeline(target, arrivals, self.player, horizon)\n\n    def hold_status(self, target_id, planned_commitments=None, horizon=HORIZON):\n        planned_commitments = planned_commitments or {}\n        if planned_commitments.get(target_id):\n            tl = self.projected_timeline(\n                target_id, horizon, planned_commitments=planned_commitments,\n            )\n        else:\n            tl = self.base_timeline[target_id]\n        return {\n            "keep_needed": tl["keep_needed"],\n            "min_owned": tl["min_owned"],\n            "first_enemy": tl["first_enemy"],\n            "fall_turn": tl["fall_turn"],\n            "holds_full": tl["holds_full"],\n        }\n\n    def _ownership_search_cap(self, eval_turn):\n        productive_cap = self.total_production * max(2, eval_turn + 2)\n        return max(32, int(self.total_visible_ships + productive_cap + 32))\n\n    def min_ships_to_own_by(\n        self,\n        target_id,\n        eval_turn,\n        attacker_owner,\n        arrival_turn=None,\n        planned_commitments=None,\n        extra_arrivals=(),\n        upper_bound=None,\n    ):\n        planned_commitments = planned_commitments or {}\n        eval_turn = max(1, int(math.ceil(eval_turn)))\n        arrival_turn = eval_turn if arrival_turn is None else max(1, int(math.ceil(arrival_turn)))\n        if arrival_turn > eval_turn:\n            if upper_bound is not None:\n                return max(1, int(upper_bound)) + 1\n            return self._ownership_search_cap(eval_turn) + 1\n\n        normalized_extra = tuple(\n            (max(1, int(math.ceil(turns))), owner, int(ships))\n            for turns, owner, ships in extra_arrivals\n            if ships > 0 and max(1, int(math.ceil(turns))) <= eval_turn\n        )\n\n        cache_key = None\n        if (\n            arrival_turn == eval_turn\n            and not planned_commitments.get(target_id)\n            and not normalized_extra\n        ):\n            cache_key = (target_id, eval_turn, attacker_owner)\n            cached = self.exact_need_cache.get(cache_key)\n            if cached is not None:\n                return cached\n\n        owner_before, ships_before = self.projected_state(\n            target_id,\n            eval_turn,\n            planned_commitments=planned_commitments,\n            extra_arrivals=normalized_extra,\n        )\n        if owner_before == attacker_owner:\n            if cache_key is not None:\n                self.exact_need_cache[cache_key] = 0\n            return 0\n\n        def owns_at(ships):\n            owner_after, _ = self.projected_state(\n                target_id,\n                eval_turn,\n                planned_commitments=planned_commitments,\n                extra_arrivals=normalized_extra + ((arrival_turn, attacker_owner, int(ships)),),\n            )\n            return owner_after == attacker_owner\n\n        if upper_bound is not None:\n            hi = max(1, int(upper_bound))\n            if not owns_at(hi):\n                return hi + 1\n        else:\n            hi = max(1, int(math.ceil(ships_before)) + 1)\n            search_cap = self._ownership_search_cap(eval_turn)\n            while hi <= search_cap and not owns_at(hi):\n                hi *= 2\n            if hi > search_cap:\n                hi = search_cap\n                if not owns_at(hi):\n                    return hi + 1\n\n        lo = 1\n        while lo < hi:\n            mid = (lo + hi) // 2\n            if owns_at(mid):\n                hi = mid\n            else:\n                lo = mid + 1\n\n        if cache_key is not None:\n            self.exact_need_cache[cache_key] = lo\n        return lo\n\n    def min_ships_to_own_at(\n        self,\n        target_id,\n        arrival_turn,\n        attacker_owner,\n        planned_commitments=None,\n        extra_arrivals=(),\n        upper_bound=None,\n    ):\n        return self.min_ships_to_own_by(\n            target_id,\n            arrival_turn,\n            attacker_owner,\n            arrival_turn=arrival_turn,\n            planned_commitments=planned_commitments,\n            extra_arrivals=extra_arrivals,\n            upper_bound=upper_bound,\n        )\n\n    def reinforcement_needed_to_hold_until(\n        self,\n        planet_id,\n        arrival_turn,\n        hold_until,\n        planned_commitments=None,\n        upper_bound=None,\n    ):\n        planned_commitments = planned_commitments or {}\n        target = self.planet_by_id[planet_id]\n        arrival_turn = max(1, int(math.ceil(arrival_turn)))\n        hold_until = max(arrival_turn, int(math.ceil(hold_until)))\n\n        if target.owner != self.player:\n            return self.min_ships_to_own_by(\n                planet_id,\n                hold_until,\n                self.player,\n                arrival_turn=arrival_turn,\n                planned_commitments=planned_commitments,\n                upper_bound=upper_bound,\n            )\n\n        def holds_with_reinforcement(ships):\n            timeline = self.projected_timeline(\n                planet_id,\n                hold_until,\n                planned_commitments=planned_commitments,\n                extra_arrivals=((arrival_turn, self.player, int(ships)),),\n            )\n            for turn in range(arrival_turn, hold_until + 1):\n                if timeline["owner_at"].get(turn) != self.player:\n                    return False\n            return True\n\n        if upper_bound is not None:\n            hi = max(1, int(upper_bound))\n            if not holds_with_reinforcement(hi):\n                return hi + 1\n        else:\n            hi = 1\n            search_cap = self._ownership_search_cap(hold_until)\n            while hi <= search_cap and not holds_with_reinforcement(hi):\n                hi *= 2\n            if hi > search_cap:\n                hi = search_cap\n                if not holds_with_reinforcement(hi):\n                    return hi + 1\n\n        lo = 1\n        while lo < hi:\n            mid = (lo + hi) // 2\n            if holds_with_reinforcement(mid):\n                hi = mid\n            else:\n                lo = mid + 1\n        return lo\n\n    def ships_needed_to_capture(\n        self,\n        target_id,\n        arrival_turn,\n        planned_commitments=None,\n        extra_arrivals=(),\n    ):\n        return self.min_ships_to_own_at(\n            target_id,\n            arrival_turn,\n            self.player,\n            planned_commitments=planned_commitments,\n            extra_arrivals=extra_arrivals,\n        )\n\n# ============================================================\n# Strategy\n# ============================================================\n\ndef planet_distance(first, second):\n    return math.hypot(first.x - second.x, first.y - second.y)\n\n\ndef nearest_sources_to_target(target, sources, top_k):\n    if top_k <= 0 or len(sources) <= top_k:\n        return sources\n    return sorted(\n        sources,\n        key=lambda src: (planet_distance(src, target), -int(src.ships), src.id),\n    )[:top_k]\n\n\ndef min_legal_reaction_time(target, sources, world):\n    best = 10**9\n    for src in sources:\n        seeded = world.best_probe_aim(src.id, target.id, max(1, int(src.ships)))\n        if seeded is None:\n            continue\n        _, aim = seeded\n        best = min(best, aim[1])\n    return best\n\n\ndef policy_reaction_times(target_id, policy):\n    return policy["reaction_time_map"].get(target_id, (10**9, 10**9))\n\n\ndef candidate_time_valid(target, turns, world, remaining_buffer):\n    if turns > world.remaining_steps - remaining_buffer:\n        return False\n    if target.id in world.comet_ids:\n        life = world.comet_life(target.id)\n        if turns >= life or turns > COMET_MAX_CHASE_TURNS:\n            return False\n    return True\n\n\ndef stacked_enemy_proactive_keep(planet, world):\n    threats = []\n    for enemy in world.enemy_planets:\n        seeded = world.best_probe_aim(enemy.id, planet.id, max(1, int(enemy.ships)))\n        if seeded is None:\n            continue\n        _, aim = seeded\n        eta = aim[1]\n        if eta > MULTI_ENEMY_PROACTIVE_HORIZON:\n            continue\n        threats.append((eta, int(enemy.ships)))\n\n    if not threats:\n        return 0\n\n    threats.sort()\n    best_stacked = 0\n    left = 0\n    running = 0\n    for right in range(len(threats)):\n        running += threats[right][1]\n        while threats[right][0] - threats[left][0] > MULTI_ENEMY_STACK_WINDOW:\n            running -= threats[left][1]\n            left += 1\n        best_stacked = max(best_stacked, running)\n\n    return int(best_stacked * MULTI_ENEMY_PROACTIVE_RATIO)\n\n\ndef swarm_eta_tolerance(options, target, world):\n    if len(options) >= 3:\n        return THREE_SOURCE_ETA_TOLERANCE\n    if target.owner not in (-1, world.player):\n        return HOSTILE_SWARM_ETA_TOLERANCE\n    return MULTI_SOURCE_ETA_TOLERANCE\n\n\ndef detect_enemy_crashes(world):\n    crashes = []\n    for target_id, arrivals in world.arrivals_by_planet.items():\n        enemy_events = [\n            (int(math.ceil(eta)), owner, int(ships))\n            for eta, owner, ships in arrivals\n            if owner not in (-1, world.player) and ships > 0\n        ]\n        enemy_events.sort()\n        for i in range(len(enemy_events)):\n            eta_a, owner_a, ships_a = enemy_events[i]\n            for j in range(i + 1, len(enemy_events)):\n                eta_b, owner_b, ships_b = enemy_events[j]\n                if owner_a == owner_b:\n                    continue\n                if abs(eta_a - eta_b) > CRASH_EXPLOIT_ETA_WINDOW:\n                    break\n                if ships_a + ships_b < CRASH_EXPLOIT_MIN_TOTAL_SHIPS:\n                    continue\n                crashes.append({\n                    "target_id": target_id,\n                    "crash_turn": max(eta_a, eta_b),\n                    "owners": (owner_a, owner_b),\n                    "ships": (ships_a, ships_b),\n                })\n    return crashes\n\n\ndef detect_enemy_planet_battles(world):\n    """\n    Detect where an enemy fleet is attacking another enemy\'s owned planet.\n    These create attack windows — the winning side will be weakened.\n    Returns list of dicts with target_id, battle_turn, estimated post_battle_ships.\n    """\n    battles = []\n    for target in world.enemy_planets:\n        attacking_fleets = [\n            (int(math.ceil(eta)), owner, int(ships))\n            for eta, owner, ships in world.arrivals_by_planet.get(target.id, [])\n            if owner not in (-1, world.player) and owner != target.owner and ships > 0\n        ]\n        if not attacking_fleets:\n            continue\n\n        for eta, attacker_owner, attacker_ships in attacking_fleets:\n            # Rough post-battle estimate (production growth + garrison vs attacker)\n            garrison_at_eta = target.ships + target.production * eta\n            surviving_attacker = max(0, attacker_ships - garrison_at_eta)\n            surviving_defender = max(0, garrison_at_eta - attacker_ships)\n\n            if attacker_ships > garrison_at_eta:\n                post_owner = attacker_owner\n                post_ships = surviving_attacker\n            else:\n                post_owner = target.owner\n                post_ships = surviving_defender\n\n            # Only interesting if planet will be weak after battle\n            if post_ships < 25:\n                battles.append({\n                    "target_id": target.id,\n                    "battle_turn": eta,\n                    "post_owner": post_owner,\n                    "post_ships": post_ships,\n                    "original_owner": target.owner,\n                })\n\n    return battles\n\n\ndef build_policy_state(world, deadline=None):\n    def expired():\n        return deadline is not None and time.perf_counter() > deadline\n\n    indirect_wealth_map = {}\n    for target_id, features in world.indirect_feature_map.items():\n        friendly, neutral, enemy = features\n        indirect_wealth_map[target_id] = (\n            friendly * INDIRECT_FRIENDLY_WEIGHT\n            + neutral * INDIRECT_NEUTRAL_WEIGHT\n            + enemy * INDIRECT_ENEMY_WEIGHT\n        )\n\n    reserve = {}\n    attack_budget = {}\n    reaction_time_map = {}\n\n    for target in world.planets:\n        if expired():\n            break\n        if target.owner == world.player:\n            continue\n        my_sources = nearest_sources_to_target(target, world.my_planets, REACTION_SOURCE_TOP_K_MY)\n        enemy_sources = nearest_sources_to_target(target, world.enemy_planets, REACTION_SOURCE_TOP_K_ENEMY)\n        my_t = min_legal_reaction_time(target, my_sources, world)\n        enemy_t = min_legal_reaction_time(target, enemy_sources, world)\n        reaction_time_map[target.id] = (my_t, enemy_t)\n\n    for planet in world.my_planets:\n        if expired():\n            break\n        exact_keep = world.keep_needed_map.get(planet.id, 0)\n\n        proactive_keep = 0\n        for enemy in nearest_sources_to_target(planet, world.enemy_planets, PROACTIVE_ENEMY_TOP_K):\n            enemy_aim = world.plan_shot(enemy.id, planet.id, max(1, int(enemy.ships)))\n            if enemy_aim is None:\n                continue\n            enemy_eta = enemy_aim[1]\n            if enemy_eta > PROACTIVE_DEFENSE_HORIZON:\n                continue\n            proactive_keep = max(proactive_keep, int(enemy.ships * PROACTIVE_DEFENSE_RATIO))\n        proactive_keep = max(proactive_keep, stacked_enemy_proactive_keep(planet, world))\n\n        if world.is_four_player and proactive_keep > 0 and not world.is_late:\n            cap_ratio = FOUR_PLAYER_PROACTIVE_RESERVE_CAP\n            if world.max_enemy_prod >= world.my_prod + FOUR_PLAYER_LEADER_PRESSURE_MIN_GAP:\n                cap_ratio = FOUR_PLAYER_BEHIND_RESERVE_CAP\n            proactive_cap = max(\n                int(planet.production) + 2,\n                int(planet.ships * cap_ratio),\n            )\n            proactive_keep = min(proactive_keep, proactive_cap)\n\n        if world.is_total_war:\n            exact_keep = min(exact_keep, max(1, exact_keep // 2))\n            proactive_keep = min(proactive_keep, max(1, proactive_keep // 2))\n\n        reserve[planet.id] = min(int(planet.ships), max(exact_keep, proactive_keep))\n        attack_budget[planet.id] = max(0, int(planet.ships) - reserve[planet.id])\n\n    return {\n        "indirect_wealth_map": indirect_wealth_map,\n        "reserve": reserve,\n        "attack_budget": attack_budget,\n        "reaction_time_map": reaction_time_map,\n    }\n\n\ndef build_modes(world):\n    domination = (world.my_total - world.enemy_total) / max(1, world.my_total + world.enemy_total)\n    is_behind = domination < BEHIND_DOMINATION\n    is_ahead = domination > AHEAD_DOMINATION\n    prod_gap = world.max_enemy_prod - world.my_prod\n    is_prod_behind = (\n        not world.is_four_player\n        and world.step >= 35\n        and prod_gap >= 7\n        and world.max_enemy_prod > world.my_prod * 1.18\n    )\n    is_four_player_leader_pressure = (\n        world.is_four_player\n        and world.step >= 35\n        and prod_gap >= FOUR_PLAYER_LEADER_PRESSURE_MIN_GAP\n        and world.max_enemy_prod >= world.my_prod * FOUR_PLAYER_LEADER_PRESSURE_RATIO\n        and not is_ahead\n    )\n    is_snowball_risk = is_prod_behind and not is_ahead\n    is_dominating = is_ahead or (\n        world.max_enemy_strength > 0 and world.my_total > world.max_enemy_strength * 1.25\n    )\n    is_finishing = (\n        domination > FINISHING_DOMINATION\n        and world.my_prod > world.enemy_prod * FINISHING_PROD_RATIO\n        and world.step > 80\n    )\n\n    attack_margin_mult = 1.0\n    if is_ahead:\n        attack_margin_mult += AHEAD_ATTACK_MARGIN_BONUS\n    if is_behind:\n        attack_margin_mult -= BEHIND_ATTACK_MARGIN_PENALTY\n    if is_finishing:\n        attack_margin_mult += FINISHING_ATTACK_MARGIN_BONUS\n\n    return {\n        "domination": domination,\n        "is_behind": is_behind,\n        "is_ahead": is_ahead,\n        "is_prod_behind": is_prod_behind,\n        "is_four_player_leader_pressure": is_four_player_leader_pressure,\n        "is_snowball_risk": is_snowball_risk,\n        "is_dominating": is_dominating,\n        "is_finishing": is_finishing,\n        "attack_margin_mult": attack_margin_mult,\n    }\n\n\ndef strategy_profile(world):\n    return FOUR_PLAYER_STRATEGY if world.is_four_player else TWO_PLAYER_STRATEGY\n\n\ndef adaptive_partial_source_min(world, modes=None):\n    return strategy_profile(world)["partial_source_min"]\n\n\ndef adaptive_followup_min(world, modes=None):\n    return strategy_profile(world)["followup_min"]\n\n\ndef is_safe_neutral(target, policy):\n    if target.owner != -1:\n        return False\n    my_t, enemy_t = policy_reaction_times(target.id, policy)\n    return my_t <= enemy_t - SAFE_NEUTRAL_MARGIN\n\n\ndef is_contested_neutral(target, policy):\n    if target.owner != -1:\n        return False\n    my_t, enemy_t = policy_reaction_times(target.id, policy)\n    return abs(my_t - enemy_t) <= CONTESTED_NEUTRAL_MARGIN\n\n\ndef opening_high_prod_packet_floor(target, base_needed, world=None):\n    profile = strategy_profile(world) if world is not None else TWO_PLAYER_STRATEGY\n    return max(\n        profile["opening_high_prod_min_packet"],\n        int(base_needed) + int(target.production) * profile["opening_high_prod_packet_prod_weight"],\n    )\n\n\ndef opening_filter(target, arrival_turns, needed, src_available, world, policy, src=None):\n    if not world.is_opening:\n        return False\n    profile = strategy_profile(world)\n    if (\n        world.is_four_player\n        and src is not None\n        and world.step < 52\n        and target.production <= 2\n    ):\n        full_source = max(1, int(src.ships))\n        future_source = max(full_source, src_available + int(src.production) * 18)\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < 4:\n                continue\n            need_hint = int(candidate.ships) + 1\n            if need_hint > future_source:\n                continue\n            seeded = world.best_probe_aim(\n                src.id,\n                candidate.id,\n                max(1, min(future_source, max(src_available, need_hint))),\n                hints=(need_hint,),\n            )\n            if seeded is None:\n                continue\n            _, aim = seeded\n            if aim[1] > 36:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if enemy_t >= my_t - 4:\n                return True\n    if target.owner != -1:\n        return False\n    if target.id in world.comet_ids:\n        return False\n    if (\n        src is not None\n        and world.step < profile["opening_high_prod_turn"]\n        and target.production <= profile["opening_high_prod_low_target_max_prod"]\n    ):\n        future_budget = max(1, int(src.ships)) + int(src.production) * profile["opening_high_prod_future_turns"]\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < profile["opening_high_prod_min_prod"]:\n                continue\n            need_hint = int(candidate.ships) + 1\n            packet_floor = opening_high_prod_packet_floor(candidate, need_hint, world)\n            if min(packet_floor, need_hint) > future_budget:\n                continue\n            probe_cap = max(1, min(future_budget, max(src_available, packet_floor, need_hint)))\n            seeded = world.best_probe_aim(\n                src.id,\n                candidate.id,\n                probe_cap,\n                hints=(need_hint, min(packet_floor, probe_cap), probe_cap),\n            )\n            if seeded is None:\n                continue\n            _, aim = seeded\n            if aim[1] > profile["opening_high_prod_max_route_turns"]:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if enemy_t + profile["opening_high_prod_reaction_slack"] < my_t:\n                continue\n            return True\n    if (\n        src is not None\n        and not world.is_four_player\n        and world.step < HIGH_PROD_SOURCE_SAVE_TURN_LIMIT\n        and int(src.production) >= HIGH_PROD_SOURCE_MIN_PROD\n        and target.production <= HIGH_PROD_SAVE_LOW_TARGET_MAX_PROD\n    ):\n        future_budget = src_available + int(src.production) * HIGH_PROD_SAVE_LOOKAHEAD_TURNS\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < HIGH_PROD_SAVE_TARGET_MIN_PROD:\n                continue\n            if int(candidate.ships) + 1 > future_budget:\n                continue\n            seeded = world.best_probe_aim(\n                src.id,\n                candidate.id,\n                max(1, src_available),\n                hints=(max(1, src_available), int(candidate.ships) + 1),\n            )\n            if seeded is None:\n                continue\n            _, aim = seeded\n            if aim[1] > HIGH_PROD_SAVE_MAX_ROUTE_TURNS:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if enemy_t + 5 < my_t:\n                continue\n            return True\n    if (\n        not world.is_four_player\n        and world.step < 35\n        and world.my_prod <= 2\n        and target.production <= 1\n    ):\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < 4:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if my_t <= 34 and enemy_t >= my_t - 3:\n                return True\n    if (\n        world.is_four_player\n        and src is not None\n        and world.step < 55\n        and target.production <= 1\n    ):\n        full_source = max(1, int(src.ships))\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < 3:\n                continue\n            if int(candidate.ships) + 1 > full_source:\n                continue\n            seeded = world.best_probe_aim(\n                src.id,\n                candidate.id,\n                full_source,\n                hints=(int(candidate.ships) + 1,),\n            )\n            if seeded is None:\n                continue\n            _, aim = seeded\n            if aim[1] > 34:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if enemy_t >= my_t - 3:\n                return True\n    if (\n        world.is_four_player\n        and src is not None\n        and world.step < 32\n        and target.production <= 3\n    ):\n        full_source = max(1, int(src.ships))\n        future_source = full_source + int(src.production) * 4\n        for candidate in world.neutral_planets:\n            if candidate.id == target.id or candidate.id in world.comet_ids:\n                continue\n            if candidate.production < 5:\n                continue\n            need_hint = int(candidate.ships) + 1\n            if need_hint > future_source:\n                continue\n            aim = world.plan_shot(src.id, candidate.id, min(future_source, need_hint))\n            if aim is None:\n                continue\n            if aim[1] > 30:\n                continue\n            my_t, enemy_t = policy_reaction_times(candidate.id, policy)\n            if enemy_t >= my_t - 4:\n                return True\n    if world.is_static(target.id):\n        return False\n\n    my_t, enemy_t = policy_reaction_times(target.id, policy)\n    reaction_gap = enemy_t - my_t\n    if (\n        target.production >= SAFE_OPENING_PROD_THRESHOLD\n        and arrival_turns <= SAFE_OPENING_TURN_LIMIT\n        and reaction_gap >= SAFE_NEUTRAL_MARGIN\n    ):\n        return False\n\n    if world.is_four_player:\n        affordable = needed <= max(\n            adaptive_partial_source_min(world),\n            int(src_available * FOUR_PLAYER_ROTATING_SEND_RATIO),\n        )\n        if (\n            affordable\n            and arrival_turns <= FOUR_PLAYER_ROTATING_TURN_LIMIT\n            and reaction_gap >= FOUR_PLAYER_ROTATING_REACTION_GAP\n        ):\n            return False\n        return True\n\n    return arrival_turns > ROTATING_OPENING_MAX_TURNS or target.production <= ROTATING_OPENING_LOW_PROD\n\n\ndef target_value(target, arrival_turns, mission, world, modes, policy):\n    turns_profit = max(1, world.remaining_steps - arrival_turns)\n    if target.id in world.comet_ids:\n        life = world.comet_life(target.id)\n        turns_profit = max(0, min(turns_profit, life - arrival_turns))\n        if turns_profit <= 0:\n            return -1.0\n\n    value = target.production * turns_profit\n    value += policy["indirect_wealth_map"][target.id] * turns_profit * INDIRECT_VALUE_SCALE\n\n    if world.is_static(target.id):\n        value *= STATIC_NEUTRAL_VALUE_MULT if target.owner == -1 else STATIC_HOSTILE_VALUE_MULT\n    else:\n        value *= ROTATING_OPENING_VALUE_MULT if world.is_opening else 1.0\n\n    if target.owner not in (-1, world.player):\n        value *= OPENING_HOSTILE_TARGET_VALUE_MULT if world.is_opening else HOSTILE_TARGET_VALUE_MULT\n\n    if target.owner == -1:\n        if is_safe_neutral(target, policy):\n            value *= SAFE_NEUTRAL_VALUE_MULT\n        elif is_contested_neutral(target, policy):\n            value *= CONTESTED_NEUTRAL_VALUE_MULT\n        if world.is_early:\n            value *= EARLY_NEUTRAL_VALUE_MULT\n        if world.is_four_player and world.is_opening:\n            if target.production >= 4:\n                value *= FOUR_PLAYER_HIGH_PROD_NEUTRAL_VALUE_MULT\n            elif target.production <= 1:\n                value *= FOUR_PLAYER_LOW_PROD_OPENING_VALUE_MULT\n\n    if target.id in world.comet_ids:\n        value *= COMET_VALUE_MULT\n\n    if mission == "snipe":\n        value *= SNIPE_VALUE_MULT\n    elif mission == "swarm":\n        value *= SWARM_VALUE_MULT\n    elif mission == "reinforce":\n        value *= REINFORCE_VALUE_MULT\n    elif mission == "crash_exploit":\n        value *= CRASH_EXPLOIT_VALUE_MULT\n\n    if target.id in world.exposed_planet_ids:\n        value *= EXPOSED_PLANET_VALUE_MULT\n\n    if world.is_late:\n        value += max(0, target.ships) * LATE_IMMEDIATE_SHIP_VALUE\n\n    # Elimination bonus — applies whenever enemy is weak (not just late game)\n    if target.owner not in (-1, world.player):\n        enemy_strength = world.owner_strength.get(target.owner, 0)\n        if enemy_strength <= WEAK_ENEMY_THRESHOLD:\n            value += ELIMINATION_BONUS\n\n    # Weakest enemy targeting bonus (key for 4P strategy)\n    if target.owner not in (-1, world.player) and world._weakest_enemy is not None:\n        if target.owner == world._weakest_enemy:\n            if not (\n                world.is_four_player\n                and modes.get("is_four_player_leader_pressure")\n                and target.owner != world._leader_enemy\n            ):\n                mult = WEAKEST_ENEMY_VALUE_MULT_4P if world.is_four_player else WEAKEST_ENEMY_VALUE_MULT_2P\n                value *= mult\n    if world.is_four_player and target.owner not in (-1, world.player):\n        if target.owner == world._leader_enemy:\n            if modes.get("is_four_player_leader_pressure") or target.production >= 4:\n                value *= FOUR_PLAYER_LEADER_TARGET_VALUE_MULT\n        elif modes.get("is_four_player_leader_pressure") and target.production <= 1:\n            value *= FOUR_PLAYER_LOW_PROD_HOSTILE_VALUE_MULT\n\n    if modes["is_finishing"] and target.owner not in (-1, world.player):\n        value *= FINISHING_HOSTILE_VALUE_MULT\n    if modes["is_snowball_risk"]:\n        if target.owner not in (-1, world.player):\n            value *= 1.35\n        elif target.owner == -1 and target.production >= 4:\n            value *= 1.12\n        elif target.owner == -1 and target.production <= 2:\n            value *= 0.78\n    if modes["is_behind"] and target.owner == -1 and not world.is_static(target.id):\n        value *= BEHIND_ROTATING_NEUTRAL_VALUE_MULT\n    if modes["is_behind"] and target.owner == -1 and is_safe_neutral(target, policy):\n        value *= 1.08\n    if modes["is_dominating"] and target.owner == -1 and is_contested_neutral(target, policy):\n        value *= 0.92\n\n    return value\n\n\ndef reinforce_value(target, hold_until, world, policy):\n    saved_turns = max(1, world.remaining_steps - hold_until)\n    value = target.production * saved_turns + max(0, target.ships) * DEFENSE_SHIP_VALUE\n    if world.enemy_planets and nearest_distance_to_set(target.x, target.y, world.enemy_planets) < 22:\n        value *= DEFENSE_FRONTIER_SCORE_MULT\n    value += policy["indirect_wealth_map"][target.id] * saved_turns * INDIRECT_VALUE_SCALE * 0.35\n    return value * REINFORCE_VALUE_MULT\n\n\ndef preferred_send(target, base_needed, arrival_turns, src_available, world, modes, policy):\n    profile = strategy_profile(world)\n    send = max(base_needed, int(math.ceil(base_needed * modes["attack_margin_mult"])))\n    margin = 0\n    if target.owner == -1:\n        margin += min(\n            NEUTRAL_MARGIN_CAP,\n            NEUTRAL_MARGIN_BASE + target.production * NEUTRAL_MARGIN_PROD_WEIGHT,\n        )\n    else:\n        margin += min(\n            HOSTILE_MARGIN_CAP,\n            HOSTILE_MARGIN_BASE + target.production * HOSTILE_MARGIN_PROD_WEIGHT,\n        )\n    if world.is_static(target.id):\n        margin += STATIC_TARGET_MARGIN\n    if is_contested_neutral(target, policy):\n        margin += CONTESTED_TARGET_MARGIN\n    if world.is_four_player:\n        margin += FOUR_PLAYER_TARGET_MARGIN\n    if arrival_turns > LONG_TRAVEL_MARGIN_START:\n        margin += min(LONG_TRAVEL_MARGIN_CAP, arrival_turns // LONG_TRAVEL_MARGIN_DIVISOR)\n    if target.id in world.comet_ids:\n        margin = max(0, margin - COMET_MARGIN_RELIEF)\n    if modes["is_finishing"] and target.owner not in (-1, world.player):\n        margin += FINISHING_HOSTILE_SEND_BONUS\n    if modes["is_snowball_risk"]:\n        if target.owner == -1 and target.production <= 2:\n            margin = max(0, margin - 3)\n        elif target.owner not in (-1, world.player):\n            margin = max(0, margin - 1)\n    if target.id in world.exposed_planet_ids:\n        margin = max(0, margin - 2)\n    # In 4P, be more efficient when targeting weakest enemy (finishing blow)\n    if world.is_four_player and world._weakest_enemy is not None and target.owner == world._weakest_enemy:\n        margin = max(0, margin - 2)\n    if (\n        world.is_four_player\n        and modes.get("is_four_player_leader_pressure")\n        and target.owner == world._leader_enemy\n    ):\n        margin = max(0, margin - 1)\n    preferred = send + margin\n    if (\n        world.step < profile["opening_high_prod_turn"]\n        and target.owner == -1\n        and target.id not in world.comet_ids\n        and target.production >= profile["opening_high_prod_min_prod"]\n        and src_available >= profile["opening_high_prod_min_packet"]\n    ):\n        preferred = max(preferred, opening_high_prod_packet_floor(target, base_needed, world))\n    return min(src_available, preferred)\n\n\ndef four_player_packet_floor(world, target, mission_kind, needed, modes):\n    if (\n        not world.is_four_player\n        or world.step < FOUR_PLAYER_PACKET_AGGREGATION_TURN\n        or world.is_late\n        or mission_kind in ("rescue", "reinforce", "snipe", "crash_exploit")\n    ):\n        return 1\n\n    floor = FOUR_PLAYER_PACKET_NEUTRAL_FLOOR\n    if target.owner == -1 and target.production >= 4:\n        floor = FOUR_PLAYER_PACKET_HIGH_PROD_NEUTRAL_FLOOR\n    elif target.owner not in (-1, world.player):\n        floor = FOUR_PLAYER_PACKET_ENEMY_FLOOR\n        if target.production >= 4:\n            floor += FOUR_PLAYER_PACKET_HIGH_PROD_BONUS\n        if target.owner == world._leader_enemy or modes.get("is_four_player_leader_pressure"):\n            floor += FOUR_PLAYER_PACKET_LEADER_BONUS\n\n    if modes.get("is_finishing"):\n        floor = max(1, floor - 8)\n    return max(1, min(int(floor), max(int(needed), int(floor))))\n\n\ndef four_player_packet_allowed(world, target, mission_kind, needed, send, modes):\n    floor = four_player_packet_floor(world, target, mission_kind, needed, modes)\n    return send >= max(needed, floor)\n\n\ndef apply_score_modifiers(base_score, target, mission, world):\n    score = base_score\n    if world.is_static(target.id):\n        score *= STATIC_TARGET_SCORE_MULT\n    if world.is_early and target.owner == -1 and world.is_static(target.id):\n        score *= EARLY_STATIC_NEUTRAL_SCORE_MULT\n    if world.is_four_player and target.owner == -1 and not world.is_static(target.id):\n        score *= FOUR_PLAYER_ROTATING_NEUTRAL_SCORE_MULT\n    if (\n        len(world.static_neutral_planets) >= DENSE_STATIC_NEUTRAL_COUNT\n        and target.owner == -1\n        and not world.is_static(target.id)\n    ):\n        score *= DENSE_ROTATING_NEUTRAL_SCORE_MULT\n    if mission == "snipe":\n        score *= SNIPE_SCORE_MULT\n    elif mission == "swarm":\n        score *= SWARM_SCORE_MULT\n    elif mission == "crash_exploit":\n        score *= CRASH_EXPLOIT_SCORE_MULT\n    if target.id in world.exposed_planet_ids:\n        score *= 1.25\n    if target.owner not in (-1, world.player):\n        # When production is slipping away, every viable enemy capture also\n        # denies future production to the leader.\n        # `world` modes are not available here, so use the raw production gap.\n        if not world.is_four_player and world.step >= 35 and world.max_enemy_prod >= world.my_prod + 7:\n            score *= 1.12\n        if world.is_four_player and target.owner == world._leader_enemy:\n            leader_gap = world.max_enemy_prod - world.my_prod\n            if (\n                target.production >= 4\n                or (\n                    world.step >= 35\n                    and leader_gap >= FOUR_PLAYER_LEADER_PRESSURE_MIN_GAP\n                    and world.max_enemy_prod >= world.my_prod * FOUR_PLAYER_LEADER_PRESSURE_RATIO\n                )\n            ):\n                score *= FOUR_PLAYER_LEADER_SCORE_MULT\n    elif (\n        target.owner == -1\n        and not world.is_four_player\n        and world.step >= 35\n        and world.max_enemy_prod >= world.my_prod + 7\n        and target.production <= 2\n    ):\n        score *= 0.9\n    # Bonus score for targeting weakest enemy planet\n    if target.owner not in (-1, world.player) and world._weakest_enemy == target.owner:\n        leader_gap = world.max_enemy_prod - world.my_prod\n        if not (\n            world.is_four_player\n            and target.owner != world._leader_enemy\n            and world.step >= 35\n            and leader_gap >= FOUR_PLAYER_LEADER_PRESSURE_MIN_GAP\n        ):\n            score *= 1.2\n    return score\n\n\ndef settle_plan(\n    src,\n    target,\n    src_cap,\n    send_guess,\n    world,\n    planned_commitments,\n    modes,\n    policy,\n    mission="capture",\n    eval_turn_fn=None,\n    anchor_turn=None,\n    anchor_tolerance=None,\n    max_iter=4,\n):\n    if src_cap < 1:\n        return None\n\n    seed_hint = max(1, min(src_cap, int(send_guess)))\n    eval_turn_fn = eval_turn_fn or (lambda turns: turns)\n    anchor_tolerance = (\n        anchor_tolerance\n        if anchor_tolerance is not None\n        else (1 if mission == "snipe" else None)\n    )\n    tested = {}\n    tested_order = []\n\n    def evaluate(send):\n        send = max(1, min(src_cap, int(send)))\n        cached = tested.get(send)\n        if cached is not None or send in tested:\n            return cached\n\n        aim = world.plan_shot(src.id, target.id, send)\n        if aim is None:\n            tested[send] = None\n            return None\n\n        angle, turns, _, _ = aim\n        if mission == "crash_exploit" and anchor_turn is not None and turns < anchor_turn:\n            tested[send] = None\n            return None\n        raw_eval_turn = int(math.ceil(eval_turn_fn(turns)))\n        if raw_eval_turn < turns:\n            tested[send] = None\n            return None\n        eval_turn = raw_eval_turn\n        need = world.min_ships_to_own_by(\n            target.id,\n            eval_turn,\n            world.player,\n            arrival_turn=turns,\n            planned_commitments=planned_commitments,\n            upper_bound=src_cap,\n        )\n        if need <= 0 or need > src_cap:\n            tested[send] = None\n            return None\n\n        if mission in ("snipe", "crash_exploit"):\n            desired = need\n        elif mission == "rescue":\n            desired = min(\n                src_cap,\n                max(\n                    need,\n                    need + DEFENSE_SEND_MARGIN_BASE + target.production * DEFENSE_SEND_MARGIN_PROD_WEIGHT,\n                ),\n            )\n        else:\n            desired = min(\n                src_cap,\n                max(need, preferred_send(target, need, turns, src_cap, world, modes, policy)),\n            )\n\n        result = (angle, turns, eval_turn, need, send, desired)\n        tested[send] = result\n        tested_order.append(send)\n        return result\n\n    initial_candidates = sorted(\n        world.probe_ship_candidates(src.id, target.id, src_cap, hints=(seed_hint,)),\n        key=lambda send: (abs(send - seed_hint), send),\n    )\n\n    current_send = None\n    for seed in initial_candidates:\n        result = evaluate(seed)\n        if result is None:\n            continue\n        if (\n            anchor_turn is not None\n            and anchor_tolerance is not None\n            and abs(result[1] - anchor_turn) > anchor_tolerance\n        ):\n            continue\n        current_send = seed\n        break\n\n    if current_send is None:\n        return None\n\n    for _ in range(max_iter):\n        result = evaluate(current_send)\n        if result is None:\n            break\n\n        angle, turns, eval_turn, need, actual_send, desired = result\n        if desired == actual_send:\n            if (\n                anchor_turn is not None\n                and anchor_tolerance is not None\n                and abs(turns - anchor_turn) > anchor_tolerance\n            ):\n                return None\n            if mission == "rescue" and turns > eval_turn:\n                return None\n            return angle, turns, eval_turn, need, actual_send\n\n        next_send = max(1, min(src_cap, int(desired)))\n        if next_send in tested:\n            current_send = next_send\n            break\n        current_send = next_send\n\n    candidate_sends = sorted(\n        [send for send in tested_order if tested.get(send) is not None],\n        key=lambda send: (\n            0 if mission != "snipe" or anchor_turn is None else abs(tested[send][1] - anchor_turn),\n            abs(send - seed_hint),\n            tested[send][1],\n            send,\n        ),\n    )\n\n    seen = set()\n    for send in candidate_sends:\n        if send in seen:\n            continue\n        seen.add(send)\n        result = tested.get(send)\n        if result is None:\n            continue\n        angle, turns, eval_turn, need, actual_send, _ = result\n        if actual_send < need:\n            continue\n        if (\n            anchor_turn is not None\n            and anchor_tolerance is not None\n            and abs(turns - anchor_turn) > anchor_tolerance\n        ):\n            continue\n        if mission == "rescue" and turns > eval_turn:\n            continue\n        return angle, turns, eval_turn, need, actual_send\n\n    return None\n\n\ndef settle_reinforce_plan(\n    src,\n    target,\n    src_cap,\n    send_guess,\n    world,\n    planned_commitments,\n    hold_until,\n    max_arrival_turn,\n    max_iter=4,\n):\n    if src_cap < 1:\n        return None\n\n    seed_hint = max(1, min(src_cap, int(send_guess)))\n    tested = {}\n    tested_order = []\n\n    def evaluate(send):\n        send = max(1, min(src_cap, int(send)))\n        cached = tested.get(send)\n        if cached is not None or send in tested:\n            return cached\n\n        aim = world.plan_shot(src.id, target.id, send)\n        if aim is None:\n            tested[send] = None\n            return None\n\n        angle, turns, _, _ = aim\n        if turns > max_arrival_turn:\n            tested[send] = None\n            return None\n\n        need = world.reinforcement_needed_to_hold_until(\n            target.id,\n            turns,\n            hold_until,\n            planned_commitments=planned_commitments,\n            upper_bound=src_cap,\n        )\n        if need <= 0 or need > src_cap:\n            tested[send] = None\n            return None\n\n        desired = min(src_cap, need + REINFORCE_SAFETY_MARGIN)\n        result = (angle, turns, hold_until, need, send, desired)\n        tested[send] = result\n        tested_order.append(send)\n        return result\n\n    initial_candidates = sorted(\n        world.probe_ship_candidates(src.id, target.id, src_cap, hints=(seed_hint,)),\n        key=lambda send: (abs(send - seed_hint), send),\n    )\n\n    current_send = None\n    for seed in initial_candidates:\n        result = evaluate(seed)\n        if result is None:\n            continue\n        current_send = seed\n        break\n\n    if current_send is None:\n        return None\n\n    for _ in range(max_iter):\n        result = evaluate(current_send)\n        if result is None:\n            break\n\n        angle, turns, eval_turn, need, actual_send, desired = result\n        if desired == actual_send:\n            return angle, turns, eval_turn, need, actual_send\n\n        next_send = max(1, min(src_cap, int(desired)))\n        if next_send in tested:\n            current_send = next_send\n            break\n        current_send = next_send\n\n    candidate_sends = sorted(\n        [send for send in tested_order if tested.get(send) is not None],\n        key=lambda send: (abs(send - seed_hint), tested[send][1], send),\n    )\n    for send in candidate_sends:\n        result = tested.get(send)\n        if result is None:\n            continue\n        angle, turns, eval_turn, need, actual_send, _ = result\n        if actual_send < need or turns > max_arrival_turn:\n            continue\n        return angle, turns, eval_turn, need, actual_send\n\n    return None\n\n\ndef build_snipe_mission(src, target, src_available, world, planned_commitments, modes, policy):\n    if target.owner != -1:\n        return None\n\n    enemy_etas = sorted({\n        int(math.ceil(eta))\n        for eta, owner, ships in world.arrivals_by_planet.get(target.id, [])\n        if owner not in (-1, world.player) and ships > 0\n    })\n    if not enemy_etas:\n        return None\n\n    best = None\n    for enemy_eta in enemy_etas[:3]:\n        seeded = world.best_probe_aim(\n            src.id,\n            target.id,\n            src_available,\n            hints=(int(target.ships) + 1, int(target.ships) + 8),\n            anchor_turn=enemy_eta,\n            max_anchor_diff=1,\n        )\n        if seeded is None:\n            continue\n\n        probe, rough = seeded\n        sync_turn = max(rough[1], enemy_eta)\n        if target.id in world.comet_ids:\n            life = world.comet_life(target.id)\n            if sync_turn >= life or sync_turn > COMET_MAX_CHASE_TURNS:\n                continue\n\n        plan = settle_plan(\n            src,\n            target,\n            src_available,\n            probe,\n            world,\n            planned_commitments,\n            modes,\n            policy,\n            mission="snipe",\n            eval_turn_fn=lambda turns, enemy_eta=enemy_eta: max(turns, enemy_eta),\n            anchor_turn=enemy_eta,\n        )\n        if plan is None:\n            continue\n\n        angle, turns, sync_turn, need, send_pref = plan\n        if target.id in world.comet_ids:\n            life = world.comet_life(target.id)\n            if sync_turn >= life or sync_turn > COMET_MAX_CHASE_TURNS:\n                continue\n\n        value = target_value(target, sync_turn, "snipe", world, modes, policy)\n        if value <= 0:\n            continue\n\n        score = apply_score_modifiers(\n            value / (send_pref + sync_turn * SNIPE_COST_TURN_WEIGHT + 1.0),\n            target,\n            "snipe",\n            world,\n        )\n        option = ShotOption(\n            score=score,\n            src_id=src.id,\n            target_id=target.id,\n            angle=angle,\n            turns=turns,\n            needed=need,\n            send_cap=send_pref,\n            mission="snipe",\n            anchor_turn=enemy_eta,\n        )\n        mission_obj = Mission(\n            kind="snipe",\n            score=score,\n            target_id=target.id,\n            turns=sync_turn,\n            options=[option],\n        )\n        if best is None or mission_obj.score > best.score:\n            best = mission_obj\n\n    return best\n\n\ndef build_rescue_missions(world, policy, planned_commitments, modes):\n    missions = []\n\n    for target in world.my_planets:\n        fall_turn = world.fall_turn_map.get(target.id)\n        if fall_turn is None or fall_turn > DEFENSE_LOOKAHEAD_TURNS:\n            continue\n\n        for src in world.my_planets:\n            if src.id == target.id:\n                continue\n\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < adaptive_partial_source_min(world, modes):\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(target.production + DEFENSE_SEND_MARGIN_BASE + 2,),\n                max_turn=fall_turn,\n            )\n            if seeded is None:\n                continue\n            probe, probe_aim = seeded\n            plan = settle_plan(\n                src,\n                target,\n                src_available,\n                probe,\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="rescue",\n                eval_turn_fn=lambda _turns, fall_turn=fall_turn: fall_turn,\n                anchor_turn=fall_turn,\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            saved_turns = max(1, world.remaining_steps - fall_turn)\n            value = target.production * saved_turns + max(0, target.ships) * DEFENSE_SHIP_VALUE\n            if world.enemy_planets and nearest_distance_to_set(target.x, target.y, world.enemy_planets) < 22:\n                value *= DEFENSE_FRONTIER_SCORE_MULT\n            score = value / (send_pref + turns * DEFENSE_COST_TURN_WEIGHT + 1.0)\n\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="rescue",\n                anchor_turn=fall_turn,\n            )\n            missions.append(Mission(\n                kind="rescue",\n                score=score,\n                target_id=target.id,\n                turns=fall_turn,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_recapture_missions(world, policy, planned_commitments, modes):\n    missions = []\n\n    for target in world.my_planets:\n        fall_turn = world.fall_turn_map.get(target.id)\n        if fall_turn is None or fall_turn > DEFENSE_LOOKAHEAD_TURNS:\n            continue\n\n        for src in world.my_planets:\n            if src.id == target.id:\n                continue\n\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < adaptive_partial_source_min(world, modes):\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(target.production + DEFENSE_SEND_MARGIN_BASE + 2,),\n                min_turn=fall_turn + 1,\n                max_turn=fall_turn + RECAPTURE_LOOKAHEAD_TURNS,\n            )\n            if seeded is None:\n                continue\n            probe, probe_aim = seeded\n            probe_turns = probe_aim[1]\n\n            plan = settle_plan(\n                src,\n                target,\n                src_available,\n                probe,\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="capture",\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            if turns <= fall_turn or turns - fall_turn > RECAPTURE_LOOKAHEAD_TURNS:\n                continue\n\n            saved_turns = max(1, world.remaining_steps - turns)\n            value = (\n                RECAPTURE_PRODUCTION_WEIGHT * target.production * saved_turns\n                + RECAPTURE_IMMEDIATE_WEIGHT * max(0, target.ships)\n            )\n            if world.enemy_planets and nearest_distance_to_set(target.x, target.y, world.enemy_planets) < 22:\n                value *= RECAPTURE_FRONTIER_MULT\n            value *= RECAPTURE_VALUE_MULT\n            score = value / (send_pref + turns * RECAPTURE_COST_TURN_WEIGHT + 1.0)\n\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="recapture",\n                anchor_turn=fall_turn,\n            )\n            missions.append(Mission(\n                kind="recapture",\n                score=score,\n                target_id=target.id,\n                turns=turns,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_reinforce_missions(world, policy, planned_commitments, modes, inventory_left_fn):\n    if not REINFORCE_ENABLED:\n        return []\n\n    missions = []\n    if world.remaining_steps < REINFORCE_MIN_FUTURE_TURNS:\n        return missions\n\n    for target in world.my_planets:\n        fall_turn = world.fall_turn_map.get(target.id)\n        if fall_turn is None:\n            continue\n        if target.production < REINFORCE_MIN_PRODUCTION:\n            continue\n\n        hold_until = min(HORIZON, fall_turn + REINFORCE_HOLD_LOOKAHEAD)\n        max_arrival_turn = min(fall_turn, REINFORCE_MAX_TRAVEL_TURNS)\n\n        for src in world.my_planets:\n            if src.id == target.id:\n                continue\n\n            budget = inventory_left_fn(src.id)\n            source_cap = min(budget, int(src.ships * REINFORCE_MAX_SOURCE_FRACTION))\n            if source_cap < adaptive_partial_source_min(world, modes):\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                source_cap,\n                hints=(target.production + REINFORCE_SAFETY_MARGIN + 2,),\n                max_turn=max_arrival_turn,\n            )\n            if seeded is None:\n                continue\n            probe, _ = seeded\n\n            plan = settle_reinforce_plan(\n                src,\n                target,\n                source_cap,\n                probe,\n                world,\n                planned_commitments,\n                hold_until,\n                max_arrival_turn,\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            value = reinforce_value(target, hold_until, world, policy)\n            score = value / (send_pref + turns * REINFORCE_COST_TURN_WEIGHT + 1.0)\n\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="reinforce",\n                anchor_turn=hold_until,\n            )\n            missions.append(Mission(\n                kind="reinforce",\n                score=score,\n                target_id=target.id,\n                turns=fall_turn,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_crash_exploit_missions(world, policy, planned_commitments, modes):\n    if not CRASH_EXPLOIT_ENABLED or not world.is_four_player:\n        return []\n\n    missions = []\n    for crash in detect_enemy_crashes(world):\n        target = world.planet_by_id[crash["target_id"]]\n        if target.owner == world.player:\n            continue\n        desired_arrival = crash["crash_turn"] + CRASH_EXPLOIT_POST_CRASH_DELAY\n\n        for src in world.my_planets:\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < adaptive_partial_source_min(world, modes):\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(12, int(target.ships) + 1),\n                anchor_turn=desired_arrival,\n                max_anchor_diff=CRASH_EXPLOIT_ETA_WINDOW,\n            )\n            if seeded is None:\n                continue\n            probe, _ = seeded\n\n            plan = settle_plan(\n                src,\n                target,\n                src_available,\n                probe,\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="crash_exploit",\n                eval_turn_fn=lambda turns, desired_arrival=desired_arrival: max(turns, desired_arrival),\n                anchor_turn=desired_arrival,\n                anchor_tolerance=CRASH_EXPLOIT_ETA_WINDOW,\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            if not candidate_time_valid(target, turns, world, LATE_CAPTURE_BUFFER):\n                continue\n            value = target_value(target, turns, "crash_exploit", world, modes, policy)\n            if value <= 0:\n                continue\n\n            score = apply_score_modifiers(\n                value / (send_pref + turns * SNIPE_COST_TURN_WEIGHT + 1.0),\n                target,\n                "crash_exploit",\n                world,\n            )\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="crash_exploit",\n                anchor_turn=desired_arrival,\n            )\n            missions.append(Mission(\n                kind="crash_exploit",\n                score=score,\n                target_id=target.id,\n                turns=turns,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_gang_up_missions(world, policy, planned_commitments, modes):\n    """\n    Attack enemy planets that will be weakened by inter-enemy combat.\n    Schedule our fleet to arrive shortly after the battle resolves.\n    This is the key 4P tactic: use enemies fighting each other to our advantage.\n    """\n    missions = []\n\n    for battle in detect_enemy_planet_battles(world):\n        target = world.planet_by_id[battle["target_id"]]\n        if target.owner == world.player:\n            continue\n\n        # Arrive a couple turns after the battle to clean up\n        desired_arrival = battle["battle_turn"] + GANG_UP_POST_BATTLE_DELAY\n\n        for src in world.my_planets:\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < adaptive_partial_source_min(world, modes):\n                continue\n\n            # Hint: need just slightly more than estimated post-battle ships\n            post_hint = max(3, int(battle["post_ships"]) + 3)\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(post_hint, int(target.ships) + 1),\n                anchor_turn=desired_arrival,\n                max_anchor_diff=GANG_UP_ETA_WINDOW,\n            )\n            if seeded is None:\n                continue\n            probe, _ = seeded\n\n            plan = settle_plan(\n                src,\n                target,\n                src_available,\n                probe,\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="capture",\n                eval_turn_fn=lambda turns, da=desired_arrival: max(turns, da),\n                anchor_turn=desired_arrival,\n                anchor_tolerance=GANG_UP_ETA_WINDOW,\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            if not candidate_time_valid(target, turns, world, LATE_CAPTURE_BUFFER):\n                continue\n\n            value = target_value(target, turns, "capture", world, modes, policy)\n            value *= GANG_UP_VALUE_MULT  # extra bonus for exploiting enemy fight\n            if value <= 0:\n                continue\n\n            score = apply_score_modifiers(\n                value / (send_pref + turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                target,\n                "capture",\n                world,\n            )\n\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=send_pref,\n                mission="capture",\n                anchor_turn=desired_arrival,\n            )\n            missions.append(Mission(\n                kind="single",\n                score=score,\n                target_id=target.id,\n                turns=turns,\n                options=[option],\n            ))\n\n    return missions\n\n\ndef build_pressure_packet_missions(world, policy, planned_commitments, modes):\n    if not PRESSURE_PACKET_ENABLED:\n        return []\n    profile = strategy_profile(world)\n    if world.step < PRESSURE_PACKET_TURN or world.remaining_steps < PRESSURE_PACKET_STOP_REMAINING:\n        return []\n    if world.my_prod < profile["pressure_packet_min_my_prod"]:\n        return []\n    if not world.enemy_planets:\n        return []\n\n    missions = []\n    target_pool = [\n        target\n        for target in world.enemy_planets\n        if target.id not in world.comet_ids and target.production >= 2\n    ]\n    if not target_pool:\n        return missions\n\n    for src in world.my_planets:\n        src_available = policy["attack_budget"].get(src.id, 0)\n        if src_available < PRESSURE_PACKET_MIN_LEFT:\n            continue\n\n        ratio = profile["pressure_packet_base_ratio"]\n        if modes.get("is_behind") or modes.get("is_four_player_leader_pressure"):\n            ratio = profile["pressure_packet_behind_ratio"]\n        send_cap = min(\n            PRESSURE_PACKET_MAX_SEND,\n            src_available,\n            max(profile["pressure_packet_min_send"], int(src_available * ratio)),\n        )\n        if send_cap < profile["pressure_packet_min_send"]:\n            continue\n\n        best = None\n        for target in target_pool:\n            aim = world.plan_shot(src.id, target.id, send_cap)\n            if aim is None:\n                continue\n            angle, turns, _, _ = aim\n            if turns > PRESSURE_PACKET_MAX_TURNS:\n                continue\n            if not candidate_time_valid(target, turns, world, LATE_CAPTURE_BUFFER):\n                continue\n\n            need = world.min_ships_to_own_at(\n                target.id,\n                turns,\n                world.player,\n                planned_commitments=planned_commitments,\n                upper_bound=send_cap,\n            )\n            if need <= 0 or need > send_cap:\n                continue\n\n            desired = send_cap\n            overkill_cap = int(max(need + PRESSURE_PACKET_HIGH_PROD_BONUS, need * PRESSURE_PACKET_OVERKILL_CAP))\n            desired = min(desired, max(profile["pressure_packet_min_send"], overkill_cap))\n            if desired < need:\n                continue\n            if desired != send_cap:\n                aim = world.plan_shot(src.id, target.id, desired)\n                if aim is None:\n                    continue\n                angle, turns, _, _ = aim\n                if turns > PRESSURE_PACKET_MAX_TURNS:\n                    continue\n                need = world.min_ships_to_own_at(\n                    target.id,\n                    turns,\n                    world.player,\n                    planned_commitments=planned_commitments,\n                    upper_bound=desired,\n                )\n                if need <= 0 or need > desired:\n                    continue\n\n            if desired >= 64 and not shot_hits_intended_target(\n                src,\n                target,\n                angle,\n                desired,\n                world.planets,\n                world.initial_by_id,\n                world.ang_vel,\n                world.comets,\n                world.comet_ids,\n                max_turns=min(PRESSURE_PACKET_MAX_TURNS + 2, turns + 3),\n            ):\n                continue\n\n            value = target_value(target, turns, "capture", world, modes, policy)\n            if value <= 0:\n                continue\n            if target.production >= 4:\n                value *= 1.18\n            if world.is_four_player and target.owner == world._leader_enemy:\n                value *= PRESSURE_PACKET_LEADER_MULT\n            if world.enemy_planets and nearest_distance_to_set(target.x, target.y, world.my_planets) < 24:\n                value *= PRESSURE_PACKET_FRONTIER_MULT\n\n            score = apply_score_modifiers(\n                value / (max(1, need) + turns * 0.30 + 1.0),\n                target,\n                "capture",\n                world,\n            )\n            score *= 1.18\n            option = ShotOption(\n                score=score,\n                src_id=src.id,\n                target_id=target.id,\n                angle=angle,\n                turns=turns,\n                needed=need,\n                send_cap=desired,\n                mission="pressure_packet",\n            )\n            mission = Mission(\n                kind="pressure_packet",\n                score=score,\n                target_id=target.id,\n                turns=turns,\n                options=[option],\n            )\n            if best is None or mission.score > best.score:\n                best = mission\n\n        if best is not None:\n            missions.append(best)\n\n    return missions\n\n\ndef build_elimination_missions(world, policy, planned_commitments, modes):\n    """\n    Dedicated missions to eliminate the weakest enemy entirely.\n    High priority in 4P — removing a player is a massive advantage.\n    Only activates when we have a clear strength advantage over the target.\n    """\n    if world._weakest_enemy is None:\n        return []\n\n    weakest = world._weakest_enemy\n    weakest_total = world._weakest_enemy_strength\n\n    # Only pursue if we\'re meaningfully stronger than the target\n    if weakest_total > world.my_total * 0.9:\n        return []\n\n    # Must be clearly the weakest (not just slightly weaker than someone else)\n    other_enemies = [\n        s for owner, s in world.owner_strength.items()\n        if owner not in (world.player, weakest)\n    ]\n    if other_enemies and weakest_total > min(other_enemies) * 0.95:\n        return []\n\n    weakest_planets = [p for p in world.enemy_planets if p.owner == weakest]\n    if not weakest_planets:\n        return []\n\n    missions = []\n    elimination_bonus_mult = 1.5 if world.is_four_player else 1.25\n\n    for target in weakest_planets:\n        for src in world.my_planets:\n            src_available = policy["attack_budget"].get(src.id, 0)\n            if src_available < adaptive_partial_source_min(world, modes):\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(int(target.ships) + 1, int(target.ships) + 5),\n            )\n            if seeded is None:\n                continue\n            probe, rough_aim = seeded\n            rough_turns = rough_aim[1]\n\n            if not candidate_time_valid(target, rough_turns, world, LATE_CAPTURE_BUFFER):\n                continue\n\n            global_needed = world.min_ships_to_own_at(\n                target.id, rough_turns, world.player,\n                planned_commitments=planned_commitments,\n            )\n            if global_needed <= 0 or global_needed > src_available:\n                continue\n\n            send_guess = preferred_send(target, global_needed, rough_turns, src_available, world, modes, policy)\n            plan = settle_plan(\n                src, target, src_available, send_guess,\n                world, planned_commitments, modes, policy,\n                mission="capture",\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send_pref = plan\n            if not candidate_time_valid(target, turns, world, LATE_CAPTURE_BUFFER):\n                continue\n            if send_pref < need:\n                continue\n\n            value = target_value(target, turns, "capture", world, modes, policy)\n            if value <= 0:\n                continue\n\n            score = apply_score_modifiers(\n                value * elimination_bonus_mult / (send_pref + turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                target, "capture", world,\n            )\n\n            option = ShotOption(\n                score=score, src_id=src.id, target_id=target.id,\n                angle=angle, turns=turns, needed=need, send_cap=send_pref,\n                mission="capture",\n            )\n            missions.append(Mission(\n                kind="single", score=score, target_id=target.id,\n                turns=turns, options=[option],\n            ))\n\n    return missions\n\n\ndef plan_moves(world, deadline=None):\n    def expired():\n        return deadline is not None and time.perf_counter() > deadline\n\n    def time_left():\n        if deadline is None:\n            return 10**9\n        return deadline - time.perf_counter()\n\n    def allow_heavy_phase():\n        return time_left() > HEAVY_PHASE_MIN_TIME and len(world.planets) <= HEAVY_ROUTE_PLANET_LIMIT\n\n    def allow_optional_phase():\n        return time_left() > OPTIONAL_PHASE_MIN_TIME\n\n    modes = build_modes(world)\n    profile = strategy_profile(world)\n    policy = build_policy_state(world, deadline=deadline)\n    planned_commitments = defaultdict(list)\n    source_options_by_target = defaultdict(list)\n    missions = []\n    moves = []\n    spent_total = defaultdict(int)\n    pressure_packets_sent = 0\n\n    def source_inventory_left(source_id):\n        return world.source_inventory_left(source_id, spent_total)\n\n    def source_attack_left(source_id):\n        budget = policy["attack_budget"].get(source_id, 0)\n        return max(0, budget - spent_total[source_id])\n\n    def append_move(src_id, angle, ships):\n        send = min(int(ships), source_inventory_left(src_id))\n        if send < 1:\n            return 0\n        moves.append([src_id, float(angle), int(send)])\n        spent_total[src_id] += send\n        return send\n\n\n    def finalize_moves():\n        final_moves = []\n        used_final = defaultdict(int)\n        for src_id, angle, ships in moves:\n            source = world.planet_by_id[src_id]\n            max_allowed = int(source.ships) - used_final[src_id]\n            send = min(int(ships), max_allowed)\n            if send >= 1:\n                final_moves.append([src_id, float(angle), int(send)])\n                used_final[src_id] += send\n        return final_moves\n\n    def compute_live_doomed():\n        doomed = set()\n        for planet in world.my_planets:\n            status = world.hold_status(\n                planet.id,\n                planned_commitments=planned_commitments,\n                horizon=DOOMED_EVAC_TURN_LIMIT,\n            )\n            if (\n                not status["holds_full"]\n                and status["fall_turn"] is not None\n                and status["fall_turn"] <= DOOMED_EVAC_TURN_LIMIT\n                and source_inventory_left(planet.id) >= DOOMED_MIN_SHIPS\n            ):\n                doomed.add(planet.id)\n        return doomed\n\n    def time_filters_pass(target, turns, needed, src_cap, src=None):\n        if not candidate_time_valid(target, turns, world, VERY_LATE_CAPTURE_BUFFER if world.is_very_late else LATE_CAPTURE_BUFFER):\n            return False\n        if opening_filter(target, turns, needed, src_cap, world, policy, src=src):\n            return False\n        return True\n\n    # === MISSION BUILDING PHASE ===\n\n    if allow_heavy_phase():\n        missions.extend(\n            build_reinforce_missions(world, policy, planned_commitments, modes, source_inventory_left)\n        )\n\n    missions.extend(build_rescue_missions(world, policy, planned_commitments, modes))\n    missions.extend(build_recapture_missions(world, policy, planned_commitments, modes))\n\n    # Elimination missions — high priority in 4P\n    if allow_heavy_phase():\n        missions.extend(build_elimination_missions(world, policy, planned_commitments, modes))\n\n    # Gang-up missions — exploit inter-enemy fights (very useful in 4P)\n    if allow_heavy_phase():\n        missions.extend(build_gang_up_missions(world, policy, planned_commitments, modes))\n\n    for src in world.my_planets:\n        if expired():\n            return finalize_moves()\n        src_available = source_attack_left(src.id)\n        if src_available <= 0:\n            continue\n\n        for target in world.planets:\n            if expired():\n                return finalize_moves()\n            if target.id == src.id or target.owner == world.player:\n                continue\n\n            seeded = world.best_probe_aim(\n                src.id,\n                target.id,\n                src_available,\n                hints=(int(target.ships) + 1,),\n            )\n            if seeded is None:\n                continue\n            _, rough_aim = seeded\n\n            rough_turns = rough_aim[1]\n            if not candidate_time_valid(\n                target,\n                rough_turns,\n                world,\n                VERY_LATE_CAPTURE_BUFFER if world.is_very_late else LATE_CAPTURE_BUFFER,\n            ):\n                continue\n\n            global_needed = world.min_ships_to_own_at(\n                target.id,\n                rough_turns,\n                world.player,\n                planned_commitments=planned_commitments,\n            )\n            if global_needed <= 0:\n                continue\n            if opening_filter(target, rough_turns, global_needed, src_available, world, policy, src=src):\n                continue\n\n            partial_send_cap = min(\n                src_available,\n                preferred_send(target, global_needed, rough_turns, src_available, world, modes, policy),\n            )\n            if partial_send_cap >= adaptive_partial_source_min(world, modes):\n                partial_seed = world.best_probe_aim(\n                    src.id,\n                    target.id,\n                    partial_send_cap,\n                    hints=(partial_send_cap, global_needed, int(target.ships) + 1),\n                )\n                if partial_seed is not None:\n                    _, partial_aim = partial_seed\n                    p_angle, p_turns, _, _ = partial_aim\n                    if time_filters_pass(target, p_turns, global_needed, src_available, src=src):\n                        partial_value = target_value(target, p_turns, "swarm", world, modes, policy)\n                        if partial_value > 0:\n                            partial_score = apply_score_modifiers(\n                                partial_value / (partial_send_cap + p_turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                                target,\n                                "swarm",\n                                world,\n                            )\n                            source_options_by_target[target.id].append(\n                                ShotOption(\n                                    score=partial_score,\n                                    src_id=src.id,\n                                    target_id=target.id,\n                                    angle=p_angle,\n                                    turns=p_turns,\n                                    needed=global_needed,\n                                    send_cap=partial_send_cap,\n                                    mission="swarm",\n                                )\n                            )\n\n            if global_needed <= src_available:\n                send_guess = preferred_send(\n                    target, global_needed, rough_turns, src_available, world, modes, policy,\n                )\n                plan = settle_plan(\n                    src,\n                    target,\n                    src_available,\n                    send_guess,\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="capture",\n                )\n                if plan is None:\n                    continue\n\n                angle, turns, _, needed, send_cap = plan\n                if not time_filters_pass(target, turns, needed, src_available, src=src):\n                    continue\n                if send_cap < 1:\n                    continue\n\n                value = target_value(target, turns, "capture", world, modes, policy)\n                if value <= 0:\n                    continue\n\n                score = apply_score_modifiers(\n                    value / (send_cap + turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                    target,\n                    "capture",\n                    world,\n                )\n\n                option = ShotOption(\n                    score=score,\n                    src_id=src.id,\n                    target_id=target.id,\n                    angle=angle,\n                    turns=turns,\n                    needed=needed,\n                    send_cap=send_cap,\n                    mission="capture",\n                )\n\n                if send_cap >= needed:\n                    missions.append(Mission(\n                        kind="single",\n                        score=score,\n                        target_id=target.id,\n                        turns=turns,\n                        options=[option],\n                    ))\n\n            snipe = build_snipe_mission(src, target, src_available, world, planned_commitments, modes, policy)\n            if snipe is not None:\n                missions.append(snipe)\n\n    for target_id, options in source_options_by_target.items():\n        if expired():\n            return finalize_moves()\n        if len(options) < 2:\n            continue\n\n        target = world.planet_by_id[target_id]\n        top_options = sorted(options, key=lambda item: -item.score)[:MULTI_SOURCE_TOP_K]\n        for i in range(len(top_options)):\n            for j in range(i + 1, len(top_options)):\n                first = top_options[i]\n                second = top_options[j]\n                if first.src_id == second.src_id:\n                    continue\n                pair_tol = swarm_eta_tolerance((first, second), target, world)\n                if abs(first.turns - second.turns) > pair_tol:\n                    continue\n\n                joint_turn = max(first.turns, second.turns)\n                total_cap = first.send_cap + second.send_cap\n                need = world.min_ships_to_own_at(\n                    target_id,\n                    joint_turn,\n                    world.player,\n                    planned_commitments=planned_commitments,\n                    upper_bound=total_cap,\n                )\n                if need <= 0:\n                    continue\n                if first.send_cap >= need or second.send_cap >= need:\n                    continue\n                if total_cap < need:\n                    continue\n\n                value = target_value(target, joint_turn, "swarm", world, modes, policy)\n                if value <= 0:\n                    continue\n\n                pair_score = apply_score_modifiers(\n                    value / (need + joint_turn * ATTACK_COST_TURN_WEIGHT + 1.0),\n                    target,\n                    "swarm",\n                    world,\n                )\n                pair_score *= MULTI_SOURCE_PLAN_PENALTY\n                missions.append(Mission(\n                    kind="swarm",\n                    score=pair_score,\n                    target_id=target_id,\n                    turns=joint_turn,\n                    options=[first, second],\n                ))\n\n        if (\n            THREE_SOURCE_SWARM_ENABLED\n            and allow_heavy_phase()\n            and target.owner not in (-1, world.player)\n            and int(target.ships) >= THREE_SOURCE_MIN_TARGET_SHIPS\n            and len(top_options) >= 3\n        ):\n            for i in range(len(top_options)):\n                for j in range(i + 1, len(top_options)):\n                    for k in range(j + 1, len(top_options)):\n                        if expired():\n                            return finalize_moves()\n                        trio = [top_options[i], top_options[j], top_options[k]]\n                        if len({option.src_id for option in trio}) < 3:\n                            continue\n                        trio_tol = swarm_eta_tolerance(tuple(trio), target, world)\n                        turns = [option.turns for option in trio]\n                        if max(turns) - min(turns) > trio_tol:\n                            continue\n\n                        joint_turn = max(turns)\n                        total_cap = sum(option.send_cap for option in trio)\n                        need = world.min_ships_to_own_at(\n                            target_id,\n                            joint_turn,\n                            world.player,\n                            planned_commitments=planned_commitments,\n                            upper_bound=total_cap,\n                        )\n                        if need <= 0 or total_cap < need:\n                            continue\n                        if any(\n                            trio[a].send_cap + trio[b].send_cap >= need\n                            for a in range(3)\n                            for b in range(a + 1, 3)\n                        ):\n                            continue\n\n                        value = target_value(target, joint_turn, "swarm", world, modes, policy)\n                        if value <= 0:\n                            continue\n\n                        trio_score = apply_score_modifiers(\n                            value / (need + joint_turn * ATTACK_COST_TURN_WEIGHT + 1.0),\n                            target,\n                            "swarm",\n                            world,\n                        )\n                        trio_score *= THREE_SOURCE_PLAN_PENALTY\n                        missions.append(Mission(\n                            kind="swarm",\n                            score=trio_score,\n                            target_id=target_id,\n                            turns=joint_turn,\n                            options=trio,\n                        ))\n\n        coordinated_pressure_window = (\n            COORDINATED_WAVE_ENABLED\n            and allow_heavy_phase()\n            and len(options) >= 2\n            and target.owner not in (-1, world.player)\n            and world.step >= 45\n            and (\n                modes.get("is_snowball_risk")\n                or modes.get("is_behind")\n                or world.max_enemy_prod >= world.my_prod + COORDINATED_WAVE_MIN_PROD_GAP\n                or (\n                    world.is_four_player\n                    and modes.get("is_four_player_leader_pressure")\n                    and target.owner == world._leader_enemy\n                )\n            )\n        )\n        if coordinated_pressure_window:\n            wave_options = sorted(options, key=lambda item: (-item.score, item.turns))[:COORDINATED_WAVE_TOP_K]\n            seen_waves = set()\n            for anchor in wave_options:\n                if expired():\n                    return finalize_moves()\n                window = [\n                    option\n                    for option in wave_options\n                    if abs(option.turns - anchor.turns) <= COORDINATED_WAVE_ETA_TOLERANCE\n                ]\n                chosen = []\n                chosen_sources = set()\n                for option in sorted(window, key=lambda item: (-item.score, item.turns, item.src_id)):\n                    if option.src_id in chosen_sources:\n                        continue\n                    chosen.append(option)\n                    chosen_sources.add(option.src_id)\n                    if len(chosen) >= COORDINATED_WAVE_MAX_SOURCES:\n                        break\n                if len(chosen) < 2:\n                    continue\n\n                joint_turn = max(option.turns for option in chosen)\n                total_cap = sum(option.send_cap for option in chosen)\n                need = world.min_ships_to_own_at(\n                    target_id,\n                    joint_turn,\n                    world.player,\n                    planned_commitments=planned_commitments,\n                    upper_bound=total_cap,\n                )\n                if need <= 0 or total_cap < need:\n                    continue\n                if any(option.send_cap >= need for option in chosen):\n                    continue\n\n                key = tuple(sorted(option.src_id for option in chosen))\n                if key in seen_waves:\n                    continue\n                seen_waves.add(key)\n\n                value = target_value(target, joint_turn, "swarm", world, modes, policy)\n                if value <= 0:\n                    continue\n                wave_score = apply_score_modifiers(\n                    value / (need + joint_turn * ATTACK_COST_TURN_WEIGHT + 1.0),\n                    target,\n                    "swarm",\n                    world,\n                )\n                wave_score *= COORDINATED_WAVE_PLAN_PENALTY\n                missions.append(Mission(\n                    kind="swarm",\n                    score=wave_score,\n                    target_id=target_id,\n                    turns=joint_turn,\n                    options=chosen,\n                ))\n\n    if allow_heavy_phase():\n        missions.extend(build_crash_exploit_missions(world, policy, planned_commitments, modes))\n\n    if allow_heavy_phase():\n        missions.extend(build_pressure_packet_missions(world, policy, planned_commitments, modes))\n\n    missions.sort(key=lambda item: -item.score)\n\n    # === MISSION EXECUTION PHASE ===\n\n    for mission in missions:\n        if expired():\n            return finalize_moves()\n        target = world.planet_by_id[mission.target_id]\n\n        if mission.kind == "pressure_packet":\n            if pressure_packets_sent >= profile["pressure_packet_max_per_turn"]:\n                continue\n            option = mission.options[0]\n            src = world.planet_by_id[option.src_id]\n            left = source_attack_left(option.src_id)\n            send = min(left, option.send_cap)\n            if send < profile["pressure_packet_min_send"]:\n                continue\n\n            aim = world.plan_shot(src.id, target.id, send)\n            if aim is None:\n                continue\n            angle, turns, _, _ = aim\n            if turns > PRESSURE_PACKET_MAX_TURNS:\n                continue\n            if not candidate_time_valid(target, turns, world, LATE_CAPTURE_BUFFER):\n                continue\n            if send >= 64 and not shot_hits_intended_target(\n                src,\n                target,\n                angle,\n                send,\n                world.planets,\n                world.initial_by_id,\n                world.ang_vel,\n                world.comets,\n                world.comet_ids,\n                max_turns=min(PRESSURE_PACKET_MAX_TURNS + 2, turns + 3),\n            ):\n                continue\n\n            need = world.min_ships_to_own_at(\n                target.id,\n                turns,\n                world.player,\n                planned_commitments=planned_commitments,\n                upper_bound=send,\n            )\n            if need <= 0 or need > send:\n                continue\n\n            actual = append_move(option.src_id, angle, send)\n            if actual < need:\n                continue\n            planned_commitments[target.id].append((turns, world.player, int(actual)))\n            pressure_packets_sent += 1\n            continue\n\n        if mission.kind in ("single", "snipe", "rescue", "recapture", "reinforce", "crash_exploit"):\n            option = mission.options[0]\n            src = world.planet_by_id[option.src_id]\n            if mission.kind == "reinforce":\n                left = min(\n                    source_inventory_left(option.src_id),\n                    int(src.ships * REINFORCE_MAX_SOURCE_FRACTION),\n                )\n            else:\n                left = source_attack_left(option.src_id)\n            if left <= 0:\n                continue\n\n            if mission.kind == "reinforce":\n                plan = settle_reinforce_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    option.anchor_turn,\n                    mission.turns,\n                )\n            elif mission.kind == "rescue":\n                plan = settle_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="rescue",\n                    eval_turn_fn=lambda _turns, hold_turn=mission.turns: hold_turn,\n                    anchor_turn=option.anchor_turn,\n                )\n            elif mission.kind == "snipe":\n                plan = settle_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="snipe",\n                    eval_turn_fn=lambda turns, enemy_eta=option.anchor_turn: max(turns, enemy_eta),\n                    anchor_turn=option.anchor_turn,\n                )\n            elif mission.kind == "crash_exploit":\n                plan = settle_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="crash_exploit",\n                    eval_turn_fn=lambda turns, desired_arrival=option.anchor_turn: max(turns, desired_arrival),\n                    anchor_turn=option.anchor_turn,\n                    anchor_tolerance=CRASH_EXPLOIT_ETA_WINDOW,\n                )\n            else:\n                plan = settle_plan(\n                    src,\n                    target,\n                    left,\n                    min(left, option.send_cap),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="capture",\n                )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send = plan\n            if send < need or need > left:\n                continue\n            if not four_player_packet_allowed(world, target, mission.kind, need, send, modes):\n                continue\n\n            sent = append_move(option.src_id, angle, send)\n            if sent < need:\n                continue\n            planned_commitments[target.id].append((turns, world.player, int(sent)))\n            continue\n\n        limits = []\n        for option in mission.options:\n            left = source_attack_left(option.src_id)\n            limits.append(min(left, option.send_cap))\n        if min(limits) <= 0:\n            continue\n\n        missing = world.min_ships_to_own_at(\n            target.id,\n            mission.turns,\n            world.player,\n            planned_commitments=planned_commitments,\n            upper_bound=sum(limits),\n        )\n        if missing <= 0 or sum(limits) < missing:\n            continue\n        if (\n            world.is_four_player\n            and world.step >= FOUR_PLAYER_PACKET_AGGREGATION_TURN\n            and sum(limits) < max(missing, FOUR_PLAYER_PACKET_JOINT_FLOOR)\n        ):\n            continue\n\n        ordered = sorted(\n            zip(mission.options, limits),\n            key=lambda item: (item[0].turns, -item[1], item[0].src_id),\n        )\n        remaining = missing\n        sends = {}\n        for idx, (option, limit) in enumerate(ordered):\n            remaining_other = sum(other_limit for _, other_limit in ordered[idx + 1:])\n            send = min(limit, max(0, remaining - remaining_other))\n            sends[option.src_id] = send\n            remaining -= send\n        if remaining > 0:\n            continue\n\n        reaimed = []\n        for option, _ in ordered:\n            send = sends.get(option.src_id, 0)\n            if send <= 0:\n                continue\n            src = world.planet_by_id[option.src_id]\n            fixed_aim = world.plan_shot(src.id, target.id, send)\n            if fixed_aim is None:\n                reaimed = []\n                break\n            angle, turns, _, _ = fixed_aim\n            reaimed.append((option.src_id, angle, turns, send))\n        if not reaimed:\n            continue\n\n        turns_only = [item[2] for item in reaimed]\n        eta_tol = swarm_eta_tolerance(mission.options, target, world)\n        if max(turns_only) - min(turns_only) > eta_tol:\n            continue\n\n        actual_joint_turn = max(turns_only)\n        owner_after, _ = world.projected_state(\n            target.id,\n            actual_joint_turn,\n            planned_commitments=planned_commitments,\n            extra_arrivals=[(turns, world.player, send) for _, _, turns, send in reaimed],\n        )\n        if owner_after != world.player:\n            continue\n\n        committed = []\n        for src_id, angle, turns, send in reaimed:\n            actual = append_move(src_id, angle, send)\n            if actual <= 0:\n                continue\n            committed.append((turns, world.player, int(actual)))\n        if sum(item[2] for item in committed) < missing:\n            continue\n        planned_commitments[target.id].extend(committed)\n\n    # === FOLLOWUP PHASE ===\n\n    if not world.is_very_late and allow_optional_phase():\n        for src in world.my_planets:\n            if expired():\n                return finalize_moves()\n            src_left = source_attack_left(src.id)\n            if src_left < adaptive_followup_min(world, modes):\n                continue\n\n            best = None\n            for target in world.planets:\n                if expired():\n                    return finalize_moves()\n                if target.id == src.id or target.owner == world.player:\n                    continue\n                if target.id in world.comet_ids and target.production <= LOW_VALUE_COMET_PRODUCTION:\n                    continue\n\n                seeded = world.best_probe_aim(\n                    src.id,\n                    target.id,\n                    src_left,\n                    hints=(int(target.ships) + 1,),\n                )\n                if seeded is None:\n                    continue\n                rough_ships, rough_aim = seeded\n\n                est_turns = rough_aim[1]\n                if world.is_late and est_turns > world.remaining_steps - LATE_CAPTURE_BUFFER:\n                    continue\n\n                rough_needed = world.min_ships_to_own_at(\n                    target.id,\n                    est_turns,\n                    world.player,\n                    planned_commitments=planned_commitments,\n                    upper_bound=src_left,\n                )\n                if rough_needed <= 0 or rough_needed > src_left:\n                    continue\n                if opening_filter(target, est_turns, rough_needed, src_left, world, policy, src=src):\n                    continue\n\n                send = preferred_send(target, rough_needed, est_turns, src_left, world, modes, policy)\n                if send < rough_needed:\n                    continue\n\n                plan = settle_plan(\n                    src,\n                    target,\n                    src_left,\n                    send,\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="capture",\n                )\n                if plan is None:\n                    continue\n\n                _, turns, _, need, final_send = plan\n                if world.is_late and turns > world.remaining_steps - LATE_CAPTURE_BUFFER:\n                    continue\n                if final_send < need:\n                    continue\n\n                value = target_value(target, turns, "capture", world, modes, policy)\n                if value <= 0:\n                    continue\n\n                score = apply_score_modifiers(\n                    value / (final_send + turns * ATTACK_COST_TURN_WEIGHT + 1.0),\n                    target,\n                    "capture",\n                    world,\n                )\n                if best is None or score > best[0]:\n                    best = (score, target, plan)\n\n            if best is None:\n                continue\n\n            _, target, plan = best\n            angle, turns, _, need, send = plan\n            src_left = source_attack_left(src.id)\n            if need > src_left:\n                continue\n\n            plan = settle_plan(\n                src,\n                target,\n                src_left,\n                min(src_left, send),\n                world,\n                planned_commitments,\n                modes,\n                policy,\n                mission="capture",\n            )\n            if plan is None:\n                continue\n\n            angle, turns, _, need, send = plan\n            if send < need:\n                continue\n            if not four_player_packet_allowed(world, target, "capture", need, send, modes):\n                continue\n\n            actual = append_move(src.id, angle, send)\n            if actual < need:\n                continue\n            planned_commitments[target.id].append((turns, world.player, int(actual)))\n\n    # === DOOMED PLANET EVACUATION ===\n\n    if expired():\n        return finalize_moves()\n    live_doomed = compute_live_doomed()\n    if live_doomed:\n        frontier_targets = (\n            world.enemy_planets\n            if world.enemy_planets\n            else (world.static_neutral_planets or world.neutral_planets)\n        )\n        if frontier_targets:\n            frontier_distance = {\n                planet.id: nearest_distance_to_set(planet.x, planet.y, frontier_targets)\n                for planet in world.my_planets\n            }\n        else:\n            frontier_distance = {planet.id: 10**9 for planet in world.my_planets}\n\n        for planet in world.my_planets:\n            if expired():\n                return finalize_moves()\n            if planet.id not in live_doomed:\n                continue\n\n            available_now = source_inventory_left(planet.id)\n            if available_now < policy["reserve"].get(planet.id, 0):\n                continue\n\n            best_capture = None\n            for target in world.planets:\n                if expired():\n                    return finalize_moves()\n                if target.id == planet.id or target.owner == world.player:\n                    continue\n                seeded = world.best_probe_aim(\n                    planet.id,\n                    target.id,\n                    available_now,\n                    hints=(available_now, int(target.ships) + 1),\n                )\n                if seeded is None:\n                    continue\n                _, probe_aim = seeded\n                probe_turns = probe_aim[1]\n                if probe_turns > world.remaining_steps - 2:\n                    continue\n\n                need = world.min_ships_to_own_at(\n                    target.id,\n                    probe_turns,\n                    world.player,\n                    planned_commitments=planned_commitments,\n                    upper_bound=available_now,\n                )\n                if need <= 0 or need > available_now:\n                    continue\n\n                plan = settle_plan(\n                    planet,\n                    target,\n                    available_now,\n                    min(available_now, max(need, int(target.ships) + 1)),\n                    world,\n                    planned_commitments,\n                    modes,\n                    policy,\n                    mission="capture",\n                )\n                if plan is None:\n                    continue\n                angle, turns, _, plan_need, send = plan\n                if send < plan_need:\n                    continue\n                score = target_value(target, turns, "capture", world, modes, policy) / (send + turns + 1.0)\n                if target.owner not in (-1, world.player):\n                    score *= 1.05\n                if best_capture is None or score > best_capture[0]:\n                    best_capture = (score, target.id, angle, turns, send)\n\n            if best_capture is not None:\n                _, target_id, angle, turns, need = best_capture\n                actual = append_move(planet.id, angle, need)\n                if actual >= 1:\n                    planned_commitments[target_id].append((turns, world.player, int(actual)))\n                continue\n\n            safe_allies = [\n                ally\n                for ally in world.my_planets\n                if ally.id != planet.id and ally.id not in live_doomed\n            ]\n            if not safe_allies:\n                continue\n\n            retreat_target = min(\n                safe_allies,\n                key=lambda ally: (\n                    frontier_distance.get(ally.id, 10**9),\n                    planet_distance(planet, ally),\n                ),\n            )\n            aim = world.plan_shot(planet.id, retreat_target.id, available_now)\n            if aim is None:\n                continue\n            angle, _, _, _ = aim\n            append_move(planet.id, angle, available_now)\n\n    # === REAR FORWARDING ===\n\n    if (\n        (world.enemy_planets or world.neutral_planets)\n        and len(world.my_planets) > 1\n        and not world.is_late\n        and allow_optional_phase()\n    ):\n        live_doomed = compute_live_doomed()\n        frontier_targets = (\n            world.enemy_planets\n            if world.enemy_planets\n            else (world.static_neutral_planets or world.neutral_planets)\n        )\n        frontier_distance = {\n            planet.id: nearest_distance_to_set(planet.x, planet.y, frontier_targets)\n            for planet in world.my_planets\n        }\n        safe_fronts = [planet for planet in world.my_planets if planet.id not in live_doomed]\n        if safe_fronts:\n            front_anchor = min(safe_fronts, key=lambda planet: frontier_distance[planet.id])\n            send_ratio = profile["rear_send_ratio"]\n            if modes["is_finishing"]:\n                send_ratio = max(send_ratio, FOUR_PLAYER_STRATEGY["rear_send_ratio"])\n            rear_source_min = profile["rear_source_min"]\n            rear_send_min = profile["rear_send_min"]\n            rear_distance_ratio = profile["rear_distance_ratio"]\n            rear_stage_progress = profile["rear_stage_progress"]\n            rear_max_turns = profile["rear_max_turns"]\n\n            for rear in sorted(world.my_planets, key=lambda planet: -frontier_distance[planet.id]):\n                if expired():\n                    return finalize_moves()\n                if rear.id == front_anchor.id or rear.id in live_doomed:\n                    continue\n                if source_attack_left(rear.id) < rear_source_min:\n                    continue\n                if frontier_distance[rear.id] < frontier_distance[front_anchor.id] * rear_distance_ratio:\n                    continue\n\n                stage_candidates = [\n                    planet\n                    for planet in safe_fronts\n                    if planet.id != rear.id\n                    and frontier_distance[planet.id] < frontier_distance[rear.id] * rear_stage_progress\n                ]\n                if stage_candidates:\n                    front = min(stage_candidates, key=lambda planet: planet_distance(rear, planet))\n                else:\n                    objective = min(frontier_targets, key=lambda target: planet_distance(rear, target))\n                    remaining_fronts = [planet for planet in safe_fronts if planet.id != rear.id]\n                    if not remaining_fronts:\n                        continue\n                    front = min(remaining_fronts, key=lambda planet: planet_distance(planet, objective))\n\n                if front.id == rear.id:\n                    continue\n\n                send = int(source_attack_left(rear.id) * send_ratio)\n                if send < rear_send_min:\n                    continue\n\n                aim = world.plan_shot(rear.id, front.id, send)\n                if aim is None:\n                    continue\n\n                angle, turns, _, _ = aim\n                if turns > rear_max_turns:\n                    continue\n                append_move(rear.id, angle, send)\n\n    # === TOTAL WAR ENDGAME ===\n\n    if world.is_total_war and world.enemy_planets and allow_optional_phase():\n        # Prioritize weakest enemy in total war\n        if world._weakest_enemy is not None:\n            weakest_planets = [p for p in world.enemy_planets if p.owner == world._weakest_enemy]\n            if weakest_planets:\n                primary_targets = weakest_planets\n            else:\n                primary_targets = world.enemy_planets\n        else:\n            primary_targets = world.enemy_planets\n\n        # Attack weakest enemy first, then others\n        for target_set in [primary_targets, world.enemy_planets]:\n            if not target_set:\n                continue\n            for src in world.my_planets:\n                if expired():\n                    return finalize_moves()\n                atk_left = source_attack_left(src.id)\n                if atk_left < 5:\n                    continue\n\n                # Find best target from current set\n                best_target = None\n                best_dist = float(\'inf\')\n                for ep in target_set:\n                    d = planet_distance(src, ep)\n                    if d < best_dist:\n                        aim_test = world.plan_shot(src.id, ep.id, atk_left)\n                        if aim_test is not None:\n                            best_dist = d\n                            best_target = ep\n\n                if best_target is None:\n                    continue\n                aim = world.plan_shot(src.id, best_target.id, atk_left)\n                if aim is None:\n                    continue\n                angle, turns, _, _ = aim\n                if turns >= world.remaining_steps:\n                    continue\n                append_move(src.id, angle, atk_left)\n            break  # Only run primary targets set; secondary is backup\n\n    return finalize_moves()\n\n# ============================================================\n# Agent Entry Point\n# ============================================================\n\n_TURN_BY_GAME_PLAYER = {}\n\n\ndef _read(obs, key, default=None):\n    if isinstance(obs, dict):\n        return obs.get(key, default)\n    return getattr(obs, key, default)\n\n\ndef _safe_int(value, default=0):\n    try:\n        return int(value)\n    except (TypeError, ValueError):\n        return default\n\n\ndef _turn_state_key(obs, player, angular_velocity):\n    initial_rows = _read(obs, "initial_planets", []) or []\n    if not initial_rows:\n        return (player, round(float(angular_velocity or 0.0), 8), "fallback")\n\n    signature = []\n    for row in initial_rows:\n        try:\n            signature.append(\n                (\n                    int(row[0]),\n                    int(row[1]),\n                    round(float(row[2]), 3),\n                    round(float(row[3]), 3),\n                    round(float(row[4]), 3),\n                    int(row[6]),\n                )\n            )\n        except (TypeError, ValueError, IndexError):\n            continue\n\n    if not signature:\n        return (player, round(float(angular_velocity or 0.0), 8), "fallback")\n    return (player, round(float(angular_velocity or 0.0), 8), tuple(signature))\n\n\ndef _remember_step(obs, player, angular_velocity, step):\n    _TURN_BY_GAME_PLAYER[_turn_state_key(obs, player, angular_velocity)] = max(0, min(TOTAL_STEPS, int(step)))\n\n\ndef _infer_step_from_orbits(obs, planets, angular_velocity, comet_ids):\n    if abs(angular_velocity) < 1e-9:\n        return None\n\n    initial_rows = _read(obs, "initial_planets", []) or []\n    if not initial_rows:\n        return None\n\n    current_by_id = {planet.id: planet for planet in planets}\n    inferred_steps = []\n    for row in initial_rows:\n        try:\n            initial = Planet(*row)\n        except (TypeError, ValueError):\n            continue\n        if initial.id in comet_ids:\n            continue\n\n        current = current_by_id.get(initial.id)\n        if current is None:\n            continue\n        if orbital_radius(initial) + initial.radius >= ROTATION_LIMIT:\n            continue\n        if orbital_radius(current) + current.radius >= ROTATION_LIMIT + 1.0:\n            continue\n\n        start_angle = math.atan2(initial.y - CENTER_Y, initial.x - CENTER_X)\n        current_angle = math.atan2(current.y - CENTER_Y, current.x - CENTER_X)\n        if angular_velocity > 0:\n            delta = (current_angle - start_angle) % (2.0 * math.pi)\n        else:\n            delta = (start_angle - current_angle) % (2.0 * math.pi)\n        inferred_steps.append(delta / abs(angular_velocity))\n\n    if not inferred_steps:\n        return None\n    inferred_steps.sort()\n    return inferred_steps[len(inferred_steps) // 2]\n\n\ndef _current_step(obs, planets, fleets, player, angular_velocity, comet_ids):\n    raw_step = _read(obs, "step", None)\n    if raw_step is not None:\n        step = _safe_int(raw_step, 0)\n        _remember_step(obs, player, angular_velocity, step)\n        return step\n\n    inferred = _infer_step_from_orbits(obs, planets, angular_velocity, comet_ids)\n    key = _turn_state_key(obs, player, angular_velocity)\n    prior = _TURN_BY_GAME_PLAYER.get(key)\n\n    if prior is not None and inferred is not None and inferred <= 1.5 and prior > 20 and not fleets:\n        prior = None\n\n    if prior is None:\n        step = max(0, int(round(inferred or 0)))\n    elif inferred is None or abs(angular_velocity) < 1e-9:\n        step = prior + 1\n    else:\n        expected = prior + 1\n        period = (2.0 * math.pi) / abs(angular_velocity)\n        wraps = int(TOTAL_STEPS / period) + 3\n        candidates = [inferred + period * wrap for wrap in range(wraps)]\n        step = int(round(min(candidates, key=lambda candidate: abs(candidate - expected))))\n        if abs(step - expected) > 4:\n            step = expected\n\n    step = max(0, min(TOTAL_STEPS, step))\n    _TURN_BY_GAME_PLAYER[key] = step\n    return step\n\n\ndef build_world(obs, inferred_step=None):\n    player = _read(obs, "player", 0)\n    raw_planets = _read(obs, "planets", []) or []\n    raw_fleets = _read(obs, "fleets", []) or []\n    ang_vel = _read(obs, "angular_velocity", 0.0) or 0.0\n    raw_init = _read(obs, "initial_planets", []) or []\n    comets = _read(obs, "comets", []) or []\n    comet_ids = set(_read(obs, "comet_planet_ids", []) or [])\n\n    planets = [Planet(*planet) for planet in raw_planets]\n    fleets = [Fleet(*fleet) for fleet in raw_fleets]\n    initial_planets = [Planet(*planet) for planet in raw_init]\n    initial_by_id = {planet.id: planet for planet in initial_planets}\n    step = _current_step(obs, planets, fleets, player, ang_vel, comet_ids)\n    if inferred_step is not None:\n        step = max(step, int(inferred_step))\n\n    return WorldModel(\n        player=player,\n        step=step,\n        planets=planets,\n        fleets=fleets,\n        initial_by_id=initial_by_id,\n        ang_vel=ang_vel,\n        comets=comets,\n        comet_ids=comet_ids,\n    )\n\n\ndef _is_endgame_refinement_state(world):\n    if not ENDGAME_REFINER_ENABLED:\n        return False\n    if world.is_four_player:\n        return False\n    if world.remaining_steps > ENDGAME_REFINER_REMAINING_TURNS:\n        return False\n    non_comet_planets = [planet for planet in world.planets if planet.id not in world.comet_ids]\n    return len(non_comet_planets) <= ENDGAME_REFINER_MAX_NON_COMET_PLANETS\n\n\ndef _build_endgame_synthetic_fleets(world, moves):\n    new_fleets = list(world.fleets)\n    next_id = max((fleet.id for fleet in world.fleets), default=-1) + 1000\n    planet_by_id = {planet.id: planet for planet in world.planets}\n    spent = defaultdict(int)\n\n    for from_id, angle, ships in moves[:ENDGAME_REFINER_MAX_MOVES]:\n        source = planet_by_id.get(int(from_id))\n        if source is None:\n            continue\n        send = min(int(ships), max(0, int(source.ships) - spent[source.id]))\n        if send <= 0:\n            continue\n        spent[source.id] += send\n        start_x, start_y = launch_point(source.x, source.y, source.radius, float(angle))\n        new_fleets.append(\n            Fleet(next_id, world.player, start_x, start_y, float(angle), source.id, send)\n        )\n        next_id += 1\n\n    return new_fleets, dict(spent)\n\n\ndef _score_endgame_position(world, moves):\n    fleets_after, spent_by_planet = _build_endgame_synthetic_fleets(world, moves)\n    planets_after = []\n    for planet in world.planets:\n        spent = spent_by_planet.get(planet.id, 0)\n        if spent:\n            planets_after.append(planet._replace(ships=max(0, planet.ships - spent)))\n        else:\n            planets_after.append(planet)\n\n    arrivals_ledger = build_arrival_ledger(\n        fleets_after,\n        planets_after,\n        initial_by_id=world.initial_by_id,\n        ang_vel=world.ang_vel,\n        comets=world.comets,\n        comet_ids=world.comet_ids,\n    )\n    horizon = max(1, world.remaining_steps)\n    score = 0.0\n\n    for planet in planets_after:\n        timeline = simulate_planet_timeline(\n            planet,\n            arrivals_ledger.get(planet.id, []),\n            world.player,\n            horizon,\n        )\n        owner_at = timeline["owner_at"]\n        for turn in range(1, horizon + 1):\n            owner = owner_at.get(turn, planet.owner)\n            if owner == world.player:\n                score += planet.production * ENDGAME_REFINER_PROD_VALUE\n            elif owner >= 0:\n                score -= planet.production * ENDGAME_REFINER_ENEMY_PROD_VALUE\n\n        final_owner = owner_at.get(horizon, planet.owner)\n        final_ships = timeline["ships_at"].get(horizon, 0.0)\n        if final_owner == world.player:\n            score += final_ships * ENDGAME_REFINER_SHIP_VALUE\n        elif final_owner >= 0:\n            score -= final_ships * ENDGAME_REFINER_SHIP_VALUE\n\n    my_in_flight = sum(fleet.ships for fleet in fleets_after if fleet.owner == world.player)\n    enemy_in_flight = sum(\n        fleet.ships\n        for fleet in fleets_after\n        if fleet.owner >= 0 and fleet.owner != world.player\n    )\n    score += (my_in_flight - enemy_in_flight) * ENDGAME_REFINER_FLEET_VALUE\n    return score\n\n\ndef _generate_endgame_variants(baseline_moves):\n    variants = [tuple(tuple(move) for move in baseline_moves[:ENDGAME_REFINER_MAX_MOVES])]\n    if baseline_moves:\n        variants.append(())\n\n        half = []\n        for from_id, angle, ships in baseline_moves[:ENDGAME_REFINER_MAX_MOVES]:\n            ships = int(ships)\n            if ships >= 4:\n                half.append((from_id, angle, max(2, ships // 2)))\n        if half:\n            variants.append(tuple(half))\n\n        sorted_moves = sorted(baseline_moves, key=lambda move: int(move[2]))\n        if len(sorted_moves) >= 2:\n            smallest = sorted_moves[0]\n            dropped = [move for move in baseline_moves if move is not smallest]\n            variants.append(tuple(tuple(move) for move in dropped[:ENDGAME_REFINER_MAX_MOVES]))\n\n    seen = set()\n    deduped = []\n    for variant in variants:\n        key = tuple((int(move[0]), round(float(move[1]), 4), int(move[2])) for move in variant)\n        if key in seen:\n            continue\n        seen.add(key)\n        deduped.append([list(move) for move in variant])\n    return deduped\n\n\ndef _endgame_refine(world, baseline_moves, deadline):\n    if not _is_endgame_refinement_state(world):\n        return baseline_moves\n\n    candidates = _generate_endgame_variants(baseline_moves)\n    if len(candidates) <= 1:\n        return baseline_moves\n\n    best_score = None\n    best_moves = baseline_moves\n    for candidate in candidates:\n        if time.perf_counter() >= deadline:\n            break\n        score = _score_endgame_position(world, candidate)\n        if best_score is None or score > best_score:\n            best_score = score\n            best_moves = candidate\n    return best_moves\n\n\ndef agent(obs, config=None):\n    start_time = time.perf_counter()\n    world = build_world(obs)\n    if not world.my_planets:\n        return []\n    act_timeout = _read(config, "actTimeout", 1.0) if config is not None else 1.0\n    soft_budget = min(SOFT_ACT_DEADLINE, max(0.55, act_timeout * 0.82))\n    deadline = start_time + soft_budget\n    baseline = plan_moves(world, deadline=deadline)\n    return _endgame_refine(world, baseline, deadline)\n\n\n__all__ = ["agent", "build_world"]\n'

_V2P_NS = {"__name__": "_orbit_v646_2p_v50"}
_V4P_NS = {"__name__": "_orbit_v646_4p_v635"}
exec(_V2P_SOURCE, _V2P_NS)
exec(_V4P_SOURCE, _V4P_NS)

_V2P_AGENT = _V2P_NS["agent"]
_V4P_AGENT = _V4P_NS["agent"]

Planet = _V4P_NS["Planet"]
Fleet = _V4P_NS["Fleet"]
BOARD_SIZE = _V4P_NS["BOARD_SIZE"]
build_world = _V4P_NS["build_world"]
crosses_sun = _V4P_NS["crosses_sun"]
distance_to_segment = _V4P_NS["distance_to_segment"]
fleet_speed = _V4P_NS["fleet_speed"]
projected_fleet_target = _V4P_NS["projected_fleet_target"]


def _read_field(obs, name, default=None):
    if isinstance(obs, dict):
        return obs.get(name, default)
    return getattr(obs, name, default)


def _owner_count(rows, owner_index):
    owners = set()
    for row in rows or []:
        try:
            owner = int(row[owner_index])
        except (IndexError, TypeError, ValueError):
            continue
        if owner != -1:
            owners.add(owner)
    return len(owners)


_ROUTER_GAME_PLAYERS = {}


def _router_state_key(obs):
    player = _read_field(obs, "player", 0)
    angular_velocity = _read_field(obs, "angular_velocity", 0.0) or 0.0
    initial = _read_field(obs, "initial_planets", []) or []
    if initial:
        signature = []
        for row in initial:
            try:
                signature.append((int(row[0]), int(row[1]), round(float(row[2]), 3), round(float(row[3]), 3), round(float(row[4]), 3), int(row[6])))
            except (IndexError, TypeError, ValueError):
                continue
        if signature:
            return (int(player), round(float(angular_velocity), 8), tuple(signature))

    comet_ids = set(_read_field(obs, "comet_planet_ids", []) or [])
    planets = _read_field(obs, "planets", []) or []
    signature = []
    for row in planets:
        try:
            planet_id = int(row[0])
            if planet_id in comet_ids:
                continue
            signature.append((planet_id, round(float(row[4]), 3), int(row[6])))
        except (IndexError, TypeError, ValueError):
            continue
    return (int(player), round(float(angular_velocity), 8), tuple(signature))


def _detect_game_players(obs):
    initial = _read_field(obs, "initial_planets", []) or []
    detected = _owner_count(initial, 1)
    if detected >= 4:
        players = 4
    elif detected >= 2:
        players = 2
    else:
        planets = _read_field(obs, "planets", []) or []
        fleets = _read_field(obs, "fleets", []) or []
        owners = set()
        for row in planets:
            try:
                owner = int(row[1])
            except (IndexError, TypeError, ValueError):
                continue
            if owner != -1:
                owners.add(owner)
        for row in fleets:
            try:
                owner = int(row[1])
            except (IndexError, TypeError, ValueError):
                continue
            if owner != -1:
                owners.add(owner)
        players = 4 if len(owners) >= 4 else 2

    key = _router_state_key(obs)
    remembered = _ROUTER_GAME_PLAYERS.get(key, players)
    players = max(remembered, players)
    _ROUTER_GAME_PLAYERS[key] = players
    return players


def agent(obs, config=None):
    if _detect_game_players(obs) >= 4:
        return _V4P_AGENT(obs, config)
    return _V2P_AGENT(obs, config)
